('Párvulos 2', 'Destrezas de Comunicación y Lenguaje', 'Produce distintos tipos de textos de manera emergente, en su idioma materno. Produce textos en forma emergente, acorde con su edad, proceso evolutivo y formación educativa previa.', ARRAY['Produce textos en forma emergente, acorde con su edad, proceso evolutivo y formación educativa previa.']),
('Párvulos 3', 'Destrezas de Comunicación y Lenguaje', 'Produce distintos tipos de textos de manera emergente, en su idioma materno. Produce textos en forma emergente, acorde con su edad, proceso evolutivo, formación educativa previa y sus propios intereses.', ARRAY['Produce textos en forma emergente, acorde con su edad, proceso evolutivo, formación educativa previa y sus propios intereses.']),

-- Área: Destrezas de Aprendizaje Matemático
('Párvulos 1', 'Destrezas de Aprendizaje Matemático', 'Establece relaciones de forma, espacio, tiempo y cantidad, a partir de información que obtiene del entorno, para tomar decisiones propias de su etapa de vida. Establece relaciones entre actividades y el tiempo; objetos y forma, cantidad y espacio, tomando como referencia su cuerpo y elementos de su entorno.', ARRAY['Establece relaciones entre actividades y el tiempo; objetos y forma, cantidad y espacio, tomando como referencia su cuerpo y elementos de su entorno.']),
('Párvulos 2', 'Destrezas de Aprendizaje Matemático', 'Establece relaciones de forma, espacio, tiempo y cantidad, a partir de información que obtiene del entorno, para tomar decisiones propias de su etapa de vida. Determina relaciones espaciales, temporales, de cantidad y atributos, cambiando de referencias para interactuar con el contexto.', ARRAY['Determina relaciones espaciales, temporales, de cantidad y atributos, cambiando de referencias para interactuar con el contexto.']),
('Párvulos 3', 'Destrezas de Aprendizaje Matemático', 'Establece relaciones de forma, espacio, tiempo y cantidad, a partir de información que obtiene del entorno, para tomar decisiones propias de su etapa de vida. Utiliza la forma, atributos, posiciones espaciales, nociones temporales y de cantidad de los elementos para comparar de forma lógica a partir de dos o más referencias.', ARRAY['Utiliza la forma, atributos, posiciones espaciales, nociones temporales y de cantidad de los elementos para comparar de forma lógica a partir de dos o más referencias.']),

('Párvulos 1', 'Destrezas de Aprendizaje Matemático', 'Genera el pensamiento científico y creativo, a partir de la comprensión del entorno, para resolver situaciones de su cotidianidad. Utiliza pensamiento científico y creativo que favorecen la comprensión de su entorno y le permiten expresarse.', ARRAY['Utiliza pensamiento científico y creativo que favorecen la comprensión de su entorno y le permiten expresarse.']),
('Párvulos 2', 'Destrezas de Aprendizaje Matemático', 'Genera el pensamiento científico y creativo, a partir de la comprensión del entorno, para resolver situaciones de su cotidianidad. Establece procesos que implican un pensamiento científico y creativo para resolver situaciones cotidianas.', ARRAY['Establece procesos que implican un pensamiento científico y creativo para resolver situaciones cotidianas.']),
('Párvulos 3', 'Destrezas de Aprendizaje Matemático', 'Genera el pensamiento científico y creativo, a partir de la comprensión del entorno, para resolver situaciones de su cotidianidad. Emplea el pensamiento científico y creativo para verificar procesos y resolver situaciones cotidianas.', ARRAY['Emplea el pensamiento científico y creativo para verificar procesos y resolver situaciones cotidianas.']),

-- Área: Educación Artística
('Párvulos 1', 'Educación Artística', 'Competencia 1 (ritmo/expresión sonora). Realiza ejercicios de ritmo auditivo guiados, con diferentes fuentes sonoras de su entorno.', ARRAY['Realiza ejercicios de ritmo auditivo guiados, con diferentes fuentes sonoras de su entorno.']),
('Párvulos 2', 'Educación Artística', 'Competencia 1 (ritmo/expresión sonora). Produce ritmos musicales que percibe de diferentes fuentes de su entorno.', ARRAY['Produce ritmos musicales que percibe de diferentes fuentes de su entorno.']),
('Párvulos 3', 'Educación Artística', 'Competencia 1 (ritmo/expresión sonora). Ejecuta ritmos de su entorno utilizándolos en expresiones cotidianas.', ARRAY['Ejecuta ritmos de su entorno utilizándolos en expresiones cotidianas.']),

('Párvulos 1', 'Educación Artística', 'Competencia 2 (exploración sonora e instrumental). Experimenta sonidos con su cuerpo y voz, útiles sonoros e instrumentos musicales dentro de ensambles sonoros o musicales.', ARRAY['Experimenta sonidos con su cuerpo y voz, útiles sonoros e instrumentos musicales dentro de ensambles sonoros o musicales.']),
('Párvulos 2', 'Educación Artística', 'Competencia 2 (exploración sonora e instrumental). Reproduce música con diferentes formas de producción sonora como su cuerpo y su voz, útiles sonoros e instrumentos musicales que tiene a su alcance para explorar todas sus posibilidades.', ARRAY['Reproduce música con diferentes formas de producción sonora como su cuerpo y su voz, útiles sonoros e instrumentos musicales que tiene a su alcance para explorar todas sus posibilidades.']),
('Párvulos 3', 'Educación Artística', 'Competencia 2 (exploración sonora e instrumental). Interpreta ritmos y melodías sencillas individual y grupalmente.', ARRAY['Interpreta ritmos y melodías sencillas individual y grupalmente.']),

('Párvulos 1', 'Educación Artística', 'Competencia 3 (reconocimiento de paisajes sonoros). Identifica sonidos de su alrededor.', ARRAY['Identifica sonidos de su alrededor.']),
('Párvulos 2', 'Educación Artística', 'Competencia 3 (reconocimiento de paisajes sonoros). Reconoce paisajes sonoros de su contexto.', ARRAY['Reconoce paisajes sonoros de su contexto.']),
('Párvulos 3', 'Educación Artística', 'Competencia 3 (reconocimiento de paisajes sonoros). Reproduce sonidos y paisajes sonoros de su entorno.', ARRAY['Reproduce sonidos y paisajes sonoros de su entorno.']),

-- Área: Educación Física
('Párvulos 1', 'Educación Física', 'Domina habilidades motoras básicas que le permiten organizar y estructurar su acción motora en diferentes contextos. Desarrolla habilidades motrices a partir de sus posibilidades y funciones corporales.', ARRAY['Desarrolla habilidades motrices a partir de sus posibilidades y funciones corporales.']),
('Párvulos 2', 'Educación Física', 'Domina habilidades motoras básicas que le permiten organizar y estructurar su acción motora en diferentes contextos. Realiza acciones motoras de forma organizada, en diferentes contextos y circunstancias, de acuerdo a sus posibilidades.', ARRAY['Realiza acciones motoras de forma organizada, en diferentes contextos y circunstancias, de acuerdo a sus posibilidades.']),
('Párvulos 3', 'Educación Física', 'Domina habilidades motoras básicas que le permiten organizar y estructurar su acción motora en diferentes contextos. Coordina esquemas motrices de manera estructurada y autónoma en diferentes situaciones y contextos, de acuerdo con sus posibilidades.', ARRAY['Coordina esquemas motrices de manera estructurada y autónoma en diferentes situaciones y contextos, de acuerdo con sus posibilidades.']),

('Párvulos 1', 'Educación Física', 'Establece relaciones sociales positivas y autorregula sus emociones, de manera progresiva, en las actividades motrices grupales y colaborativas. Expresa sus emociones en diferentes contextos y acciones motrices.', ARRAY['Expresa sus emociones en diferentes contextos y acciones motrices.']),
('Párvulos 2', 'Educación Física', 'Establece relaciones sociales positivas y autorregula sus emociones, de manera progresiva, en las actividades motrices grupales y colaborativas. Desarrolla habilidades emocionales que facilitan su interacción con otros en diferentes contextos y actividades motrices.', ARRAY['Desarrolla habilidades emocionales que facilitan su interacción con otros en diferentes contextos y actividades motrices.']),
('Párvulos 3', 'Educación Física', 'Establece relaciones sociales positivas y autorregula sus emociones, de manera progresiva, en las actividades motrices grupales y colaborativas. Autorregula sus emociones al interactuar de forma progresiva a la etapa de desarrollo.', ARRAY['Autorregula sus emociones al interactuar de forma progresiva a la etapa de desarrollo.']),

('Párvulos 1', 'Educación Física', 'Practica hábitos de higiene, alimentarios y de actividad física que favorecen su desarrollo integral y mejoran su calidad de vida. Realiza rutinas de higiene, actividades físicas y hábitos alimentarios de manera guiada en beneficio de una vida saludable.', ARRAY['Realiza rutinas de higiene, actividades físicas y hábitos alimentarios de manera guiada en beneficio de una vida saludable.']),
('Párvulos 2', 'Educación Física', 'Practica hábitos de higiene, alimentarios y de actividad física que favorecen su desarrollo integral y mejoran su calidad de vida. Practica actividad física, hábitos higiénicos y alimentarios que favorecen su desarrollo integral.', ARRAY['Practica actividad física, hábitos higiénicos y alimentarios que favorecen su desarrollo integral.']),
('Párvulos 3', 'Educación Física', 'Practica hábitos de higiene, alimentarios y de actividad física que favorecen su desarrollo integral y mejoran su calidad de vida. Practica con autonomía rutinas de hábitos higiénicos, alimentarios y de actividad física que le permiten mejorar su calidad de vida.', ARRAY['Practica con autonomía rutinas de hábitos higiénicos, alimentarios y de actividad física que le permiten mejorar su calidad de vida.']);

-- ===== cnb_primaria_1.sql =====
-- CNB Primaria - Comunicación y Lenguaje L 1 - Primer Grado
-- Fuente: https://cnbguatemala.org/wiki/Dosificaci%C3%B3n_de_los_aprendizajes_-_%C3%81rea_de_Comunicaci%C3%B3n_y_Lenguaje_L_1_-_Primer_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primer Grado', 'Comunicación y Lenguaje L 1', '1. Escucha a su interlocutor o interlocutora demostrando respeto y comprensión del mensaje por medio de gestos y movimientos. 1.1. Demuestra respeto hacia las prácticas comunicativas de otras personas y culturas. 1.2. Demuestra comprensión de lo que escucha. 1.3. Identifica los sonidos del habla y percibe sus semejanzas y diferencias en los mensajes que escucha. (Conciencia fonológica).', ARRAY['1.1.1. Demostración de respeto hacia la persona que habla: posición del cuerpo, gestos (miradas, movimientos de la cara, señales con las manos, con los hombros, entre otros.), silencio en el momento en que se usa la palabra.', '1.1.2. Práctica de normas de cortesía en conversaciones, diálogos y discusiones (esperar turno para hablar, hablar con el tono de voz apropiado, utilizar el vocabulario preciso, evitar el uso de sobrenombres, clasificadores personales, entre otros).', '1.1.3. Demostración de respeto hacia gestos y prácticas comunicativas comunes en otros idiomas y culturas del país.', '1.2.1. Seguimiento de instrucciones orales de hasta tres eventos.', '1.2.2. Interpretación de rimas, cuentos, poemas, canciones, entre otros por medio de gestos y movimientos corporales.', '1.2.3. Comparación de las características de los personajes que protagonizan los cuentos en las narraciones que escuchan.', '1.2.4. Expresión de opiniones sobre el texto que se lee o escucha (Comprensión crítica).', '1.3.1. Identificación de similitudes y diferencias entre los sonidos en el lenguaje que escucha.', '1.3.2. Percepción auditiva de las sílabas que integran las palabras clave en los mensajes que escucha.', '1.3.3. Reconocimiento de los fonemas como las unidades sonoras que conforman las palabras que escucha.', '1.3.4. Identificación de palabras que riman.', '1.3.5. Percepción auditiva del fonema inicial y del fonema final en las palabras que escucha.', '1.3.6 Reconocimiento de la diferencia que representa la sustitución de una letra en palabras determinadas en cuanto a sonido y significación (luna - lana - lona; puma - fuma - bruma; casa - caza - caña - cana).']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '2. Expresa oralmente sus opiniones, sentimientos, emociones y experiencias de su contexto familiar y escolar. 2.1. Utiliza diferentes estrategias para expresarse. 2.2. Narra o describe oralmente, situaciones reales o ficticias.', ARRAY['2.1.1. Organización de la información necesaria dentro y fuera del aula.', '2.1.2. Estructuración mental de la información solicitada antes de verbalizar su respuesta.', '2.1.3. Formulación de preguntas para solicitar información y de respuestas a preguntas que le plantean. (Entrevista)', '2.1.4. Emisión de opiniones personales al evaluar mensajes escuchados', '2.1.5. Iniciación y desarrollo de conversaciones dentro y fuera del aula.', '2.1.6. Utilización de argumentos pertinentes para fundamentar una idea ante diferentes opiniones.', '2.2.1. Narración de experiencias propias o de otros y otras.', '2.2.2. Narración de cuentos, leyendas, poemas y otros tipos de textos escuchados.', '2.2.3. Narración de mensajes orales escuchados, resumiendo o aclarando la información.', '2.2.4. Descripción de experiencias utilizando oraciones y pronunciando claramente.', '2.2.5. Reproducción de juegos verbales: rimas, trabalenguas, retahilas.', '2.2.6. Reproducción oral de lo escuchado recitándolo o parafraseándolo.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '3. Utiliza el lenguaje no verbal como auxiliar de la comunicación. 3.1. Utiliza gestos y movimientos corporales como apoyo en su expresión oral. 3.2. Utiliza sonidos onomatopéyicos para reforzar sus mensajes.', ARRAY['3.1.1. Comunicación de estados de ánimo por medio de gestos.', '3.1.2. Descripción de las características de objetos y de personas por medio de gestos.', '3.1.3. Manifestación del conocimiento de su esquema corporal por medio de gestos.', '3.1.4. Asociación de los movimientos corporales con las palabras que indican la dirección de su desplazamiento en el espacio: arriba, abajo, adelante, atrás, izquierda, derecha, entre otras.', '3.1.5. Utilización de gestos y movimientos corporales para indicar la posición de objetos en el espacio y la relación que existe ellos: encima, debajo, adelante atrás, lejos, cerca, izquierda, derecha, al frente, detrás de, entre otros.', '3.1.6. Representación de cuentos, juegos e historietas por medio del lenguaje corporal, de la danza y del teatro.', '3.2.1. Utilización de palabras cuya pronunciación imita el sonido de aquello que describe: "pum", "clic", "crash", entre otras.', '3.2.2. Utilización de palabras que imitan el sonido producido por animales: "miau", "guau", "pío, pío", "cuac, cuac", entre otras.', '3.2.3. Utilización de palabras que imitan el sonido producido por instrumentos musicales: "chin", "plin", "pom, pom, pom", entre otros.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '4. Utiliza la lectura para recrearse y asimilar información. 4.1. Interpreta el significado de imágenes, signos, símbolos y señales del entorno y los relaciona con textos escritos. 4.2. Lee textos de diferente contenido demostrando comprensión de los mismos a un nivel literal. 4.3. Lee textos de diferente. 4.4. Emite opinión con respecto al contenido de los textos que lee y analiza. 4.5. Lee con un propósito definido: recrearse u obtener información.', ARRAY['4.1.1. Identificación de signos, símbolos, íconos y señales del entorno inmediato.', '4.1.2. Diferenciación entre ilustraciones, señales y texto escrito.', '4.1.3. Asociación de ilustraciones con textos cortos que las describen.', '4.1.4. Identificación de las partes de un libro: portada, título, subtítulos, entre otros.', '4.1.5. Sucesión cronológica o temporal de eventos en una historia: ordenamiento de gráficas o ilustraciones.', '4.1.6. Predicción sobre el tema de una historia a partir de signos, símbolos o ilustraciones.', '4.2.1. Asociación entre objetos del entorno y la o las palabras que los nombran.', '4.2.2. Establecimiento de la relación símbolo escrito (grafema) y sonido (fonema)', '4.2.3. Asociación del fonema con la letra respectiva (por lo menos las vocales y 6 consonantes).', '4.2.4. Asociación del fonemas con las letras del alfabeto (por lo menos las vocales y 12 consonantes).', '4.2.5. Asociación de fonemas con las letras del alfabeto (por lo menos las vocales y 20 consonantes).', '4.2.6. Lectura de palabras, oraciones e historias con dominio de las vocales y por lo menos 6 consonantes, y con dominio de las vocales y por lo menos 12 consonantes.', '4.2.7. Lectura de las palabras que nombran números de uno a diez en español y de uno a veinte en idiomas mayas.', '4.2.8 Formulación de preguntas y elaboración de respuestas a nivel literal sobre la lectura.', '4.2.9. Seguimiento de instrucciones escritas, con no más de tres acciones.', '4.3.1. Identificación del orden de los eventos en las historias o material informativo que lee.', '4.3.2 Identificación de los detalles importantes en un texto: personajes principales y secundarios, hechos, objetos, entre otros.', '4.3.3. Comparación y contraste entre personajes y entre lugares.', '4.3.4. Diferenciación entre el inicio y el final de la historia', '4.3.5. Identificación de la idea principal de un texto corto.', '4.3.6. Reconocimiento de palabras que pueden sustituir a otras en una historia sin cambiar el significado de la misma.', '4.4.1. Identificación del problema y de las posibles soluciones en los textos que lee.', '4.4.2. Emisión de comentarios de gusto o disgusto sobre los textos que lee.', '4.4.3. Elaboración de conclusiones tomando en cuenta los acontecimientos principales en la historia.', '4.5.1. Distinción entre fantasía y realidad.', '4.5.2. Lectura de diversos tipos de texto.', '4.5.3. Distinción entre un cuento y una noticia.', '4.5.4. Diferenciación entre la estructura de los cuentos y las cartas.', '4.5.5. Lectura con diferentes propósitos: como recreación (rimas, retahilas, poemas y cuentos), para determinar la ubicación en el tiempo: reloj y calendarios - gregoriano y cholq''ij-, con diferentes intenciones: compras, inventarios, almacenamiento.', '4.5.6. Localización de información específica en diversos medios impresos: libros, revistas, periódicos, entre otros.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '5. Se expresa por escrito utilizando los trazos de las letras y los signos de puntuación. 5.1. Aplica los principios de la caligrafía al expresarse por escrito. 5.2. Utiliza principios de gramática al expresarse por escrito.', ARRAY['5.1.1. Aplicación de los principios de la caligrafía: posición del cuerpo, empuñadura del lápiz, posición del papel, trazo de letras, entre otros.', '5.1.2. Observación de la direccionalidad de las letras al escribir (rasgos que ocupan el espacio principal, rasgos que se extienden hacia arriba y hacia abajo).', '5.1.3. Observación de la linealidad al escribir (dirección izquierda - derecha).', '5.1.4. Observación de los espacios entre las letras y las palabras, márgenes.', '5.1.5. Utilización de los elementos convencionales para escribir: lugar de las letras y palabras sobre el renglón.', '5.2.1. Diferenciación entre letras mayúsculas y minúsculas.', '5.2.2. Utilización de mayúscula inicial en las oraciones que escribe.', '5.2.3. Uso del punto al final de las oraciones que escribe.', '5.2.4. Formulación de oraciones que reflejen concordancia de género y de número según la lengua materna.', '5.2.5. Formulación de párrafos que reflejen orden lógico de las ideas: inicio, desarrollo y desenlace.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '6. Utiliza nociones de la estructura de las palabras al expresar sus ideas. 6.1. Identifica las sílabas que conforman las palabras y percibe sus semejanzas y diferencias. (Conciencia silábica). 6.2. Forma nuevas palabras con base en la estructura del idioma.', ARRAY['6.1.1. Identificación de las palabras que integran una oración.', '6.1.2. Identificación oral de las sílabas que conforman palabras específicas.', '6.1.3. Separación oral de palabras en sílabas.', '6.1.4. Reconocimiento de sílabas directas, indirectas y cerradas en palabras conocidas.', '6.1.5. Diferenciación entre sílabas directas y cerradas.', '6.2.1. Indicación del número de sílabas que conforman una palabra.', '6.2.2. Formación de palabras nuevas tomando como referencia palabras conocidas', '6.2.3. Formación de palabras nuevas uniendo sílabas de palabras conocidas.', '6.2.4. Formación del plural de las palabras en español agregando "s" o "es"; en K''iche'' "ab" o "ib"; en Q''eqchi'' "eb"; entre otros.', '6.2.5. Formación de familias de palabras agregando a la raíz el afijo que forma el diminutivo y el aumentativo de palabras conocidas (sufijo en español; prefijos en idiomas mayas).']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '7. Utiliza vocabulario propio de su lengua materna abundante y pertinente en su interacción con las y los demás. 7.1. Demuestra comprensión del vocabulario que escucha. 7.2. Manifiesta interés por enriquecer su vocabulario con palabras y expresiones propias de su lengua materna. 7.3. Utiliza el vocabulario adquirido en diferentes situaciones al interactuar con otras personas.', ARRAY['7.1.1. Utilización de claves de contexto para identificar palabras nuevas.', '7.1.2. Utilización pertinente de palabras que se forman a partir de palabras conocidas.', '7.1.3. Utilización del vocabulario apropiado para describir características físicas (adjetivos), estados de ánimo, emociones, sensaciones y sentimientos.', '7.1.4. Análisis oral (deletreo) de palabras cuyo significado desconoce.', '7.1.5. Identificación de palabras que nombran (sustantivos: comunes y propios).', '7.1.6. Identificación de palabras con significado igual o parecido (sinónimos).', '7.1.7. Identificación de palabras con significado opuesto (antónimos).', '7.2.1. Interpretación del significado de palabras desconocidas asociándolas con el vocabulario que posee.', '7.2.2. Uso del contexto para identificar el significado de palabras nuevas.', '7.2.3 Utilización de vocabulario y expresiones propias de su lengua materna.', '7.3.1. Descripción de estados de ánimo utilizando las palabras apropiadas y la entonación precisa.', '7.3.2. Incorporación, al vocabulario básico, de palabras que escucha en su interacción con otras personas y que son apropiadas a la situación.', '7.3.3. Introducción de palabras nuevas en los textos que escribe.', '7.3.4. Utilización del vocabulario adecuado según el tipo de texto que escribe.']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '8. Expresa por escrito sus sentimientos, emociones pensamientos y experiencias. 8.1. Expresa por escrito su percepción de las características de personas, objetos, animales y plantas. 8.2. Narra experiencias personales o elementos de lecturas realizadas.', ARRAY['8.1.1. Elaboración de dibujos para expresar ideas con respecto a personas, objetos, animales y plantas', '8.1.2. Descripción de características de los personajes incluidos en sus dibujos.', '8.2.1. Representación de ideas o contenido de un cuento por medio de dibujos en secuencia.', '8.2.2. Selección de las palabras apropiadas según los dibujos elaborados alrededor de un tema.', '8.2.3. Elaboración de imágenes para ilustrar textos que redacta.', '8.2.4. Redacción individual de narraciones cortas, anéctotas y chistes acerca de eventos de la vida cotidiana.', '8.2.5. Organización de ideas y respeto a las normas del idioma al elaborar narraciones cortas (dominio de, por lo menos, 20 consonantes y las vocales).', '8.2.6. Formulación de párrafos sencillos que reflejen concordancia entre artículos, sustantivos y adjetivos (sin mencionar la terminología).']),

('Primer Grado', 'Comunicación y Lenguaje L 1', '9. Utiliza el lenguaje oral y escrito como instrumento para afianzar su aprendizaje. 9.1. Utiliza elementos del lenguaje oral y escrito en la reafirmación de su aprendizaje. 9.2. Utiliza elementos del lenguaje oral y escrito en el manejo de la información que proporcionan los medios de comunicación.', ARRAY['9.1.1. Expresión de ideas, sentimientos y emociones formando párrafos según las reglas del idioma.', '9.1.2. Utilización de la información obtenida de diferentes medios en la formulación de preguntas y mostrar sus puntos de vista.', '9.1.3 Revisión de textos que produce para corregirlos y asegurar que puedan ser comprendidos por otras personas.', '9.2.1. Utilización de la biblioteca del aula en la documentación de sus trabajos.', '9.2.2. Selección de los recursos existentes y de la información pertinente para estructurar el periódico mural.']);

-- ===== cnb_primaria_2.sql =====
-- CNB Primaria - Comunicación y Lenguaje L 1 - Segundo Grado
-- Fuente: https://cnbguatemala.org/wiki/Dosificaci%C3%B3n_de_los_aprendizajes_-_%C3%81rea_de_Comunicaci%C3%B3n_y_Lenguaje_L_1_-_Segundo_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Grado', 'Comunicación y Lenguaje L 1', '1. Escucha diferentes mensajes demostrando comprensión por medio de gestos, movimientos corporales o en forma oral. 1.1. Demuestra respeto hacia las personas a quienes escucha y hacia las prácticas comunicativas de otras culturas. 1.2. Utiliza gestos y lenguaje corporal para responder a mensajes escuchados. 1.3. Establece la relación entre símbolo, sonido y significado (Conciencia fonológica). 1.4. Emite opiniones que reflejan diferentes niveles de comprensión de lo escuchado.', ARRAY['1.1.1. Demostración de respeto hacia la persona que habla (posición del cuerpo, gestos faciales, silencio cuando otras y otros están en el uso de la palabra).', '1.1.2. Práctica de normas de cortesía en conversaciones, diálogos y discusiones.', '1.1.3. Demostración de respeto hacia gestos y prácticas comunicativas comunes en otros idiomas y culturas del país.', '1.1.4. Uso de expresiones de cortesía: saludo, despedida, excusas, agradecimientos, disculpas al interrumpir.', '1.1.5. Demostración de respeto por el derecho a la diferencia de opinión.', '1.2.1. Seguimiento de instrucciones orales con tres o más eventos.', '1.2.2. Interpretación de rimas, cuentos, poemas, canciones, entre otros, por medio de gestos y movimientos corporales.', '1.2.3. Reproducción de lo escuchado por medios electrónicos: radio, cintas, discos compactos, entre otros.', '1.3.1. Aplicación de destrezas de comunicación oral: entonación, fluidez, volumen.', '1.3.2. Reconocimiento de palabras específicas que escucha en párrafos descriptivos o narrativos y poemas.', '1.3.3. Identificación del fonema inicial y final en palabras que escucha.', '1.3.4. Reconocimiento de la rima en el lenguaje poético.', '1.3.5. Identificación de ritmo, rima y sonoridad en el lenguaje poético.', '1.3.6. Identificación de la diferencia que representa, en cuanto a sonido y significado, la sustitución de una letra en palabras determinadas.', '1.3.7. Reproducción oral del ritmo, la rima y la sonoridad en elementos expresados en lenguaje poético.', '1.3.8. Segmentación de las sílabas que conforman palabras que escucha según los fonemas que las integran.', '1.3.9. Identificación de las sílabas que integran determinadas palabras que escucha.', '1.4.1. Repetición de información explícita expresada oralmente por medio de diálogos, lecturas o narraciones que escucha (Comprensión literal).', '1.4.2. Establecimiento de similitudes y diferencias entre las características de los personajes que protagonizan los cuentos o las narraciones que se escuchan.', '1.4.3. Asociación de situaciones en las narraciones que escucha con la experiencia personal.', '1.4.4. Enumeración, explicación y justificación de los contenidos de los mensajes o presentaciones que escucha.', '1.4.5. Anticipación o predicción de lo que pueda ocurrir en los mensajes que escucha (Comprensión semántica).', '1.4.6. Inferencia o suposición de ideas relacionadas con los mensajes que escucha (Comprensión semántica).', '1.4.7. Expresión de opiniones que reflejen análisis y evaluación con respecto al texto que se lee o escucha (Comprensión crítica).']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '2. Expresa oralmente, su respuesta a mensajes emitidos por otras personas. 2.1. Utiliza estrategias del lenguaje oral que le permiten obtener información precisa. 2.2. Utiliza diferentes estrategias para responder oralmente los mensajes recibidos. 2.3. Demuestra seguridad al emitir, oralmente, sus opiniones ante mensajes recibidos.', ARRAY['2.1.1. Solicitud de información o explicaciones dentro del aula.', '2.1.2. Formulación de respuestas según información solicitada.', '2.1.3. Inicio y desarrollo de conversaciones y diálogos de tipo social y personal dentro del aula y del ambiente escolar.', '2.2.1. Emisión de información que se solicita.', '2.2.2. Reproducción oral de lo escuchado, recitándolo o parafraseándolo.', '2.2.3. Emisión de opiniones personales dentro y fuera del aula.', '2.2.4. Utilización de argumentos pertinentes para fundamentar una idea u opinión.', '2.2.5. Narración de experiencias propias o de otros y de mensajes orales que se escuchan resumiendo o aclarando la información.', '2.2.6. Narración de cuentos, leyendas, poemas y otros tipos de texto que escucha.', '2.2.7. Reproducción de juegos verbales: dichos populares, refranes.', '2.3.1. Organización lógica y secuencial de la información.', '2.3.2. Descripción o narración de experiencias utilizando oraciones completas y pronunciando claramente las palabras.', '2.3.3. Descripción de personajes, lugares u objetos utilizando los adjetivos apropiados.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '3. Utiliza el lenguaje no verbal como un auxiliar de la comunicación oral en la manifestación de sus ideas, sentimientos y emociones. 3.1. Utiliza gestos faciales y movimientos corporales como apoyo en su comunicación oral. 3.2. Utiliza sonidos onomatopéyicos para reforzar sus mensajes orales. 3.3. Utiliza la información presentada por medio de signos, símbolos y otros recursos gráficos.', ARRAY['3.1.1. Utilización de los elementos del lenguaje no verbal (gestos, mímica, movimientos corporales, desplazamientos, voces onomatopéyicas) como apoyo en la manifestación de sus ideas.', '3.1.2. Utilización de gestos y movimientos corporales en la comunicación de estados de ánimo.', '3.1.3. Descripción de características de objetos y de personas por medio de gestos y movimientos corporales.', '3.1.4. Descripción oral de la relación entre direccionalidad y movimientos corporales que indican la dirección de su desplazamiento en el espacio.', '3.1.5. Utilización de gestos y movimientos corporales para indicar la posición de objetos en el espacio y la relación entre ellos.', '3.1.6. Participación voluntaria en dramatizaciones formales o informales, espontáneas o dirigidas.', '3.1.7. Identificación de los elementos básicos de la dramatización (tema, ambiente, personajes, entre otros).', '3.1.8. Representación de cuentos por medio del lenguaje corporal, de la danza y del teatro.', '3.1.9. Representación de juegos e historias mediante el lenguaje corporal.', '3.1.10. Utilización de la poesía coral como medio de expresión.', '3.2.1. Utilización de palabras que imitan el sonido de aquello que describen.', '3.2.2. Utilización de palabras que reproducen el sonido de animales.', '3.2.3. Utilización de palabras que imitan el sonido producido por instrumentos musicales.', '3.2.4. Identificación de palabras que nombran el efecto que produce el sonido emitido por animales.', '3.3.1. Diferenciación entre signos, señales convencionales y señales naturales frecuentemente utilizados en su entorno.', '3.3.2. Respeto por las señales viales en la escuela y la comunidad.', '3.3.3. Interpretación de la información presentada por medio de tablas y otros recursos gráficos.', '3.3.4. Utilización de símbolos, señales y otros recursos gráficos para establecer comunicación con otros.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '4. Utiliza estrategias de lectura con propósitos informativos y recreativos. 4.1. Interpreta el significado de ilustraciones, imágenes, signos, símbolos y señales del entorno y las relaciona con textos escritos. 4.2. Demuestra fluidez en su lectura oral. 4.3. Demuestra fluidez en lectura silenciosa. 4.4. Identifica palabras con diferentes significados demostrando comprensión de los conceptos que representan. 4.5. Identifica los hechos y detalles o elementos importantes en lo que lee y sus implicaciones para anticipar los eventos en un texto determinado. 4.6. Emite opinión con respecto al contenido de los textos que lee y analiza. 4.7. Lee para obtener información.', ARRAY['4.1.1. Asociación de ilustraciones con textos que las describen.', '4.1.2. Identificación de palabras en negrilla, palabras subrayadas y de otros recursos gráficos que resaltan los detalles del texto.', '4.1.3. Predicción sobre el tema de la lectura a partir de signos, símbolos o ilustraciones.', '4.2.1. Reconocimiento instantáneo de palabras seleccionadas.', '4.2.2. Lectura de palabras pronunciando claramente las sílabas que las componen.', '4.2.3. Reconocimiento visual instantáneo de diptongos y triptongos en el caso del español.', '4.2.4. Selección visual instantánea de palabras con principios y finales comunes (familias de palabras).', '4.2.5. Reconocimiento visual instantáneo de palabras compuestas.', '4.2.6. Diferenciación entre palabras que se confunden fácilmente por su forma.', '4.2.7. Lectura oral de oraciones y párrafos con las palabras que reconocen instantáneamente.', '4.3.1. Diferenciación entre la lectura oral y la silenciosa.', '4.3.2. Utilización de estrategias de decodificación adecuados al texto objeto de la lectura.', '4.3.3. Aumento en su velocidad de comprensión lectora.', '4.4.1. Asociación de palabras en un texto determinado con su sinónimo correspondiente.', '4.4.2. Selección de una palabra determinada situándola en el contexto apropiado.', '4.4.3. Uso del contexto en el desarrollo de conceptos.', '4.4.4. Reconocimiento de una palabra determinada dándole una definición propia.', '4.4.5. Identificación de una palabra determinada indicando la función que desempeña en el texto.', '4.4.6. Asociación de objetos del entorno con la o las palabras que los nombran.', '4.5.1. Clasificación de objetos o de los hechos en un texto determinado según sus similitudes y diferencias.', '4.5.2. Identificación de los detalles o elementos importantes en un texto.', '4.5.3. Determinación del orden de los eventos en las historias o material informativo que lee.', '4.5.4. Formulación de respuestas a preguntas literales sobre los textos que lee.', '4.5.5. Identificación de la causa y el efecto en eventos determinados contenidos en materiales narrativos.', '4.5.6. Identificación de la idea principal y de las ideas secundarias en los textos leídos.', '4.5.7. Seguimiento de instrucciones escritas de no más de cuatro hechos o eventos.', '4.6.1. Identificación del problema y anticipación de su solución en los textos que lee.', '4.6.2. Expresión de comentarios de gusto o disgusto sobre los textos que escucha o lee.', '4.6.3. Elaboración de conclusiones tomando en cuenta los acontecimientos principales en la historia.', '4.7.1. Diferenciación entre cuento y noticia.', '4.7.2. Diferenciación entre texto informativo y texto narrativo.', '4.7.3. Búsqueda de información específica en diversos medios impresos.', '4.7.4. Definición de la estructura de los cuentos, las cartas, los instructivos y las listas.', '4.7.5. Toma de conciencia de su propio proceso de lectura tanto en voz alta como silenciosa (Control metacognitivo).', '4.7.6. Lectura voluntaria de textos literarios: rimas, retahílas, poemas y cuentos como recreación.', '4.7.7. Utilización voluntaria de la biblioteca del aula o de la escuela o de textos en formatos electrónicos para seleccionar lecturas.', '4.7.8. Lectura de listas de objetos con diferentes intenciones: compras, inventarios, almacenamiento.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '5. Se expresa por escrito de acuerdo con los cambios que sufren las palabras al relacionarse unas con otras. 5.1. Aplica los principios de la caligrafía al expresarse por escrito. 5.2. Utiliza principios de gramática al expresarse por escrito.', ARRAY['5.1.1. Aplicación de los principios de la caligrafía: posición del cuerpo, empuñadura del lápiz, posición del papel.', '5.1.2. Direccionalidad al escribir.', '5.1.3. Linealidad al escribir (dirección izquierda-derecha).', '5.1.4. Espacios entre letras y palabras, márgenes.', '5.1.5. Introducción al uso de la letra cursiva al expresarse por escrito.', '5.1.6. Utilización, indistinta, de la letra de molde (script) y de la cursiva.', '5.2.1. Clasificación de palabras que nombran (sustantivos).', '5.2.2. Clasificación de palabras que describen (adjetivos).', '5.2.3. Utilización del pronombre como sustituto del nombre.', '5.2.4. Identificación de palabras que indican acción, sensación, estado y emoción en tiempo presente y pasado.', '5.2.5. Identificación de las partes de la oración: Sujeto y Predicado.', '5.2.6. Uso del punto al final de las oraciones y de los párrafos que escribe.', '5.2.7. Utilización de la coma para separar frases en una oración.', '5.2.8. Identificación de oraciones declarativas.', '5.2.9. Identificación de oraciones interrogativas.', '5.2.10. Utilización de los signos de interrogación en oraciones interrogativas.', '5.2.11. Identificación de oraciones exclamativas.', '5.2.12. Identificación de signos de admiración en oraciones exclamativas.', '5.2.13. Creación de oraciones declarativas, interrogativas, exclamativas.', '5.2.14. Formulación de oraciones y párrafos que reflejen concordancia de género y de número según la lengua materna.', '5.2.15. Utilización del guión mayor al escribir conversaciones.', '5.2.16. Diferenciación entre letras mayúsculas y minúsculas.', '5.2.17. Uso de la letra mayúscula al iniciar la oración, el párrafo y al escribir nombres propios.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '6. Utiliza, con propiedad, un vocabulario abundante en su comunicación oral y escrita. 6.1. Utiliza el análisis de la estructura de las palabras para ampliar su vocabulario. 6.2. Utiliza el análisis fonético para reconocer palabras nuevas. 6.3. Utiliza el contexto para identificar los significados de palabras nuevas. 6.4. Utiliza, eficientemente, el vocabulario adquirido en la interacción con los demás.', ARRAY['6.1.1. Identificación oral de las sílabas que conforman palabras específicas.', '6.1.2. Separación oral de palabras en sílabas.', '6.1.3. Unión de sílabas para formar palabras nuevas.', '6.1.4. Identificación del número de sílabas que conforman una palabra.', '6.1.5. Sustitución del final de palabras conocidas por otras letras o combinaciones de letras para formar nuevas palabras.', '6.1.6. Lectura de palabras nuevas que se forman al sustituir las letras iniciales en palabras conocidas.', '6.1.7. Creación de palabras nuevas utilizando sílabas de palabras conocidas.', '6.1.8. Formación del plural de las palabras según el idioma.', '6.1.9. Formación de familias de palabras agregando a la raíz el afijo que forma el diminutivo y el aumentativo.', '6.1.10. Clasificación de las palabras por el número de sílabas.', '6.1.11. Clasificación de las palabras por la sílaba acentuada: agudas, graves, esdrújulas.', '6.2.1. Análisis oral (deletreo) de palabras cuyo significado desconoce.', '6.2.2. Identificación de dígrafos en palabras del vocabulario básico (ll, rr, ch, qu).', '6.2.3. Identificación de palabras que empiezan con una combinación de consonantes según el idioma que se maneje.', '6.2.4. Identificación de palabras que terminan con la misma combinación de sonidos.', '6.2.5. Identificación de sustantivos dentro de los textos y su significado por el contexto.', '6.3.1. Identificación del significado de adjetivos y verbos por las palabras anteriores y posteriores.', '6.4.1. Utilización de palabras nuevas en su conversación con los demás o en las narraciones y descripciones emitidas.', '6.4.2. Descripción de estados de ánimo utilizando las palabras apropiadas y la entonación precisa.', '6.4.3. Incorporación, al vocabulario básico, de palabras que escucha en su interacción con otros y que considera apropiadas a la situación.', '6.4.4. Introducción de palabras nuevas en los textos que escribe.', '6.4.5. Utilización del vocabulario adecuado al tipo de texto que escribe.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '7. Redacta textos informativos y literarios apegándose a las normas del idioma. 7.1. Caracteriza los elementos presentes en textos informativos. 7.2. Caracteriza los elementos presentes en textos literarios.', ARRAY['7.1.1. Identificación de las ilustraciones como apoyo a la expresión de ideas con respecto a personas, objetos, animales y plantas.', '7.1.2. Determinación de la relación entre el título y el contenido del tema bajo estudio.', '7.1.3. Atención a las características del párrafo al redactar textos informativos.', '7.1.4. Distribución de la información en diferentes párrafos atendiendo al tema.', '7.1.5. Redacción de notas, mensajes, textos informativos y descriptivos según las normas del idioma.', '7.1.6. Utilización de los pasos a seguir en la redacción de textos.', '7.2.1. Reconocimiento de la estructura de los poemas.', '7.2.2. Identificación de la sílaba que se pronuncia con mayor fuerza en la última palabra de cada verso.', '7.2.3. Reconocimiento del sonido final en cada verso de un poema dado.', '7.2.4. Selección de las palabras que riman en un poema dado.', '7.2.5. Características del texto literario (recrea la realidad desde un punto de vista personal y refleja la subjetividad del autor).']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '8. Utiliza el lenguaje oral y escrito para adquirir información con respecto a los elementos de la vida cotidiana. 8.1. Utiliza diferentes estrategias del lenguaje oral para adquirir información en eventos de la vida cotidiana. 8.2. Utiliza diferentes estrategias para organizar la información obtenida en publicaciones periódicas, libros, bibliotecas, entre otros.', ARRAY['8.1.1. Formulación de preguntas para definir la información que recibe.', '8.1.2. Interpretación y reproducción oral de lo escuchado por medios de comunicación auditiva.', '8.1.3. Organización de la información que transmiten los medios audiovisuales.', '8.1.4. Organización de entrevistas para obtener información con respecto a eventos de la vida cotidiana.', '8.2.1. Revisión de textos que se producen para corregirlos y asegurar que puedan ser comprendidos por otras personas.', '8.2.2. Elaboración de esquemas que indican la distribución de tareas de aprendizaje.', '8.2.3. Selección de los recursos existentes y de la información pertinente para estructurar diversos documentos.']);

-- ===== cnb_primaria_3.sql =====
-- CNB Primaria - Comunicación y Lenguaje L 1 - Tercer Grado
-- Fuente: https://cnbguatemala.org/wiki/Dosificaci%C3%B3n_de_los_aprendizajes_-_%C3%81rea_de_Comunicaci%C3%B3n_y_Lenguaje_L_1_-_Tercer_Grado
-- Nivel de detalle: competencia + sub-competencias (1.1, 1.2...), sin bajar a indicadores 1.1.1

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercer Grado', 'Comunicación y Lenguaje L 1', '1. Interpreta mensajes orales emitidos con lenguaje cotidiano, científico y literario.', ARRAY['1.1. Interpreta mensajes orales expresados en lenguaje cotidiano.', '1.2. Interpreta mensajes orales emitidos en lenguaje literario.', '1.3. Interpreta mensajes emitidos en lenguaje científico.']),
('Tercer Grado', 'Comunicación y Lenguaje L 1', '2. Expresa oralmente sus opiniones y pensamientos utilizando las estrategias adecuadas.', ARRAY['2.1. Utiliza los recursos adecuados en la expresión de sus mensajes orales, dependiendo de la intencionalidad de cada uno.', '2.2. Sustenta en forma espontánea sus ideas y opiniones, con argumentos lógicos.', '2.3. Organiza sus ideas en forma lógica y secuencial.']),
('Tercer Grado', 'Comunicación y Lenguaje L 1', '3. Utiliza elementos del lenguaje no verbal en el análisis de expresiones emitidas en otros lenguajes y por diferentes interlocutores.', ARRAY['3.1. Interpreta los mensajes implícitos en signos y señales utilizados en la comunidad.', '3.2. Asocia el significado de símbolos y señales con normas e instrucciones.', '3.3. Interpreta los mensajes que contienen los diferentes tipos de historietas gráficas.']),
('Tercer Grado', 'Comunicación y Lenguaje L 1', '4. Aplica diversas estrategias de lectura para la asimilación de la información, la ampliación de conocimientos y como recreación.', ARRAY['4.1. Diferencia las destrezas de la lectura oral y de la silenciosa.', '4.2. Relaciona imagen y texto al hacer inferencias sobre la lectura, tanto en lectura oral como silenciosa.', '4.3. Identifica las palabras o expresiones que desempeñan funciones específicas en un texto, tanto en lectura oral como silenciosa.', '4.4. Utiliza destrezas de síntesis y aplicación en la interpretación de textos informativos en lectura silenciosa.', '4.5. Utiliza destrezas de análisis y de evaluación al seleccionar información específica.']),
('Tercer Grado', 'Comunicación y Lenguaje L 1', '5. Expresa sus ideas por escrito utilizando la estructura de las palabras y las modificaciones que sufren en su relación con las demás.', ARRAY['5.1. Atiende las variaciones de las palabras (género, número, tiempo, persona) al redactar oraciones y párrafos.', '5.2. Atiende las variaciones de las palabras en cuanto a la pronunciación indicada por medio de la acentuación.', '5.3. Incluye, en los textos que escribe, elementos que señalan matices semánticos.', '5.4. Aplica las normas del idioma (organización lógica de la información) al elaborar párrafos o historias.']),
('Tercer Grado', 'Comunicación y Lenguaje L 1', '6. Enriquece su vocabulario básico con palabras generadas con la aplicación de diferentes estrategias.', ARRAY['6.1. Genera palabras utilizando el análisis de su estructura.', '6.2. Identifica palabras desconocidas utilizando el análisis fonético.', '6.3. Reconoce palabras desconocidas utilizando el diccionario.']),
('Tercer Grado', 'Comunicación y Lenguaje L 1', '7. Redacta textos con diferentes propósitos apegándose a las normas del idioma.', ARRAY['7.1. Elabora textos en los que describe o narra sus experiencias.', '7.2. Redacta documentos informativos utilizados como parte de la vida cotidiana.', '7.3. Crea poemas para expresar ideas y sentimientos.']),
('Tercer Grado', 'Comunicación y Lenguaje L 1', '8. Aplica las herramientas del lenguaje oral y escrito además de recursos diversos en la investigación y en la generación de nuevos conocimientos.', ARRAY['8.1. Aplica herramientas del lenguaje oral y escrito para obtener información en tareas de investigación.', '8.2. Utiliza diferentes recursos de la expresión escrita para organizar la información obtenida en investigaciones.', '8.3. Utiliza diferentes estrategias para estructurar la información obtenida.']);

-- ===== cnb_primaria_4.sql =====
-- CNB Primaria - Comunicación y Lenguaje L 1 - Cuarto, Quinto y Sexto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Comunicación_y_Lenguaje_L_1_-_{Cuarto,Quinto,Sexto}_Grado
-- Nivel de detalle: competencia + sub-competencias

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Cuarto Grado
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '1. Interpreta mensajes escuchados en diferentes situaciones de comunicación social.', ARRAY['1.1. Identifica elementos importantes en mensajes escuchados en situaciones diversas de comunicación social.', '1.2. Demuestra comprensión de la información contenida en mensajes recibidos por medios audiovisuales: el teléfono, la radio, la televisión, entre otros.', '1.3. Organiza el contenido de los mensajes recibidos y la respuesta que dará a los mismos.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '2. Participa en intercambios comunicativos orales adecuando los mensajes que emite a la situación en que se encuentra.', ARRAY['2.1. Utiliza la modulación, la entonación y el timbre de la voz adecuados a la circunstancia comunicativa y al interlocutor o a los interlocutores.', '2.2. Organiza, en forma lógica y coherente, la información recibida en mensajes orales.', '2.3. Participa en situaciones comunicativas de manera responsable y respetuosa para establecer acuerdos y tomar decisiones.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '3. Interpreta mensajes verbales, textos icónicos e íconoverbales propios de su entorno sociocultural.', ARRAY['3.1. Establece la diferencia entre los diversos tipos de mensajes: visuales, auditivos, icónicos, entre otros.', '3.2. Interpreta la información explícita e infiere la información implícita presente en textos que presentan imagen y escritura.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '4. Aplica diferentes estrategias de lectura para obtener información y como recreación.', ARRAY['4.1. Interpreta, por medio de la lectura silenciosa, el significado de textos escritos y visuales.', '4.2. Aplica diferentes estrategias en la comprensión de textos informativos y literarios.', '4.3. Interpreta, por medio de la lectura oral y silenciosa, el significado de textos literarios e informativos.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '5. Produce textos informativos y con intención literaria de acuerdo con la estructura externa (forma) e interna (contenido).', ARRAY['5.1. Identifica el formato e intencionalidad de textos informativos.', '5.2. Redacta textos funcionales e informativos atendiendo los elementos que caracterizan la estructura externa de los mismos.', '5.3. Redacta textos narrativos y poéticos atendiendo los elementos que caracterizan la estructura externa de los mismos.', '5.4. Utiliza estructuras lingüísticas en la producción de diferentes tipos de texto.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '6. Utiliza estrategias para enriquecer su vocabulario básico.', ARRAY['6.1. Utiliza diversos significados de las palabras teniendo en cuenta la relación entre la estructura del idioma y el contexto sociocultural.', '6.2. Interpreta variaciones lingüísticas propias de su comunidad.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '7. Utiliza la normativa del idioma para el logro de una comunicación escrita eficaz.', ARRAY['7.1. Aplica, en los textos escritos, los elementos normativos emanados del estudio de los sonidos y de las palabras.', '7.2. Redacta oraciones de acuerdo a la normativa del idioma.', '7.3. Integra los aspectos formales de la lengua escrita, en los textos que produce.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 1', '8. Organiza la información de acuerdo con las características estructurales, formales y de contenido de diferentes tipos de texto.', ARRAY['8.1. Organiza la información obtenida de diversas fuentes escritas.', '8.2. Utiliza tecnología de uso frecuente en el ambiente para obtener información.', '8.3. Utiliza diversos esquemas gráficos y modelos en la integración de información.']),

-- Quinto Grado
('Quinto Grado', 'Comunicación y Lenguaje L 1', '1. Interpreta diferentes tipos de mensajes orales que le orientan en la realización de un trabajo.', ARRAY['1.1. Identifica las palabras, en el lenguaje oral, que indican la secuencia a seguir en la realización de tareas.', '1.2. Selecciona términos que indican direccionalidad en el movimiento y que le facilitan la realización de tareas específicas.', '1.3. Determina los detalles importantes de la información transmitida oralmente y por medios de comunicación masiva para la organización de su trabajo.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '2. Utiliza el lenguaje oral en el intercambio de ideas, información y opiniones.', ARRAY['2.1. Participa en distintas situaciones comunicativas expresando sus ideas con claridad y seguridad.', '2.2. Utiliza diferentes medios de comunicación para informar y expresar sus opiniones.', '2.3. Aplica las normas de cortesía en las diferentes modalidades de intercambio de información.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '3. Produce mensajes verbales, no verbales, icónicos e ícono-verbales como apoyo a las actividades planeadas en los proyectos de aprendizaje.', ARRAY['3.1. Utiliza la información explícita e implícita que transmiten textos icónicos e ícono-verbales.', '3.2. Utiliza en su comunicación información por medio de signos y símbolos propios de su comunidad o región.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '4. Lee textos y, con base en la estructura, el contenido y la finalidad de los diferentes tipos, selecciona los materiales que responden a sus necesidades.', ARRAY['4.1. Lee textos y utiliza la estructura de los diferentes tipos de texto en la selección de información pertinente.', '4.2. Reformula el contenido de los materiales leídos para seleccionar los que responden a sus necesidades.', '4.3. Evalúa la información seleccionada en función del trabajo que necesita realizar.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '5. Produce textos informativos y con intención literaria de acuerdo con aspectos normativos y contenidos propios de la escritura de los idiomas.', ARRAY['5.1. Incluye, en su producción escrita, diferentes tipos de texto atendiendo a su estructura externa.', '5.2. Incluye en los textos que escribe elementos que señalan matices semánticos.', '5.3. Integra en los textos poéticos los rasgos propios del lenguaje figurado (asociaciones e identificaciones).']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '6. Utiliza el vocabulario adecuado en los diferentes tipos de lenguaje de acuerdo con las distintas culturas.', ARRAY['6.1. Utiliza el vocabulario específico atendiendo a la situación comunicativa y a la audiencia.', '6.2. Elabora textos atendiendo a la relación de significado entre las palabras.', '6.3. Utiliza, en eventos comunicativos, variaciones lingüísticas propias de su comunidad.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '7. Utiliza las estructuras básicas y los elementos normativos del idioma materno en la comunicación oral y escrita.', ARRAY['7.1. Utiliza las diferentes categorías de palabras para ampliar el significado de su expresión oral y escrita.', '7.2. Utiliza palabras que funcionan como nexos y conectores en la redacción de textos breves.', '7.3. Integra la normativa del idioma en la producción de textos orales y escritos.']),
('Quinto Grado', 'Comunicación y Lenguaje L 1', '8. Utiliza estrategias que le permiten organizar la información esencial de fuentes escritas y tecnológicas.', ARRAY['8.1. Localiza la información pertinente en diversas fuentes escritas y audiovisuales.']),

-- Sexto Grado
('Sexto Grado', 'Comunicación y Lenguaje L 1', '1. Evalúa con actitud crítica la intencionalidad del mensaje: expositiva, argumentativa o normativa.', ARRAY['1.1. Identifica si el mensaje oral lleva una intención expositiva.', '1.2. Identifica si la intencionalidad del mensaje es argumentar sobre algún hecho o evento.', '1.3. Identifica si la intención del mensaje oral es establecer normas.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '2. Argumenta en situaciones de comunicación oral utilizando un lenguaje adecuado a los interlocutores, al contenido y al contexto.', ARRAY['2.1. Expresa oralmente sus argumentos manteniéndose fiel a los temas tratados.', '2.2. Utiliza diferentes técnicas de comunicación oral en exposiciones de carácter argumentativo.', '2.3. Participa voluntariamente en eventos de libre expresión demostrando respeto por las personas con quienes interactúa.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '3. Interpreta información transmitida por sistemas de comunicación verbal y no verbal y los procedimientos de persuasión y disuasión utilizados por los medios de comunicación masiva.', ARRAY['3.1. Interpreta los mensajes que se transmiten por los medios de comunicación y los compara con eventos de la vida cotidiana.', '3.2. Interpreta los símbolos y códigos cartográficos y de otra naturaleza utilizados frecuentemente en su comunidad y en el país.', '3.3. Interpreta la información explícita e implícita que transmiten los textos icónicos e ícono-verbales.', '3.4. Utiliza recursos tecnológicos para ampliar la información generada por medios de comunicación masiva.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '4. Lee con sentido crítico identificando ideas y datos importantes que le permiten comunicarse de manera funcional e informarse, ampliar y profundizar sus conocimientos.', ARRAY['4.1. Aplica destrezas de lectura silenciosa al leer materiales en la adquisición de nuevos conocimientos.', '4.2. Aplica las destrezas de lectura que le permiten utilizar eficientemente la información necesaria.', '4.3. Determina la veracidad, relevancia y utilidad de la información según el tema que necesita abordar.', '4.4. Aplica destrezas de lectura para interpretar la información contenida en documentos legales.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '5. Produce textos de diversos géneros, como medio de expresión, adaptados a requerimientos personales, escolares y socioculturales.', ARRAY['5.1. Identifica textos de diferentes géneros según su estructura externa.', '5.2. Incluye, en los textos que escribe, elementos que señalan matices semánticos.', '5.3. Integra en los textos que escribe, los rasgos propios del lenguaje figurado.', '5.4. Coopera en la generación grupal de textos recopilatorios propios de la tradición de su Pueblo o nación.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '6. Aplica vocabulario amplio en diferentes situaciones comunicativas individuales y grupales.', ARRAY['6.1. Utiliza el vocabulario específico atendiendo a la situación comunicativa y a la audiencia.', '6.2. Elabora textos en su lengua materna atendiendo a diferentes intenciones y contextos comunicativos.', '6.3. Utiliza variaciones lingüísticas propias de su comunidad.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '7. Expresa intenciones concretas de comunicación utilizando elementos normativos del lenguaje escrito.', ARRAY['7.1. Utiliza las diferentes categorías de palabras para ampliar el significado de su expresión oral y escrita.', '7.2. Integra los aspectos lexicales y gramaticales del idioma en la producción de textos orales y escritos.', '7.3. Aplica un proceso de revisión sistemática a los textos que produce para facilitar su comprensión.']),
('Sexto Grado', 'Comunicación y Lenguaje L 1', '8. Elabora textos de apoyo integrando datos obtenidos en las fuentes de información para la realización de actividades y tareas de aprendizaje.', ARRAY['8.1. Identifica las fuentes de información pertinentes en el proceso de elaboración de diferentes tareas.', '8.2. Aplica estrategias de investigación en la recolección de la información necesaria para la elaboración de diferentes tareas.', '8.3. Utiliza los recursos tecnológicos apropiados para apoyar la presentación de las tareas.']);

-- ===== cnb_primaria_5.sql =====
-- CNB Primaria - Comunicación y Lenguaje L 2 (segunda lengua) - Primero a Sexto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Comunicación_y_Lenguaje_L_2_-_{Grado}
-- Nivel de detalle: competencia + sub-competencias

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Primer Grado
('Primer Grado', 'Comunicación y Lenguaje L 2', '1. Responde con gestos, movimientos y oralmente a mensajes sencillos escuchados en la L 2.', ARRAY['1.1. Responde a preguntas y peticiones sencillas utilizando gestos y movimientos corporales.', '1.2. Identifica sonidos propios del idioma.', '1.3. Utiliza expresiones de cortesía al saludar en el aula y en la escuela.']),
('Primer Grado', 'Comunicación y Lenguaje L 2', '2. Identifica, visualmente, figuras, imágenes y palabras del vocabulario básico.', ARRAY['2.1. Asocia el nombre de objetos con las ilustraciones que los representan.', '2.2. Identifica los nombres de compañeras y compañeros, de familiares, de objetos personales y del aula cuando se presentan en forma escrita.', '2.3. Identifica signos y símbolos utilizados en la prevención de accidentes y desastres.']),
('Primer Grado', 'Comunicación y Lenguaje L 2', '3. Identifica fonemas, símbolos y grafías de la L 2 en diferentes contextos comunicativos.', ARRAY['3.1. Utiliza, en su comunicación oral y escrita, palabras y fonemas de la L 2 que son diferentes a los de la L 1.', '3.2. Forma familias de palabras partiendo de la raíz de palabras del vocabulario básico de la L 2.', '3.3. Valora los fonemas, símbolos y grafías de su L 1, L 2 y los de los otros idiomas de la comunidad.']),
('Primer Grado', 'Comunicación y Lenguaje L 2', '4. Utiliza la segunda lengua para comunicar oral y gráficamente ideas y sentimientos.', ARRAY['4.1. Utiliza los pronombres personales al comunicarse.', '4.2. Nombra animales, frutas y objetos de los distintos ambientes del hogar y del aula.', '4.3. Utiliza vocabulario básico relacionado con actividades cotidianas.']),

-- Segundo Grado
('Segundo Grado', 'Comunicación y Lenguaje L 2', '1. Utiliza el lenguaje verbal y no verbal en la expresión de sus ideas y emociones.', ARRAY['1.1. Utiliza gestos para precisar los mensajes que transmiten en una conversación.', '1.2. Utiliza información que obtiene de conversaciones.', '1.3. Intercambia, oralmente o por medio de gestos y movimientos, experiencias, gustos y sentimientos con otros y otras.']),
('Segundo Grado', 'Comunicación y Lenguaje L 2', '2. Utiliza la lectura de oraciones y relatos sencillos en la búsqueda de información o como recreación.', ARRAY['2.1. Identifica detalles importantes, secuencia de los eventos, sentimientos y emociones de los personajes en el material de lectura.', '2.2. Valora los mensajes expresados en las lecturas.', '2.3. Lee diferentes tipos de materiales de lectura.']),
('Segundo Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza conocimientos básicos del sistema fonológico propio de la L 2 en la comprensión y expresión de ideas.', ARRAY['3.1. Utiliza, en la lectura, patrones de entonación y ritmo propios de la L 2.', '3.2. Identifica y pronuncia con claridad palabras con fonemas de la L 2.', '3.3. Interpreta el significado de signos, íconos y señales.']),
('Segundo Grado', 'Comunicación y Lenguaje L 2', '4. Redacta textos cortos siguiendo las normas de la L 2.', ARRAY['4.1. Identifica la estructura básica de la oración y de los párrafos.', '4.2. Describe los diferentes tipos de palabras que conforman la oración en la L 2.', '4.3. Redacta oraciones cortas con mensajes claros.']),

-- Tercer Grado
('Tercer Grado', 'Comunicación y Lenguaje L 2', '1. Utiliza la L 2 en forma verbal y no verbal al establecer comunicación con otros y otras.', ARRAY['1.1. Interpreta gestos, posturas e imágenes utilizadas en la comunicación oral.', '1.2. Interpreta el contenido de poemas, historias, cuentos, canciones y retahílas.', '1.3. Expresa oralmente sus ideas en forma ordenada y coherente.']),
('Tercer Grado', 'Comunicación y Lenguaje L 2', '2. Lee, con diferentes propósitos, materiales de lectura del contexto cultural de la L 2.', ARRAY['2.1. Interpreta mensajes de rótulos, carteles y señalizaciones frecuentemente utilizados en la escuela y en la comunidad.', '2.2. Utiliza patrones de entonación y ritmo propios de la L 2 en la lectura oral.', '2.3. Identifica los detalles importantes en el material de lectura.', '2.4. Establece la secuencia de los eventos y la relación de causa y efecto de los mismos.']),
('Tercer Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza con propiedad los conocimientos básicos de los sistemas fonológico y ortográfico propios de la L 2.', ARRAY['3.1. Utiliza palabras con fonemas propios de la L 2 en sus expresiones orales.', '3.2. Utiliza patrones de acentuación y ritmo propios de la L 2.', '3.3. Aplica la ortografía básica de la L 2 al expresarse por escrito.']),
('Tercer Grado', 'Comunicación y Lenguaje L 2', '4. Expresa ideas, sentimientos y emociones en forma oral y escrita basándose en las normas de la L 2.', ARRAY['4.1. Formula oraciones estableciendo concordancia entre sujeto y predicado.', '4.2. Utiliza adecuadamente los momentos verbales en su comunicación.', '4.3. Utiliza palabras que califican y modifican al sustantivo.']),
('Tercer Grado', 'Comunicación y Lenguaje L 2', '5. Presenta resúmenes escritos siguiendo las reglas gramaticales básicas de la L 2.', ARRAY['5.1. Resume el contenido de textos orales y escritos.', '5.2. Elabora informes utilizando fichas y esquemas.', '5.3. Expone en forma ordenada y comprensible eventos y procesos utilizando fichas y esquemas informativos.']),

-- Cuarto Grado
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '1. Utiliza el lenguaje oral en la expresión de ideas, emociones y sentimientos y en la interpretación del mensaje recibido.', ARRAY['1.1. Demuestra comprensión de los mensajes que escucha.', '1.2. Identifica diferentes tipos de mensajes orales y escritos.', '1.3. Organiza la información pertinente para responder a los mensajes recibidos.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '2. Utiliza el lenguaje no verbal como apoyo en la expresión de ideas, emociones y sentimientos.', ARRAY['2.1. Utiliza gestos y movimientos corporales como apoyo en la comunicación.', '2.2. Utiliza otras modalidades del lenguaje no verbal como apoyo en la comunicación.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza la lectura de palabras, oraciones, párrafos, e historias para obtener y organizar información.', ARRAY['3.1. Lee, con fluidez, oraciones, párrafos e historias cortas en la L 2.', '3.2. Utiliza palabras de diferentes áreas de contenido demostrando comprensión de los conceptos que representan.', '3.3. Utiliza el orden alfabético para buscar y organizar información.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '4. Aplica, en su expresión oral y escrita, elementos básicos de la estructura de la palabra y de la oración.', ARRAY['4.1. Identifica, en palabras del vocabulario básico, los patrones de acentuación propios de la L 2.', '4.2. Identifica el elemento común a todos los vocablos que forman una familia de palabras y los elementos que determinan la diferencia entre una y otra.', '4.3. Utiliza los elementos que constituyen la estructura de una oración.', '4.4. Aplica la gramática de la L 2 en la expresión de sus ideas.', '4.5. Utiliza apropiadamente el vocabulario básico de la segunda lengua.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 2', '5. Utiliza diferentes estrategias para adquirir y producir información, oralmente y por escrito, en la L 2.', ARRAY['5.1. Aplica diferentes estrategias para obtener información.', '5.2. Utiliza diferentes estrategias para organizar la información.', '5.3. Utiliza diferentes recursos para comunicar oralmente sus ideas.']),

-- Quinto Grado
('Quinto Grado', 'Comunicación y Lenguaje L 2', '1. Interpreta, con sentido crítico, mensajes de distinta índole utilizando el lenguaje oral.', ARRAY['1.1. Demuestra comprensión en situaciones de comunicación en las que se utiliza el lenguaje oral.', '1.2. Emite juicios con respecto a los mensajes recibidos.']),
('Quinto Grado', 'Comunicación y Lenguaje L 2', '2. Interpreta representaciones de situaciones reales o imaginarias, utilizando gestos, miradas, movimientos corporales y desplazamientos en la emisión de su respuesta.', ARRAY['2.1. Utiliza gestos y movimientos corporales para reforzar el significado de expresiones del lenguaje cotidiano.', '2.2. Asocia imágenes, señales, signos, símbolos y figuras con el mensaje que comunica.']),
('Quinto Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza la lectura como medio para formar criterios, adquirir información y construir nuevos conocimientos.', ARRAY['3.1. Interpreta mensajes en textos recreativos.', '3.2. Identifica detalles importantes en textos informativos.', '3.3. Utiliza diferentes textos como apoyo para fundamentar la información con respecto a diferentes temas.']),
('Quinto Grado', 'Comunicación y Lenguaje L 2', '4. Aplica diferentes estrategias para derivar el significado de palabras desconocidas y su relación con la estructura de la oración, según la normativa de la L 2.', ARRAY['4.1. Utiliza el contexto para inferir el significado de palabras desconocidas.', '4.2. Utiliza el análisis fonológico para leer palabras desconocidas.', '4.3. Utiliza la estructura de las palabras para leer palabras desconocidas.', '4.4. Describe las palabras que constituyen parte de la estructura de la oración.', '4.5. Identifica los elementos que determinan la concordancia entre los diferentes elementos de la oración.']),
('Quinto Grado', 'Comunicación y Lenguaje L 2', '5. Utiliza las técnicas apropiadas en la redacción de textos narrativos e informativos.', ARRAY['5.1. Organiza la información que recaba durante actividades de observación.', '5.2. Elabora textos narrativos e informativos.', '5.3. Elabora textos de carácter epistolar.']),

-- Sexto Grado
('Sexto Grado', 'Comunicación y Lenguaje L 2', '1. Utiliza el lenguaje oral como medio de comunicación al discutir temas de interés personal y colectivo.', ARRAY['1.1. Argumenta sus opiniones con respecto a la información recibida.', '1.2. Participa en actividades de intercambio de información.', '1.3. Aplica normas de cortesía en las diferentes instancias en las que se da el intercambio de información.']),
('Sexto Grado', 'Comunicación y Lenguaje L 2', '2. Utiliza el lenguaje verbal y no verbal para responder a mensajes en situaciones de la vida cotidiana.', ARRAY['2.1. Infiere el significado de mensajes que se apoyan en el lenguaje no verbal.', '2.2. Asocia gestos, movimientos y desplazamientos con el mensaje que comunican.']),
('Sexto Grado', 'Comunicación y Lenguaje L 2', '3. Utiliza diferentes tipos de lectura en la documentación de sus juicios y opiniones.', ARRAY['3.1. Utiliza diferentes fuentes de información al elaborar sus argumentos.', '3.2. Utiliza diferentes estrategias lectoras para ubicar la información pertinente.', '3.3. Emite juicios críticos con respecto a lo expresado en las diferentes obras de referencia.']),
('Sexto Grado', 'Comunicación y Lenguaje L 2', '4. Aplica conocimientos de morfología, semántica y sintaxis de la L 2 en su expresión oral y escrita.', ARRAY['4.1. Aplica las reglas de pronunciación y acentuación, según la normativa de la L 2.', '4.2. Utiliza el conocimiento sobre la estructura de las palabras en la elaboración de textos escritos.', '4.3. Elabora párrafos utilizando la acentuación ortográfica y los signos de puntuación según la normativa de la L 2.']),
('Sexto Grado', 'Comunicación y Lenguaje L 2', '5. Aplica, en su expresión oral y escrita, los elementos que inciden en la corrección del lenguaje según la normativa de la L 2.', ARRAY['5.1. Utiliza, en la expresión de sus ideas, los diferentes tipos de palabras según la normativa de la L 2.', '5.2. Redacta textos narrativos de acuerdo con los requerimientos del momento y según la normativa de la L 2.', '5.3. Redacta textos poéticos de acuerdo con los requerimientos del momento y según la normativa de la L 2.', '5.4. Establece la diferencia entre textos poéticos y otros tipos de texto.']);

-- ===== cnb_primaria_6.sql =====
-- CNB Primaria - Matemáticas - Primer y Segundo Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Matemáticas_-_{Grado}
-- Nivel de detalle: competencia + sub-competencias

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Primer Grado
('Primer Grado', 'Matemáticas', '1. Establece relaciones entre personas, objetos y figuras geométricas por su posición en el espacio y por la distancia que hay entre ellos y ellas.', ARRAY['1.2. Establece relaciones entre personas, figuras, objetos, hechos, acontecimientos por su posición en el espacio y distancia entre ellos.', '1.3. Traza diferentes tipos de líneas utilizando diferentes tecnologías.', '1.4. Asocia figuras geométricas con la forma de cosas y lugares de su entorno.']),
('Primer Grado', 'Matemáticas', '2. Expresa ideas referidas a patrones y relaciones matemáticas que se dan en las manifestaciones culturales en su entorno familiar.', ARRAY['2.1. Dibuja patrones observados en la naturaleza.', '2.2. Describe patrones observados en actividades culturales tradicionales de la comunidad.', '2.3. Elabora trabajos que reproduzcan los patrones observados en las diferentes manifestaciones culturales.']),
('Primer Grado', 'Matemáticas', '3. Expresa ideas y pensamientos con libertad y coherencia utilizando diferentes signos, símbolos gráficos, algoritmos y términos matemáticos.', ARRAY['3.1. Identifica elementos de un conjunto determinado.', '3.3. Establece correspondencia uno a uno entre los elementos de 2 o 3 conjuntos.']),
('Primer Grado', 'Matemáticas', '4. Utiliza conocimientos y experiencias de aritmética básica en la interacción con su entorno familiar.', ARRAY['4.1. Cuenta objetos de su entorno y expresa las cantidades con un número en sistema decimal.', '4.8. Efectúa sumas y restas de números naturales.', '4.9. Compara una parte con la unidad.']),
('Primer Grado', 'Matemáticas', '5. Expresa opiniones sobre hechos y eventos de la vida cotidiana, relacionados con la solución de problemas.', ARRAY['5.1. Sigue reglas e instrucciones en juegos que realiza.', '5.2. Clasifica datos en forma cualitativa y cuantitativa.', '5.3. Describe diferentes soluciones para problemas.', '5.4. Describe cuantitativamente detalles importantes de eventos y sucesos.']),
('Primer Grado', 'Matemáticas', '6. Identifica formas y relaciones de figuras geométricas vinculadas a situaciones matemáticas y a su entorno familiar.', ARRAY['6.1. Establece semejanzas y diferencias entre diversas figuras y sólidos geométricos.', '6.2. Utiliza medidas no estándar para mostrar el perímetro de figuras geométricas básicas.']),
('Primer Grado', 'Matemáticas', '7. Construye nuevos conocimientos a partir de nuevos modelos de la ciencia y la cultura.', ARRAY['7.1. Utiliza diferentes tipos de unidades para medir el peso, longitud y capacidad de los objetos.', '7.2. Describe la duración de eventos cotidianos (horas, días).', '7.3. Organiza sus actividades cotidianas según los diferentes calendarios.', '7.4. Utiliza la unidad monetaria en situaciones de compra-venta.']),

-- Segundo Grado
('Segundo Grado', 'Matemáticas', '1. Construye patrones clasificando los elementos y determinando relaciones y distancias entre cada uno de ellos.', ARRAY['1.1. Establece diferencias en los patrones que se encuentran en la naturaleza y en las actividades cotidianas o culturales.']),
('Segundo Grado', 'Matemáticas', '2. Relaciona ideas y pensamientos referidos a diferentes signos y gráficas, algoritmos y términos matemáticos de su entorno familiar, escolar y cultural.', ARRAY['2.1. Establece relación entre elementos por la distancia, posición y tiempo.', '2.2. Utiliza el primer cuadrante del plano cartesiano para localizar puntos y mostrar el desplazamiento de dibujos.']),
('Segundo Grado', 'Matemáticas', '3. Relaciona ideas y pensamientos con libertad y coherencia utilizando diferentes signos, símbolos gráficos, algoritmos y términos matemáticos.', ARRAY['3.1. Establece relación de pertenencia o no pertenencia entre elementos y un conjunto determinado.', '3.2. Identifica características comunes de elementos de un conjunto para la formación de subconjuntos.', '3.3. Clasifica conjuntos que se encuentran en su entorno.']),
('Segundo Grado', 'Matemáticas', '4. Utiliza conocimientos y experiencias de aritmética básica en la interacción con su entorno familiar, escolar y comunitario.', ARRAY['4.1. Describe situaciones cotidianas en forma cuantitativa y las expresa con numerales mayas.', '4.2. Asocia los números ordinales con la posición que ocupa un elemento en una serie ordenada de hasta 20 elementos.', '4.3. Describe situaciones cotidianas en forma cuantitativa y las expresa con numerales arábigos (0-1,000).', '4.4. Distingue el valor relativo de un número en cantidades hasta de 3 dígitos.', '4.5. Completa y crea series numéricas de 2 en 2, de 3 en 3, de 4 en 4, de 5 en 5, de 10 en 10 y de 100 en 100.', '4.6. Asocia numerales con puntos de la recta numérica.', '4.7. Efectúa sumas con cantidades hasta 2 dígitos.', '4.8. Efectúa restas con minuendos hasta de 3 dígitos.', '4.9. Efectúa multiplicaciones de números menores o iguales a 9.', '4.10. Utiliza fracciones para representar partes iguales de una unidad.']),
('Segundo Grado', 'Matemáticas', '5. Emite juicios identificando causas y efectos para la solución de problemas en la vida cotidiana.', ARRAY['5.1. Propone diferentes soluciones para un problema.', '5.2. Aplica diferentes estrategias para la solución de problemas.', '5.3. Aplica el razonamiento lógico en la realización de juegos.', '5.4. Describe cuantitativamente detalles importantes de eventos y sucesos.']),
('Segundo Grado', 'Matemáticas', '6. Relaciona figuras geométricas con situaciones matemáticas y con su entorno familiar y escolar.', ARRAY['6.1. Describe figuras y sólidos geométricos por las características de los elementos que la forman.', '6.2. Calcula perímetro de figuras geométricas planas (triángulo, cuadrado y rectángulo).', '6.3. Utiliza diferentes líneas rectas para realizar dibujos.', '6.4. Identifica modelos geométricos.', '6.5. Identifica figuras simétricas.']),
('Segundo Grado', 'Matemáticas', '7. Utiliza nuevos conocimientos a partir de nuevos modelos de la ciencia y la cultura.', ARRAY['7.1. Utiliza diferentes unidades de medida para establecer peso.', '7.2. Utiliza diferentes unidades de medida para establecer longitud.', '7.3. Utiliza diferentes unidades de medida para establecer capacidad.', '7.4. Utiliza diferentes unidades de medida para describir el momento en que ocurre un evento o suceso.', '7.6. Utiliza la unidad monetaria como medida de valoración de bienes materiales.']);

-- ===== cnb_primaria_7.sql =====
-- CNB Primaria - Matemáticas - Tercer y Cuarto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Matemáticas_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Tercer Grado
('Tercer Grado', 'Matemáticas', '1. Construye patrones y establece relaciones que le facilitan la interpretación de signos y señales utilizados para el desplazamiento en su comunidad y otros contextos.', ARRAY['1.1. Elabora instrucciones para orientar a compañeros y compañeras en la realización de juegos que impliquen seguimiento de patrones o desplazamientos.', '1.2. Descubre la secuencia numérica de patrones existentes en la naturaleza o en su entorno cultural.', '1.3. Interpreta las operaciones aritméticas implícitas en patrones.', '1.4. Identifica la relación causa-efecto en patrones presentes en el entorno natural, social o cultural.', '1.5. Elabora y describe patrones.']),
('Tercer Grado', 'Matemáticas', '2. Utiliza diferentes estrategias para representar los algoritmos y términos matemáticos en su entorno cultural, familiar, escolar y comunitario.', ARRAY['2.2. Utiliza el primer cuadrante del plano cartesiano para mostrar desplazamientos.']),
('Tercer Grado', 'Matemáticas', '3. Propone diferentes ideas y pensamientos con libertad y coherencia utilizando diferentes signos, símbolos gráficos, algoritmos y términos matemáticos.', ARRAY['3.1. Identifica diferentes tipos de conjuntos.', '3.2. Diferencia conjuntos iguales de equivalentes.', '3.3. Establece la diferencia entre la unión y la intersección de conjuntos.']),
('Tercer Grado', 'Matemáticas', '4. Aplica conocimientos y experiencias de aritmética básica en la interacción con su entorno familiar, escolar y comunitario.', ARRAY['4.1. Utiliza los números naturales en sistema decimal del 0 al 10,000 y en Sistema Vigesimal Maya hasta 7,999.', '4.3. Efectúa multiplicaciones y divisiones de números naturales menores que 100.', '4.4. Utiliza hasta dos fracciones para representar partes iguales de una unidad.']),
('Tercer Grado', 'Matemáticas', '5. Aplica conocimientos matemáticos en la sistematización de soluciones diversas a problemas de la vida cotidiana.', ARRAY['5.1. Recoge y ordena información.', '5.2. Aplica diferentes operaciones y estrategias en la solución de problemas.', '5.3. Predice eventos, sucesos y problemas.']),
('Tercer Grado', 'Matemáticas', '6. Utiliza la información que obtiene de las relaciones de diferentes elementos expresándolas en forma gráfica.', ARRAY['6.1. Explora elementos de figuras geométricas planas y sólidos geométricos.', '6.2. Calcula el perímetro de un triángulo y un cuadrilátero, de un cuadrado y un rectángulo.', '6.3. Identifica ejes de simetría en figuras geométricas planas y objetos.']),
('Tercer Grado', 'Matemáticas', '7. Aplica nuevos conocimientos a partir de nuevos modelos de la ciencia y la cultura.', ARRAY['7.1. Utiliza diferentes unidades de medida para establecer longitud.', '7.3. Utiliza diferentes unidades de medida para establecer capacidad.', '7.4. Utiliza otras unidades de medida propias de la región.', '7.5. Resuelve problemas que involucren el concepto de unidad monetaria nacional.', '7.6. Calcula el tiempo de duración de diferentes actividades que se realizan en la vida cotidiana.']),

-- Cuarto Grado
('Cuarto Grado', 'Matemáticas', '1. Relaciona formas, figuras geométricas, símbolos, signos y señales con diferentes objetos y fenómenos que acontecen en el contexto natural, social y cultural de su comunidad.', ARRAY['1.1. Clasifica y mide ángulos.', '1.2. Descubre el paralelismo y la perpendicularidad en diferentes objetos que observa en el aula y fuera de ella.', '1.3. Clasifica triángulos por la longitud de sus lados.', '1.4. Clasifica cuadriláteros por la relación de paralelismo o perpendicularidad entre sus lados opuestos y contiguos.', '1.5. Calcula perímetro de triángulos y cuadriláteros.', '1.6. Clasifica sólidos geométricos.', '1.8. Utiliza el primer cuadrante del plano cartesiano para ubicar puntos.', '1.9. Interpreta señales utilizadas en su cultura para el desplazamiento.']),
('Cuarto Grado', 'Matemáticas', '2. Utiliza el pensamiento lógico reflexivo, crítico y creativo para buscar respuesta a situaciones problemáticas de la vida escolar, familiar y comunitaria.', ARRAY['2.1. Descubre patrones geométricos o numéricos.']),
('Cuarto Grado', 'Matemáticas', '3. Utiliza signos, símbolos gráficos, algoritmos y términos matemáticos que le permiten manifestar ideas y pensamientos.', ARRAY['3.1. Utiliza diferentes representaciones para nombrar un conjunto.']),
('Cuarto Grado', 'Matemáticas', '4. Identifica elementos matemáticos que contribuyen al rescate, protección y conservación de su medio social, natural y cultural.', ARRAY['4.1. Utiliza los números naturales en el sistema decimal hasta 100,000, en el sistema vigesimal maya hasta la cuarta posición y en números romanos hasta cien.', '4.2. Determina los números pares e impares como subconjunto de los números naturales.', '4.3. Realiza cálculos de adición y sustracción en el conjunto de los números naturales, en un ámbito hasta 100,000.', '4.4. Realiza cálculos de multiplicación y división en el conjunto de los números naturales, en un ámbito hasta 100,000.', '4.5. Relaciona la multiplicación con la potenciación.', '4.6. Efectúa divisiones con divisor de dos dígitos.', '4.7. Resuelve problemas con operaciones de adición, sustracción, multiplicación o división.', '4.8. Efectúa sumas y restas con numeración maya.', '4.9. Utiliza los decimales para representar cantidades y calcular sumas y restas.', '4.10. Efectúa sumas y restas de fracciones.', '4.11. Utiliza las proporciones para resolver problemas.']),
('Cuarto Grado', 'Matemáticas', '5. Organiza en forma lógica procesos de distintas materias básicas en la solución de problemas de la vida cotidiana.', ARRAY['5.1. Utiliza operaciones con naturales y fracciones para la solución de problemas.', '5.2. Resuelve problemas que tienen varias o ninguna solución.', '5.3. Predice eventos, sucesos y problemas.']),
('Cuarto Grado', 'Matemáticas', '6. Expresa en forma gráfica y descriptiva la información que obtiene relacionada con diversos elementos y acontecimientos de su contexto social, cultural y natural.', ARRAY['6.1. Establece relación de dependencia entre dos eventos o sucesos.', '6.2. Registra información cuantitativa de hechos o sucesos de su comunidad.', '6.3. Representa gráficamente información recopilada.', '6.4. Interpreta información presentada por medio de tablas y gráficas estadísticas.']),
('Cuarto Grado', 'Matemáticas', '7. Establece relaciones entre los conocimientos y tecnologías, propias de su cultura y las de otras culturas.', ARRAY['7.1. Utiliza diferentes unidades de medida para calcular longitud.', '7.2. Reproduce dibujos a escala.', '7.3. Utiliza diferentes unidades para establecer peso, capacidad y temperatura.', '7.4. Calcula el tiempo de duración de diferentes actividades que se realizan en la vida cotidiana utilizando la hora, minuto y segundo.', '7.6. Utiliza las monedas en diferentes actividades.', '7.7. Resuelve problemas que involucren el uso de la moneda nacional y operaciones de suma, resta, multiplicación y división.']);

-- ===== cnb_primaria_8.sql =====
-- CNB Primaria - Matemáticas - Quinto y Sexto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Matemáticas_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Quinto Grado
('Quinto Grado', 'Matemáticas', '1. Utiliza formas geométricas, símbolos, signos y señales para el desarrollo de sus actividades cotidianas.', ARRAY['1.1. Establece relación entre lados y ángulos de triángulos y cuadriláteros.', '1.2. Explica la relación que existe entre las figuras planas y sólidos geométricos: prismas (incluye cubo), pirámides, cilindro y cono.', '1.3. Identifica el círculo y sus partes.', '1.4. Calcula el perímetro de diferentes figuras planas y el área de un cuadrado, rectángulo y triángulo.', '1.5. Construye figuras con simetría.', '1.6. Utiliza el primer cuadrante del plano cartesiano para ubicar puntos y realizar dibujos.']),
('Quinto Grado', 'Matemáticas', '2. Aplica el pensamiento lógico, reflexivo, crítico y creativo en la solución de diferentes situaciones problemáticas de su contexto inmediato.', ARRAY['2.1. Construye mosaicos o diseños siguiendo patrones determinados.']),
('Quinto Grado', 'Matemáticas', '3. Organiza los signos, símbolos gráficos, algoritmos y términos matemáticos que le permiten ofrecer diferentes soluciones a situaciones y problemas del medio en que se desenvuelve.', ARRAY['3.1. Representa subconjuntos del conjunto de los números naturales.', '3.2. Realiza operaciones de unión, intersección y diferencia entre conjuntos.']),
('Quinto Grado', 'Matemáticas', '4. Utiliza los conocimientos y experiencias matemáticas para el cuidado preventivo del medio natural, así como su enriquecimiento cultural.', ARRAY['4.1. Utiliza los números naturales en sistema decimal hasta 999,999, en el sistema Vigesimal Maya hasta la quinta posición y los números romanos hasta 500.', '4.2. Efectúa cálculos de suma, resta, multiplicación y división en el conjunto de los números naturales y racionales.', '4.3. Efectúa cálculos de suma, resta y multiplicación con numeración Maya.', '4.4. Realiza suma y resta con potenciación y radicación en el conjunto de los números naturales.', '4.7. Utiliza las fracciones y mixtos para representar cantidades y calcular sumas, restas, multiplicaciones y divisiones.', '4.8. Utiliza proporciones para resolver problemas.']),
('Quinto Grado', 'Matemáticas', '5. Utiliza estrategias propias de aritmética básica que le orientan a la solución de problemas de la vida cotidiana.', ARRAY['5.1. Aplica suma, resta, multiplicación y división en la solución de problemas.', '5.2. Utiliza las proporciones y la regla de tres simple para la solución de problemas.']),
('Quinto Grado', 'Matemáticas', '6. Expresa, en forma gráfica y descriptiva, la información que obtiene en relación con diversos elementos y acontecimientos que observa en su contexto social, cultural y natural.', ARRAY['6.1. Predice eventos y sucesos.', '6.2. Utiliza gráficas de barra y gráfica circular para representar información recopilada.', '6.3. Calcula e interpreta el promedio aritmético.']),
('Quinto Grado', 'Matemáticas', '7. Utiliza los conocimientos y las tecnologías propias de su cultura y las de otras culturas para resolver problemas de su entorno inmediato.', ARRAY['7.1. Utiliza diferentes unidades de medida para establecer longitud (del sistema métrico e inglés).', '7.2. Utiliza diferentes unidades de medida para establecer peso (del sistema métrico e inglés).', '7.3. Utiliza diferentes unidades de medida para establecer volumen, capacidad y temperatura.', '7.4. Utiliza diferentes unidades de tiempo para referirse a eventos o sucesos.', '7.5. Describe las características del calendario Maya agrícola o Ab y religioso.', '7.6. Lleva la cuenta larga para diferentes fechas.', '7.7. Resuelve problemas que involucren el uso de la moneda nacional y extranjeras.']),

-- Sexto Grado
('Sexto Grado', 'Matemáticas', '1. Produce información acerca de la utilización de figuras geométricas, símbolos, signos y señales de fenómenos naturales, sociales y culturales en su región.', ARRAY['1.1. Identifica características de polígonos regulares e irregulares.', '1.2. Calcula perímetro y área de diferentes polígonos y del círculo.', '1.4. Calcula el área y volumen de sólidos geométricos.', '1.5. Utiliza el plano cartesiano.']),
('Sexto Grado', 'Matemáticas', '2. Aplica el pensamiento lógico, reflexivo, crítico y creativo para impulsar la búsqueda de solución a situaciones problemáticas en los diferentes ámbitos en los que se desenvuelve.', ARRAY['2.1. Construye series numéricas aplicando diferentes patrones.']),
('Sexto Grado', 'Matemáticas', '3. Aplica, con autonomía, signos, símbolos gráficos, algoritmos y términos matemáticos, para dar respuesta a diversas situaciones y problemas en los diferentes ámbitos en los que se desenvuelve.', ARRAY['3.1. Representa subconjuntos de un conjunto.', '3.2. Realiza operaciones entre conjuntos.', '3.3. Identifica los elementos del conjunto de números naturales, enteros y fraccionarios.']),
('Sexto Grado', 'Matemáticas', '4. Aplica elementos matemáticos en situaciones que promueven el mejoramiento y la transformación del medio natural, social y cultural en el que se desenvuelve.', ARRAY['4.1. Utiliza los números naturales enteros en el sistema de numeración decimal hasta 999,999,999 y en el sistema de numeración vigesimal Maya hasta la quinta posición y numeración romana hasta mil.', '4.3. Identifica relaciones entre números naturales.', '4.4. Realiza cálculos aritméticos de adición, sustracción, multiplicación, división con fracciones.', '4.5. Realiza cálculos aritméticos de adición, sustracción, multiplicación, división con decimales.', '4.6. Aplica propiedad de proporciones.']),
('Sexto Grado', 'Matemáticas', '5. Aplica estrategias de aritmética básica en la resolución de situaciones problemáticas de su vida cotidiana que contribuyen a mejorar su calidad de vida.', ARRAY['5.1. Resuelve problemas aplicando una o varias operaciones aritméticas.', '5.2. Utiliza la regla de tres simple y compuesta en la solución de problemas.']),
('Sexto Grado', 'Matemáticas', '6. Utiliza la información que obtiene de diferentes elementos y fenómenos que ocurren en su contexto social, cultural y natural y la expresa en forma gráfica y simbólica.', ARRAY['6.1. Clasifica información recopilada según variables cualitativas y cuantitativas y la expresa en porcentajes.', '6.2. Organiza información recopilada en tablas de frecuencias, gráficas de barras y circulares.', '6.3. Determina la diferencia entre el dato más bajo y el más alto (datos no agrupados).', '6.4. Calcula e interpreta el promedio aritmético, la mediana y la moda en un conjunto de datos no agrupados.']),
('Sexto Grado', 'Matemáticas', '7. Aplica los conocimientos y las tecnologías propias de la cultura y de otras culturas para impulsar el desarrollo personal, familiar y de su comunidad.', ARRAY['7.1. Identifica unidades de medida de longitud, peso y capacidad.', '7.2. Utiliza un termómetro para medir la temperatura del ambiente.', '7.3. Describe aplicaciones del calendario maya agrícola y sagrado.', '7.4. Establece equivalencia entre la moneda nacional y otras monedas.', '7.5. Resuelve problemas utilizando la moneda nacional y otras monedas de uso regional.']);

-- ===== cnb_primaria_9.sql =====
-- CNB Primaria - Comunicación y Lenguaje L 3 (idioma extranjero) - Primero, Segundo y Tercer Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Comunicación_y_Lenguaje_L_3_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Primer Grado
('Primer Grado', 'Comunicación y Lenguaje L 3', '1. Escucha activamente instrucciones básicas de su interlocutor.', ARRAY['1.1. Reconoce el cambio de expresiones de un idioma a otro.', '1.2. Sigue instrucciones con un evento.', '1.3. Realiza la acción de acuerdo con la orden recibida.']),
('Primer Grado', 'Comunicación y Lenguaje L 3', '2. Identifica sonidos diferentes al de su idioma en su relación familiar.', ARRAY['2.1. Reconoce los diferentes sonidos relacionados con las órdenes recibidas.', '2.2. Infiere el significado de las órdenes recibidas.']),
('Primer Grado', 'Comunicación y Lenguaje L 3', '3. Pronuncia correctamente órdenes básicas de uso cotidiano al dirigirse a otras personas.', ARRAY['3.1. Pronuncia adecuadamente la orden en proceso de realización.', '3.2. Reconoce la acentuación de las vocales y pronunciación de las consonantes en las órdenes recibidas.', '3.3. Asocia la pronunciación de las órdenes recibidas con la de otras similares.']),
('Primer Grado', 'Comunicación y Lenguaje L 3', '4. Utiliza el lenguaje verbal y no verbal como auxiliar de la comunicación.', ARRAY['4.1. Sigue instrucciones orales básicas.', '4.2. Infiere el significado de los movimientos corporales en la realización de una acción.']),
('Primer Grado', 'Comunicación y Lenguaje L 3', '5. Utiliza la lectura para responder a órdenes básicas recibidas.', ARRAY['5.1. Identifica órdenes expresadas de manera gráfica.']),

-- Segundo Grado
('Segundo Grado', 'Comunicación y Lenguaje L 3', '1. Escucha activamente instrucciones sencillas de su interlocutor identificando la acción requerida.', ARRAY['1.1. Sigue instrucciones orales sencillas.', '1.2. Asocia instrucciones orales con la acción requerida.', '1.3. Realiza la acción de manera correcta de acuerdo con la instrucción dada.', '1.4. Reacciona inmediatamente ante un mandato.']),
('Segundo Grado', 'Comunicación y Lenguaje L 3', '2. Identifica fonemas diferentes a los de su idioma en su relación con otros.', ARRAY['2.1. Diferencia entre los fonemas básicos de su idioma materno y los del idioma en estudio.', '2.2. Asocia órdenes con palabras que contienen fonemas similares.', '2.3. Formula y responde a preguntas con respuestas cortas utilizando palabras con sonidos similares.']),
('Segundo Grado', 'Comunicación y Lenguaje L 3', '3. Pronuncia expresiones básicas al comunicarse con otras personas.', ARRAY['3.1. Pronuncia expresiones básicas adecuadamente.', '3.2. Enuncia claramente las diferentes órdenes y expresiones cotidianas.', '3.3. Pronuncia palabras pares con sonidos similares.']),
('Segundo Grado', 'Comunicación y Lenguaje L 3', '4. Utiliza el lenguaje oral y escrito en expresiones sencillas como auxiliar de la comunicación.', ARRAY['4.1. Sigue instrucciones verbales para realizar dos acciones.', '4.2. Expresa sus preferencias de entre una serie de órdenes o instrucciones.', '4.3. Infiere el significado de los movimientos corporales acompañados de una expresión oral.']),
('Segundo Grado', 'Comunicación y Lenguaje L 3', '5. Utiliza la lectura para responder a expresiones sencillas.', ARRAY['5.1. Interpreta símbolos específicos propios del idioma en aprendizaje.', '5.2. Asocia imágenes con la grafía correspondiente.', '5.3. Realiza acciones de acuerdo con la imagen sugerida.']),

-- Tercer Grado
('Tercer Grado', 'Comunicación y Lenguaje L 3', '1. Escucha activamente instrucciones de su interlocutor demostrando seguridad al realizar una acción.', ARRAY['1.1. Responde con seguridad en seguimiento de instrucciones simples.', '1.2. Interpreta instrucciones en forma lúdica.', '1.3. Reacciona al escuchar nuevas órdenes.']),
('Tercer Grado', 'Comunicación y Lenguaje L 3', '2. Diferencia los fonemas básicos de su idioma de los del otro.', ARRAY['2.1. Compara los diferentes signos fonológicos básicos.', '2.2. Identifica palabras con fonemas similares a los de su idioma materno.', '2.3. Identifica la forma de colocación del apóstrofo en las palabras.']),
('Tercer Grado', 'Comunicación y Lenguaje L 3', '3. Pronuncia frases cotidianas con seguridad al dirigirse a otras personas.', ARRAY['3.1. Responde pronunciando adecuadamente expresiones cotidianas.', '3.2. Identifica familias de palabras con similar pronunciación.', '3.3. Reproduce espontáneamente la pronunciación de frases simples.']),
('Tercer Grado', 'Comunicación y Lenguaje L 3', '4. Utiliza frases y expresiones cotidianas, en forma escrita, con seguridad y creatividad.', ARRAY['4.1. Escribe expresiones cortas de uso cotidiano.', '4.2. Utiliza correctamente, en su escritura, signos propios del idioma en aprendizaje.', '4.3. Reproduce, correctamente, órdenes escritas.']),
('Tercer Grado', 'Comunicación y Lenguaje L 3', '5. Utiliza la lectura para responder a frases e instrucciones sencillas.', ARRAY['5.1. Deletrea palabras correctamente.', '5.2. Sigue instrucciones escritas.', '5.3. Interpreta anuncios escritos, panfletos, folletos, entre otros.']);

-- ===== cnb_primaria_10.sql =====
-- CNB Primaria - Comunicación y Lenguaje L 3 (idioma extranjero) - Cuarto, Quinto y Sexto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Comunicación_y_Lenguaje_L_3_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Cuarto Grado
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '1. Utiliza el lenguaje verbal y no verbal en la comunicación de textos orales relativos a situaciones cercanas a su realidad.', ARRAY['1.1. Sigue instrucciones orales.', '1.2. Ordena hechos para formar secuencias siguiendo parámetros temporales.', '1.3. Utiliza las expresiones de acuerdo a la particularidad del momento.', '1.4. Infiere significados de la información no verbal del contexto.', '1.5. Clasifica diferentes tipos de texto con los que trabaja de forma cotidiana.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '2. Produce textos orales con la pronunciación, el ritmo y la entonación propios del tercer idioma.', ARRAY['2.1. Se comunica mediante mensajes sencillos empleando los recursos a su alcance.', '2.2. Da respuestas breves a las preguntas que se le hacen.', '2.3. Pronuncia, correctamente, las palabras del vocabulario básico.', '2.4. Utiliza, en sus conversaciones o respuestas a preguntas, las palabras del vocabulario básico aprendido.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '3. Lee en forma comprensiva unidades mínimas de texto, estableciendo relaciones elementales entre texto y significado.', ARRAY['3.1. Reconoce palabras del vocabulario por su grafía.', '3.2. Interpreta frases de textos cortos.', '3.3. Infiere el significado de palabras específicas en frases y oraciones.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '4. Produce textos escritos breves y sencillos apegándose a las normas de la lengua extranjera.', ARRAY['4.1. Utiliza correctamente las grafías.', '4.2. Escribe palabras con el orden correspondiente.', '4.3. Escribe datos personales en el tercer idioma.']),
('Cuarto Grado', 'Comunicación y Lenguaje L 3', '5. Reconoce que un idioma extranjero es la expresión de una nueva cultura.', ARRAY['5.1. Identifica la influencia de la lengua extranjera en la lengua materna.', '5.2. Contrasta fonemas de la L 1 y L 3.', '5.3. Identifica diferencias elementales en las costumbres culturales propias y las de la lengua extranjera.', '5.4. Muestra respeto por las expresiones lingüísticas y culturales en la lengua extranjera.']),

-- Quinto Grado
('Quinto Grado', 'Comunicación y Lenguaje L 3', '1. Utiliza, en su comunicación, textos orales referentes a situaciones, acontecimientos y objetos próximos.', ARRAY['1.1. Interpreta canciones, rimas e historias cortas, entre otras.', '1.2. Asocia imágenes y grafías.', '1.3. Expresa sus gustos y preferencias utilizando la L 3.', '1.4. Amplía el vocabulario que maneja en las situaciones comunicativas.']),
('Quinto Grado', 'Comunicación y Lenguaje L 3', '2. Establece la relación entre el significado, la pronunciación, el ritmo y la entonación y la representación gráfica de palabras y frases sencillas.', ARRAY['2.1. Evidencia la importancia de una correcta pronunciación y entonación para la comunicación.', '2.2. Utiliza las palabras nuevas para elaborar sus mensajes.']),
('Quinto Grado', 'Comunicación y Lenguaje L 3', '3. Lee en forma comprensiva sus producciones escritas así como las señalizaciones, anuncios y mensajes básicos.', ARRAY['3.1. Ordena convenientemente los diferentes fragmentos de una historia dada.', '3.2. Identifica personajes en historias, cuentos y canciones.']),
('Quinto Grado', 'Comunicación y Lenguaje L 3', '4. Produce textos escritos breves de su entorno personal y familiar.', ARRAY['4.1. Maneja correctamente la ortografía de las palabras.', '4.2. Redacta textos sencillos utilizando el vocabulario aprendido.']),
('Quinto Grado', 'Comunicación y Lenguaje L 3', '5. Respeta las costumbres y tradiciones que implica el idioma en aprendizaje.', ARRAY['5.1. Establece la diferencia entre aspectos de la realidad cotidiana transmitidos por la lengua extranjera y las costumbres de su propia cultura.', '5.2. Utiliza saludos y despedidas adecuados a la situación.']),

-- Sexto Grado
('Sexto Grado', 'Comunicación y Lenguaje L 3', '1. Comunica la información global y específica de textos orales y escritos, sobre situaciones y acontecimientos de su entorno.', ARRAY['1.1. Utiliza el vocabulario en situaciones comunicativas recreadas en el aula.', '1.2. Interpreta información oral y escrita y la emplea con fines prácticos.', '1.3. Emplea el idioma para resolver dudas en los intercambios comunicativos.']),
('Sexto Grado', 'Comunicación y Lenguaje L 3', '2. Establece relaciones entre el significado, la pronunciación y la representación gráfica del vocabulario de los aspectos sonoros, del ritmo y de la entonación.', ARRAY['2.1. Reproduce espontáneamente la pronunciación correcta de las palabras.', '2.2. Describe los elementos básicos de la estructura gramatical.']),
('Sexto Grado', 'Comunicación y Lenguaje L 3', '3. Lee en forma comprensiva textos cortos y sencillos, previamente trabajados de forma oral, relacionados con sus experiencias e intereses.', ARRAY['3.1. Emplea la información contenida en los textos que se le proporcionan para construir otra información.', '3.2. Lee textos de manera espontánea.', '3.3. Sigue instrucciones expresadas por escrito.']),
('Sexto Grado', 'Comunicación y Lenguaje L 3', '4. Produce textos escritos sencillos sobre temas conocidos respetando las normas gramaticales del idioma en estudio.', ARRAY['4.1. Escribe textos cortos y sencillos de acuerdo con los patrones gramaticales básicos del idioma.', '4.2. Aplica los diferentes elementos gramaticales en producciones escritas cortas.', '4.3. Describe los elementos básicos de la estructura gramatical.']),
('Sexto Grado', 'Comunicación y Lenguaje L 3', '5. Incorpora elementos culturales por medio del idioma de acuerdo con las costumbres y modos de vida de los nativos del idioma en estudio.', ARRAY['5.1. Participa activa y voluntariamente en actividades de lectura.', '5.2. Se interesa por conocer personajes importantes de donde proviene el idioma en estudio.', '5.3. Emplea saludos y normas de cortesía adecuados a la situación.']);

-- ===== cnb_primaria_11.sql =====
-- CNB Primaria - Medio Social y Natural - Primero, Segundo y Tercer Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Medio_Social_y_Natural_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Primer Grado
('Primer Grado', 'Medio Social y Natural', '1. Identifica las partes y los órganos del cuerpo humano y realiza acciones en su entorno para mantener la salud e higiene corporal.', ARRAY['1.1. Describe las partes externas e internas del cuerpo humano, su importancia y cuidado para conservar la salud.', '1.2. Explica la importancia del Esqueleto Humano, las funciones, el cuidado y la higiene de los órganos vitales y de los sentidos.', '1.3. Practica hábitos para la conservación de la salud e higiene corporal.']),
('Primer Grado', 'Medio Social y Natural', '2. Establece la diferencia entre los factores bióticos y abióticos en el ecosistema.', ARRAY['2.1. Identifica las características de los factores bióticos en diferentes ecosistemas.', '2.2. Identifica las características de los factores abióticos en diferentes ecosistemas.', '2.3. Describe formas de protección y conservación de los factores del ecosistema.']),
('Primer Grado', 'Medio Social y Natural', '3. Utiliza la curiosidad, la experiencia personal y los saberes de su comunidad como método de aprendizaje.', ARRAY['3.1. Utiliza la observación en la recolección de información de su medio social y natural.', '3.2. Describe lo aprendido por medio de la observación y de los saberes de la comunidad.']),
('Primer Grado', 'Medio Social y Natural', '4. Practica el respeto, la tolerancia, la solidaridad y otros valores en su vida diaria.', ARRAY['4.1. Describe la importancia de la práctica de los valores en la vida diaria.']),
('Primer Grado', 'Medio Social y Natural', '5. Identifica las propiedades físicas de la materia en objetos de su entorno inmediato.', ARRAY['5.1. Asocia objetos de su entorno inmediato según características físicas de la materia: forma, tamaño, textura y color.']),
('Primer Grado', 'Medio Social y Natural', '6. Relaciona los movimientos y composición de la tierra con los fenómenos naturales y su incidencia en la sociedad.', ARRAY['6.1. Identifica el día y la noche, las estaciones y las épocas del año, como fenómenos naturales asociados a los movimientos de la tierra.', '6.2. Describe la influencia de los movimientos de la tierra en el clima, los cultivos y las ocupaciones de sus habitantes.']),
('Primer Grado', 'Medio Social y Natural', '7. Describe características físicas, hechos y actividades actuales de su comunidad relacionándolos con acontecimientos históricos.', ARRAY['7.1. Describe las actividades que practican los habitantes de su comunidad.', '7.2. Relaciona hechos y actividades que se realizan en la actualidad con las prácticas del pasado.', '7.3. Valora la tradición oral como medio para conocer la historia de su comunidad.']),

-- Segundo Grado
('Segundo Grado', 'Medio Social y Natural', '1. Identifica la estructura, funciones y cuidado de los órganos, aparatos y sistemas que forman el cuerpo humano, participando en acciones para el mantenimiento corporal.', ARRAY['1.1. Describe las características físicas, los cuidados e higiene de los seres humanos y los principales cambios en las diferentes etapas de la vida.', '1.2. Practica medidas preventivas y nutricionales para conservar la salud.', '1.3. Practica hábitos de higiene para la conservación de la salud y valores para la convivencia armónica.', '1.5. Se desempeña en forma equitativa y responsable en la vida familiar, escolar y comunitaria.']),
('Segundo Grado', 'Medio Social y Natural', '2. Describe la importancia de la interacción entre los factores bióticos y abióticos en los ecosistemas.', ARRAY['2.1. Identifica las diferentes formas de relación que se establecen entre factores bióticos y abióticos en el ecosistema.', '2.2. Establece la relación entre factores bióticos de diferentes ecosistemas con recursos naturales.']),
('Segundo Grado', 'Medio Social y Natural', '3. Utiliza saberes y procesos básicos de investigación científica como método de aprendizaje.', ARRAY['3.1. Utiliza diversas técnicas en la recolección de información de su medio social y natural.', '3.2. Describe en forma oral y escrita lo aprendido en la observación y de los saberes de la comunidad.']),
('Segundo Grado', 'Medio Social y Natural', '4. Fomenta el respeto, la tolerancia, la solidaridad y otros valores acordes a su contexto.', ARRAY['4.1. Relaciona los valores y el respeto a los Derechos Humanos con la convivencia armónica.', '4.2. Promueve el diálogo en la resolución de conflictos.']),
('Segundo Grado', 'Medio Social y Natural', '5. Identifica los beneficios que se obtienen de la materia en sus diferentes estados y las manifestaciones de la energía.', ARRAY['5.1. Describe las características de cada uno de los estados en que se presenta la materia en la naturaleza.', '5.2. Describe las formas en que se manifiesta la energía en su entorno (acústica, lumínica, calorífica y eléctrica).', '5.3. Explica la importancia de los beneficios que se obtienen de la energía.']),
('Segundo Grado', 'Medio Social y Natural', '6. Explica la importancia de los puntos de referencia y los movimientos de la tierra para su ubicación en el tiempo y en el espacio.', ARRAY['6.1. Describe características físicas del entorno en que vive y se ubica en relación a los puntos cardinales y la posición del sol en un mapa o croquis de la comunidad.', '6.2. Describe la influencia de los movimientos de la tierra en la definición del tiempo y ocupaciones de los habitantes.']),
('Segundo Grado', 'Medio Social y Natural', '7. Describe características físicas, actividades y hechos actuales en su municipio que contribuyen al reconocimiento de su origen e identidad.', ARRAY['7.1. Describe las características de su municipio y del departamento: límites, extensión, habitantes y actividades que practican.', '7.2. Relaciona costumbres y hechos actuales con el pasado para reafirmar su identidad.', '7.3. Identifica las principales autoridades de su municipio y del departamento y la función que ejercen.']),

-- Tercer Grado
('Tercer Grado', 'Medio Social y Natural', '1. Realiza acciones preventivas a nivel familiar, escolar y comunitario que promueven el buen funcionamiento de los órganos, aparatos y sistemas que forman el cuerpo humano.', ARRAY['1.1. Describe el funcionamiento de los órganos, aparatos y sistemas del cuerpo humano.', '1.2. Describe los cambios que ocurren en el cuerpo humano en las diferentes etapas de la vida.', '1.4. Practica hábitos para la conservación de la salud y de los valores morales para la convivencia armónica.', '1.5. Aplica medidas de seguridad individual y colectiva, para preservar la salud, la vida y el entorno en que vive.', '1.6. Ejerce los derechos y las responsabilidades que conllevan los diferentes roles sociales que desempeña en la vida familiar, escolar y comunitaria.']),
('Tercer Grado', 'Medio Social y Natural', '2. Describe las formas en que se relacionan los factores bióticos y abióticos en un ecosistema.', ARRAY['2.1. Identifica las funciones de los factores bióticos y abióticos en un ecosistema.', '2.2. Describe las relaciones que se establecen entre los componentes de un ecosistema.', '2.3. Participa en acciones de promoción y prevención de problemas de salud humana, sanidad animal y vegetal, así como ambientales para mantener el equilibrio ecológico.', '2.4. Participa en actividades de rescate, protección, conservación y promoción del patrimonio natural y cultural de su comunidad.', '2.5. Identifica los efectos de los procesos naturales en los procesos sociales referidos a la vida, al aumento y a la disminución poblacional.']),
('Tercer Grado', 'Medio Social y Natural', '3. Aplica saberes y procesos de investigación científica en la adquisición de conocimientos en los diferentes ámbitos en los que se desenvuelve.', ARRAY['3.1. Utiliza los resultados de la investigación en la resolución de problemas.', '3.2. Aplica el método científico para explicar la relación causa-efecto de un fenómeno natural y social.', '3.3. Elabora registros e informes sencillos de sus observaciones y experimentaciones.']),
('Tercer Grado', 'Medio Social y Natural', '4. Participa en la promoción de valores para la convivencia armónica, en el medio en que se desenvuelve.', ARRAY['4.2. Reconoce y practica la comunicación y el diálogo en la resolución de conflictos.']),
('Tercer Grado', 'Medio Social y Natural', '5. Describe la función de la materia como depositaria de energía, participando en actividades para su aprovechamiento racional y para su conservación.', ARRAY['5.1. Describe las características generales de la materia y sus propiedades.', '5.2. Describe diversas fuentes de energía para su aprovechamiento personal y colectivo.', '5.3. Explica los beneficios que se obtienen de la energía en actividades de la vida diaria.']),
('Tercer Grado', 'Medio Social y Natural', '6. Explica la relación del sol, las estrellas y los planetas con los fenómenos naturales y sociales, su influencia en el medio ambiente teniendo en cuenta los aportes de la ciencia y la tecnología.', ARRAY['6.1. Describe características físicas del entorno en que vive y se ubica en relación con los puntos cardinales y la posición del sol.', '6.2. Describe la influencia de los movimientos de la tierra en la definición del tiempo, el clima, cultivos y ocupaciones de los habitantes de su comunidad y región.', '6.3. Reconoce los aportes de la ciencia y la tecnología en los fenómenos y procesos sociales.']),
('Tercer Grado', 'Medio Social y Natural', '7. Relaciona espacios geográficos, actividades actuales, hechos históricos y culturales relevantes que han impulsado cambios significativos en su comunidad y departamento.', ARRAY['7.1. Explica la organización del espacio geográfico del municipio, departamento y país, en función de las actividades que practican.', '7.2. Relaciona manifestaciones culturales y hechos actuales con la historia del municipio, departamento y país.', '7.3. Identifica las principales autoridades de su municipio, departamento y país y la función que ejercen.']);

-- ===== cnb_primaria_12.sql =====
-- CNB Primaria - Ciencias Naturales y Tecnología - Cuarto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Ciencias_Naturales_y_Tecnología_-_Cuarto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '1. Explica las teorías del origen de la vida, las características de los seres vivos y las funciones de la célula en la organización de los sistemas de vida desde la ciencia y la diversidad cultural.', ARRAY['1.1. Describe las similitudes y diferencias entre las diversas teorías sobre el origen de la vida.', '1.2. Describe la estructura celular y su función.', '1.3. Describe las características de los seres vivos explicando la estructura y función de órganos y sistemas de su cuerpo.', '1.4. Describe los hechos científicos y los relaciona con su contexto natural y social.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '2. Diferencia entre las estructuras y las funciones de órganos y sistemas de los seres vivos.', ARRAY['2.1. Establece relaciones de similitud o diferencia entre las características de los seres vivos.', '2.2. Establece similitud entre las funciones de los diversos órganos y sistemas.', '2.3. Describe la estructura y funcionamiento de los sistemas digestivo, respiratorio, circulatorio, endocrino y nervioso.', '2.4. Explica la nutrición como proceso fundamental del aparato digestivo.', '2.5. Define la relación entre nutrición y digestión.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '3. Identifica su sexualidad y las manifestaciones físicas y sociales de su desarrollo.', ARRAY['3.1. Explica los factores de crecimiento y desarrollo de los seres vivos.', '3.2. Establece similitudes y diferencias entre crecimiento y desarrollo.', '3.3. Respeta las diferencias individuales y colectivas.', '3.4. Identifica el VIH-SIDA como una infección de transmisión sexual.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '4. Establece la relación entre vida saludable, prevención en el consumo de drogas y violencia intrafamiliar.', ARRAY['4.1. Identifica prácticas para una vida saludable.', '4.2. Reconoce las consecuencias del consumo de drogas, alcohol y tabaco.', '4.3. Identifica factores de riesgo y de protección en el consumo de drogas.', '4.4. Opina con respecto a las consecuencias sociales de la violencia intrafamiliar para la salud mental y física.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '5. Identifica las prácticas alimentarias y de salud que le permiten la prevención de enfermedades.', ARRAY['5.1. Practica hábitos alimentarios que favorecen la prevención de enfermedades.', '5.2. Explica qué es una dieta balanceada y la relaciona con la salud.', '5.3. Valora la vacunación como una forma para evitar enfermedades.', '5.4. Identifica técnicas para la conservación de alimentos.', '5.5. Relaciona la higiene con la prevención de enfermedades.', '5.6. Practica medidas para erradicar parásitos transmisores de enfermedades.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '6. Participa en actividades que promueven el rescate, el conocimiento, la protección, la conservación y el uso racional de los recursos naturales.', ARRAY['6.1. Promueve el derecho a un ambiente sano y de seguridad comunitaria.', '6.2. Describe la importancia del agua para los seres vivos.', '6.3. Explica la importancia de los ecosistemas en la supervivencia de la biodiversidad.', '6.4. Identifica los elementos nocivos para el entorno.', '6.5. Utiliza racionalmente los recursos naturales.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '7. Explica la relación entre materia y energía y su utilidad para el ser humano.', ARRAY['7.1. Relaciona el movimiento con la energía y la materia.', '7.2. Identifica fuentes de energía.', '7.3. Relaciona energía y trabajo.', '7.4. Explica la estructura y función del átomo.', '7.5. Opina acerca de la necesidad de la energía para la vida.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '8. Utiliza la tecnología de su cultura y de otras culturas en la investigación.', ARRAY['8.1. Diferencia entre características cualitativas y cuantitativas en los procesos que observa.', '8.2. Utiliza eficientemente la tecnología en el proceso de experimentación.', '8.3. Presenta en forma gráfica la información obtenida.', '8.4. Emite juicios críticos con respecto a los resultados de la experimentación científica.']);

-- ===== cnb_primaria_13.sql =====
-- CNB Primaria - Ciencias Naturales y Tecnología - Quinto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Ciencias_Naturales_y_Tecnología_-_Quinto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Quinto Grado', 'Ciencias Naturales y Tecnología', '1. Compara las teorías del origen de la vida desde la perspectiva intercultural que le permite distinguir entre los diversos tipos de manifestaciones de vida.', ARRAY['1.1. Explica el origen de la vida según la cosmovisión de las diferentes culturas.', '1.2. Establece las diferencias entre la célula animal y la célula vegetal.', '1.3. Identifica las características de los seres vivos.', '1.4. Explica el proceso de la fotosíntesis.', '1.5. Describe los beneficios que otros seres vivos representan para el ser humano.']),
('Quinto Grado', 'Ciencias Naturales y Tecnología', '2. Compara estructuras y funciones de órganos y sistemas que diferencian a los seres vivos.', ARRAY['2.1. Explica la estructura ósea y la función de los tejidos, órganos y sistemas de los seres vivos.', '2.2. Analiza la relación entre tejido, órgano y sistema.', '2.3. Explica los procesos de la vida.']),
('Quinto Grado', 'Ciencias Naturales y Tecnología', '3. Identifica la función sexual humana y su impacto en las relaciones sociales y afectivas.', ARRAY['3.1. Caracteriza la sexualidad como parte del crecimiento y desarrollo humano.', '3.2. Relaciona la sexualidad con la reproducción.', '3.3. Identifica la función de las hormonas en el comportamiento sexual.', '3.4. Explica el proceso de reproducción.', '3.5. Explica las causas y efectos de las infecciones de transmisión sexual.', '3.6. Describe las consecuencias de la pandemia del SIDA.']),
('Quinto Grado', 'Ciencias Naturales y Tecnología', '4. Manifiesta responsabilidad en la prevención del consumo de drogas.', ARRAY['4.1. Explica los efectos del tabaquismo, alcoholismo y drogas en la salud del ser humano.', '4.2. Describe las formas de prevención en el uso de las drogas.']),
('Quinto Grado', 'Ciencias Naturales y Tecnología', '5. Consume alimentos saludables dentro de un entorno limpio.', ARRAY['5.1. Identifica los elementos y el valor nutricional de los alimentos en una dieta balanceada.', '5.2. Relaciona la vacunación con la prevención de enfermedades.', '5.3. Realiza acciones de saneamiento en su entorno para erradicar animales e insectos perjudiciales para la salud humana.', '5.4. Aplica según el caso los términos epidemia, endemia y pandemia.']),
('Quinto Grado', 'Ciencias Naturales y Tecnología', '6. Fomenta la importancia de un entorno sano y la seguridad personal y colectiva por medio del desarrollo sostenible en función del equilibrio ecológico.', ARRAY['6.1. Evalúa el impacto que sobre el ambiente tienen las acciones que realiza el ser humano.', '6.2. Explica la importancia del saneamiento ambiental.', '6.3. Argumenta a favor del manejo de los desechos y prácticas de reciclaje.', '6.4. Explica el ciclo del agua, su importancia para la vida y las formas alternativas para su purificación.', '6.5. Argumenta a favor de la conservación y protección de los ecosistemas.', '6.6. Explica las técnicas que se utilizan en las diferentes etapas del cultivo de plantas.', '6.7. Identifica mecanismos para la prevención de plagas y contaminantes.']),
('Quinto Grado', 'Ciencias Naturales y Tecnología', '7. Explica los cambios en la materia y energía y el impacto de su uso desmedido por los seres humanos.', ARRAY['7.1. Diferencia la materia por sus características y estados en que se encuentra.', '7.3. Relaciona la energía con las máquinas y el trabajo.']),
('Quinto Grado', 'Ciencias Naturales y Tecnología', '8. Explica el mejoramiento de los resultados de la investigación científica en función del uso de tecnología apropiada.', ARRAY['8.1. Describe los aportes de la investigación espacial a la ciencia y la cultura universal.', '8.2. Formula conclusiones a partir de la experimentación.', '8.3. Utiliza el resultado de la experimentación en la solución de problemas.', '8.4. Utiliza las medidas internacionales y las locales en procesos de experimentación.', '8.5. Explica los factores que integran la atmósfera.', '8.6. Explica los factores que afectan la atmósfera.', '8.7. Identifica el sistema solar y otros elementos en el espacio.', '8.8. Describe los aportes de la exploración espacial.']);

-- ===== cnb_primaria_14.sql =====
-- CNB Primaria - Ciencias Naturales y Tecnología - Sexto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Ciencias_Naturales_y_Tecnología_-_Sexto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Sexto Grado', 'Ciencias Naturales y Tecnología', '1. Relaciona el origen y evolución de la vida (procesos celulares, la herencia, reproducción, entre otros) con la interacción del ser humano con la naturaleza según los aportes de la ciencia y la cosmovisión de los Pueblos.', ARRAY['1.1. Explica el origen de la Tierra y del Universo según las distintas cosmovisiones.', '1.2. Explica la estructura y función celular.', '1.3. Compara distintos tipos de células explicando su estructura, función y reproducción.', '1.4. Establece la relación entre genética y herencia.', '1.5. Explica la interdependencia entre algunos seres vivos.']),
('Sexto Grado', 'Ciencias Naturales y Tecnología', '2. Contrasta características, estructuras y funciones del ser humano, de los animales y de las plantas para comprender la razón de la diversidad biológica.', ARRAY['2.1. Clasifica los seres vivos y explica sus características.', '2.2. Describe las causas de la diversidad biológica.', '2.3. Establece la relación que existe entre la glándula, la hormona que produce y el funcionamiento del organismo.']),
('Sexto Grado', 'Ciencias Naturales y Tecnología', '3. Describe la reproducción y el comportamiento ético con relación a la sexualidad como forma de conservar la salud y proteger la vida.', ARRAY['3.1. Describe la estructura y funcionamiento del aparato reproductor masculino y femenino.', '3.2. Relaciona la sexualidad con el embarazo.', '3.3. Argumenta a favor de la ética en la sexualidad humana.', '3.4. Identifica formas de prevenir infecciones de transmisión sexual, conservar la salud y proteger la vida.', '3.5. Explica los efectos y consecuencias del VIH-SIDA.']),
('Sexto Grado', 'Ciencias Naturales y Tecnología', '4. Emite juicio crítico acerca del impacto que el consumo de drogas tiene en la salud humana.', ARRAY['4.1. Relaciona el consumo de drogas con el contagio de algunas enfermedades.', '4.2. Describe prácticas que promueven una vida saludable libre del consumo de drogas.', '4.3. Explica los efectos del consumo de drogas en la salud del ser humano.']),
('Sexto Grado', 'Ciencias Naturales y Tecnología', '5. Propicia las condiciones necesarias para el consumo de una dieta variada que facilite la conservación de la salud.', ARRAY['5.1. Describe las funciones de los nutrientes.', '5.2. Describe el valor nutritivo y económico de la lactancia materna.', '5.3. Demuestra la importancia de la nutrición en la prevención de enfermedades.']),
('Sexto Grado', 'Ciencias Naturales y Tecnología', '6. Emite juicio crítico acerca del impacto que la actividad humana y el crecimiento poblacional tienen en el deterioro ambiental.', ARRAY['6.1. Establece la relación entre ambiente sano y salud.', '6.2. Establece la relación entre la actividad humana, el deterioro ambiental y los desastres.', '6.3. Explica la importancia de la reforestación para la prevención de desastres.', '6.4. Analiza el impacto del crecimiento demográfico en el ambiente.', '6.5. Identifica elementos poblacionales como densidad, mortalidad, morbilidad, natalidad y migración.']),
('Sexto Grado', 'Ciencias Naturales y Tecnología', '7. Describe el desarrollo sostenible como una opción para conservar los recursos energéticos ante el crecimiento poblacional.', ARRAY['7.1. Relaciona los diferentes tipos de energía con el movimiento.', '7.2. Explica el desarrollo sostenible como resultado del uso racional de los recursos naturales.', '7.3. Explica las características del calentamiento global y el efecto invernadero como consecuencia de la contaminación del aire.']),
('Sexto Grado', 'Ciencias Naturales y Tecnología', '8. Realiza la experimentación a partir del uso de la tecnología a su alcance, dentro de un proceso de investigación.', ARRAY['8.1. Utiliza la información obtenida durante la observación para predecir posibles resultados.', '8.2. Utiliza la experimentación para comprobar las predicciones realizadas.', '8.3. Demuestra los principales aportes de los viajes espaciales a la cultura universal.']);

-- ===== cnb_primaria_15.sql =====
-- CNB Primaria - Ciencias Sociales - Cuarto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Ciencias_Sociales_-_Cuarto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Cuarto Grado', 'Ciencias Sociales', '1. Compara la relación dinámica de los procesos formadores de la tierra en Guatemala y Centroamérica con la configuración de su superficie.', ARRAY['1.1. Describe los procesos de formación de la tierra y su relación con la ubicación geográfica de Centroamérica.', '1.2. Describe los riesgos de vivir en zonas vulnerables a las fallas geológicas.', '1.3. Describe la incidencia que tiene el relieve en los climas y en la vida de las personas.']),
('Cuarto Grado', 'Ciencias Sociales', '2. Describe las relaciones que se dan entre diversas formas de vida y el ambiente natural.', ARRAY['2.1. Explica los distintos elementos de las cosmovisiones de los pueblos de Guatemala.', '2.2. Describe las riquezas naturales con las que cuenta Centroamérica, las formas de aprovechamiento y de conservación.']),
('Cuarto Grado', 'Ciencias Sociales', '3. Relaciona la ubicación geográfica de los países centroamericanos con la distribución, el desplazamiento y las actividades productivas de la población.', ARRAY['3.1. Identifica los procesos sociales relacionados con la vida, el aumento y la disminución de la población centroamericana.', '3.2. Describe distintas actividades económicas y productivas que se dan en los diferentes países de Centroamérica.', '3.3. Describe las acciones que realizan las instituciones y las organizaciones que impulsan la integración económica de Centroamérica.']),
('Cuarto Grado', 'Ciencias Sociales', '4. Describe los espacios y escenarios de la cotidianidad en su comunidad y la relación con otros países de Centroamérica.', ARRAY['4.1. Describe las distintas prácticas que se dan en su comunidad y otras comunidades de los países centroamericanos.', '4.2. Describe los espacios y escenarios que se dan en la cotidianidad en su comunidad.', '4.3. Identifica instituciones sociales, político-administrativas y religiosas de Centroamérica.']),
('Cuarto Grado', 'Ciencias Sociales', '5. Utiliza la curiosidad, la experiencia personal y los saberes de su comunidad como medios de aprendizaje.', ARRAY['5.1. Utiliza la observación y el registro de información como medio de aprendizaje.']),
('Cuarto Grado', 'Ciencias Sociales', '6. Relaciona hechos actuales de Centroamérica con acontecimientos históricos.', ARRAY['6.1. Relaciona la historia de los pueblos primitivos de su país y la de los pueblos primitivos en los otros países que integran la región centroamericana.', '6.2. Establece la relación entre los principales procesos históricos que ha vivido la región centroamericana, a partir del descubrimiento, conquista y colonización.', '6.3. Relaciona diferentes hechos y situaciones que se manifiestan durante la época colonial en Centroamérica.', '6.4. Describe el proceso de independencia de Centroamérica, resaltando los intereses que promovieron la participación de los diferentes grupos sociales.', '6.5. Establece la relación entre los principales acontecimientos que se manifiestan durante el siglo XIX y los efectos en el ámbito social, económico, político y cultural de cada país centroamericano.', '6.6. Identifica los principales acontecimientos ocurridos en el siglo XX.']),
('Cuarto Grado', 'Ciencias Sociales', '7. Practica valores, hábitos y actitudes que fomentan el respeto, la tolerancia, la solidaridad y otros valores en su vida diaria.', ARRAY['7.1. Practica sus derechos y cumple con sus responsabilidades en la familia, escuela y comunidad.', '7.2. Manifiesta sentido de pertenencia a la región centroamericana.']),
('Cuarto Grado', 'Ciencias Sociales', '8. Identifica distintas opciones de solución a los problemas y conflictos políticos y sociales de Centroamérica.', ARRAY['8.1. Utiliza el diálogo como medio de comunicación para la solución de conflictos.', '8.2. Relaciona condiciones que determinan la calidad de vida de los habitantes de Centroamérica.', '8.3. Identifica sus responsabilidades ciudadanas y los organismos que velan por los Derechos Humanos en el país.']);

-- ===== cnb_primaria_16.sql =====
-- CNB Primaria - Ciencias Sociales - Quinto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Ciencias_Sociales_-_Quinto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Quinto Grado', 'Ciencias Sociales', '1. Describe las formas del relieve que representan mayores ventajas para la ubicación y el desarrollo de actividades de las poblaciones de América.', ARRAY['1.1. Establece la relación entre el espacio territorial y su representación cartográfica.', '1.2. Relaciona la ubicación geográfica de las poblaciones americanas con el desarrollo de sus actividades.', '1.3. Describe los riesgos de vivir en zonas vulnerables.']),
('Quinto Grado', 'Ciencias Sociales', '2. Describe las relaciones que se dan entre el aprovechamiento de los recursos naturales y los niveles de desarrollo de los países de América.', ARRAY['2.1. Identifica las características de los recursos naturales de cada país de América.', '2.2. Identifica los recursos naturales agua, fauna y flora, suelo, aire y los relaciona con el desarrollo de la vida.', '2.3. Participa en actividades para el rescate, protección y conservación del patrimonio natural de su comunidad y su relación con otros países de América.']),
('Quinto Grado', 'Ciencias Sociales', '3. Relaciona la distribución de la población de América con las actividades productivas y el aprovechamiento del patrimonio natural y cultural.', ARRAY['3.1. Identifica los procesos sociales relacionados con la vida, el aumento y disminución de la población en América.', '3.2. Describe distintas actividades económicas y productivas que se dan en los diferentes países de América.', '3.3. Describe formas de proteger, rescatar y aprovechar el patrimonio natural y cultural de su país.', '3.4. Identifica acciones económicas y relaciones diplomáticas entre los distintos países de América.']),
('Quinto Grado', 'Ciencias Sociales', '4. Describe los cambios que han ocurrido a través del tiempo en los espacios y escenarios de lo cotidiano y no cotidiano.', ARRAY['4.1. Identifica la relación causa y efecto de lo cotidiano y no cotidiano.', '4.2. Describe las condiciones de equidad que deben prevalecer en el medio en que se desenvuelve.', '4.3. Reflexiona acerca de la función que realizan las instituciones sociales y religiosas en América.']),
('Quinto Grado', 'Ciencias Sociales', '5. Utiliza los saberes y procesos de investigación social como medio de aprendizaje para dar respuestas a interrogantes personales.', ARRAY['5.1. Utiliza la observación y el registro de información como medio de aprendizaje de los elementos culturales e históricos.']),
('Quinto Grado', 'Ciencias Sociales', '6. Relaciona los hechos actuales de América con los del pasado, basándose en los principios de su origen e identidad.', ARRAY['6.1. Identifica características físicas del continente americano.', '6.2. Relaciona la historia de los pueblos que dieron origen a su país, con la de los países que integran la región americana.', '6.3. Relaciona los principales procesos históricos que ha vivido la región americana, a partir del descubrimiento, conquista y colonización.', '6.4. Relaciona la realidad actual de su país con acontecimientos históricos relevantes sucedidos en países de América durante la época colonial.', '6.5. Explica el proceso de independencia de América, resaltando los intereses que promovieron la participación de los diferentes grupos sociales.', '6.6. Analiza los principales acontecimientos que se manifiestan durante el siglo XIX y los efectos en el ámbito social, económico, político y cultural de América.', '6.7. Identifica los principales acontecimientos ocurridos en el siglo XX.']),
('Quinto Grado', 'Ciencias Sociales', '7. Practica el respeto, la tolerancia, la solidaridad y otros valores acordes a su contexto social, cultural, étnico y natural.', ARRAY['7.1. Practica sus derechos y cumple con sus responsabilidades en la familia, escuela y comunidad.', '7.2. Manifiesta sentido de pertenencia a la región americana con la que se siente comprometido.', '7.3. Organiza actividades de promoción y respeto de la cultura de su comunidad.', '7.4. Describe los cambios culturales que se producen en los distintos países de América.', '7.5. Describe las funciones y el papel que desempeñan los organismos internacionales en la solución de los conflictos.', '7.6. Promueve acciones de participación ciudadana.']),
('Quinto Grado', 'Ciencias Sociales', '8. Promueve actividades que facilitan la identificación y solución de problemas políticos y sociales en América.', ARRAY['8.1. Organiza la participación en la identificación de problemas en América y sus posibles soluciones.', '8.2. Relaciona condiciones que permiten evaluar la calidad de vida.', '8.3. Identifica sus responsabilidades ciudadanas y los organismos que velan por los Derechos Humanos en el continente.']);

-- ===== cnb_primaria_17.sql =====
-- CNB Primaria - Ciencias Sociales - Sexto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Ciencias_Sociales_-_Sexto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Sexto Grado', 'Ciencias Sociales', '1. Compara las características geográficas relevantes de los continentes del mundo, para el aprovechamiento sostenible de sus recursos.', ARRAY['1.1. Relaciona las características y la ubicación geográfica de los continentes con el desarrollo de las actividades de las poblaciones en el mundo.', '1.2. Relaciona por medio de coordenadas geográficas (latitud y longitud) la superficie de la tierra con su localización.', '1.3. Enumera los riesgos de vivir en zonas vulnerables.']),
('Sexto Grado', 'Ciencias Sociales', '2. Relaciona el aprovechamiento racional de los recursos naturales con el mejoramiento de la calidad de vida en diferentes regiones del mundo.', ARRAY['2.1. Agrupa los tipos de recursos con que cuenta Guatemala y los contrasta con los de otros continentes.', '2.2. Describe distintas condiciones de vida en Guatemala y otros países en el mundo.', '2.3. Relaciona los recursos naturales agua, flora, fauna, suelo y aire con el desarrollo de la vida.']),
('Sexto Grado', 'Ciencias Sociales', '3. Argumenta sobre las actividades económicas, étnicas y culturales que se dan en distintas regiones del mundo.', ARRAY['3.1. Describe los procesos sociales relacionados con la vida, el aumento, la disminución y convivencia de la población mundial.', '3.2. Describe distintas actividades económicas y productivas que se dan en los diferentes escenarios y las formas de proteger y aprovechar el patrimonio natural y cultural de su país.', '3.3. Resalta la importancia de los medios de comunicación y de transporte en la vida de los seres humanos.', '3.4. Describe la incidencia de los tratados bilaterales y multilaterales, que suscribe Guatemala y la región de Centroamérica con otros países del mundo.']),
('Sexto Grado', 'Ciencias Sociales', '4. Relaciona las diferentes condiciones de vida social y laboral que se dan en los espacios y escenarios de su cotidianidad.', ARRAY['4.1. Establece la relación entre el tipo de trabajo y las condiciones de vida.', '4.2. Practica condiciones de equidad en su desempeño escolar.']),
('Sexto Grado', 'Ciencias Sociales', '5. Aplica saberes y procesos de investigación social en la adquisición de conocimientos, en los diferentes ámbitos en que se desenvuelve.', ARRAY['5.1. Aplica técnicas de investigación en la solución de problemas de la vida cotidiana.', '5.2. Utiliza varias fuentes en la búsqueda de información científica.', '5.3. Produce registros escritos de las informaciones recabadas.']),
('Sexto Grado', 'Ciencias Sociales', '6. Relaciona los procesos históricos relevantes con los cambios significativos que se han impulsado en el mundo.', ARRAY['6.1. Identifica la historia como ciencia, en relación con otras ciencias que permiten la interpretación del presente a partir de los hechos pasados.', '6.2. Relaciona la realidad actual de su país con acontecimientos históricos relevantes sucedidos en América y el mundo.', '6.3. Explica las organizaciones, desarrollos e incidencia de los modelos autoritarios y democráticos en la evolución de los pueblos y civilizaciones antiguas.', '6.5. Describe la situación política y económica mundial en los Siglos XX y XXI.', '6.6. Evalúa las condiciones que implican la Modernización y la Globalización en los distintos continentes.', '6.7. Emite opinión con respecto a los procesos políticos y de fortalecimiento de la Democracia en el mundo.']),
('Sexto Grado', 'Ciencias Sociales', '7. Participa en la promoción de valores para la convivencia armónica en su entorno y en su relación con otros pueblos y culturas del mundo.', ARRAY['7.1. Enumera sus derechos y cumple con sus responsabilidades ciudadanas y otras específicas en la familia, escuela y comunidad.', '7.2. Interpreta los avances de los procesos de paz en el mundo y las funciones y formas de desempeño de los organismos internacionales en la solución de los conflictos y la promoción del respeto a los Derechos Humanos.']),
('Sexto Grado', 'Ciencias Sociales', '8. Aplica principios de las Ciencias Sociales en la solución de problemas socioculturales.', ARRAY['8.1. Identifica la relación causa-efecto de un evento o fenómeno.', '8.2. Utiliza el diálogo como medio eficiente de comunicación para la solución de los conflictos.', '8.3. Describe la problemática de la población mundial con base en los datos e informes estadísticos.']);

-- ===== cnb_primaria_18.sql =====
-- CNB Primaria - Expresión Artística - Primero y Segundo Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Expresión_Artística_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Primer Grado
('Primer Grado', 'Expresión Artística', '1. Utiliza los recursos necesarios para la creación artística.', ARRAY['1.1. Reproduce esquemas musicales producidos con la voz.', '1.2. Reproduce esquemas musicales producidos con instrumentos.', '1.3. Reproduce esquemas musicales con su cuerpo.', '1.4. Demuestra dominio de las habilidades básicas para la expresión por medio del dibujo y la pintura.', '1.5. Respeta los espacios y las distancias entre actores al desplazarse en un escenario.', '1.6. Utiliza diferente tipo de recursos para la presentación de montajes escénicos adecuados a su edad.']),
('Primer Grado', 'Expresión Artística', '2. Integra las diversas manifestaciones artísticas con distintos aspectos de la vida de su comunidad.', ARRAY['2.1. Participa en actividades musicales que favorecen la improvisación, el movimiento y el juego.', '2.2. Utiliza el dibujo, el color y el volumen para expresar sus sentimientos, ideas y emociones.', '2.3. Participa en actividades tradicionales de su comunidad en las que resalta el movimiento, el ritmo, la actividad vocal y gesticular.', '2.4. Valora la expresión artística en sus diferentes manifestaciones.']),
('Primer Grado', 'Expresión Artística', '3. Establece relaciones entre las disciplinas artísticas en términos de movimiento y producción vocal.', ARRAY['3.1. Establece relaciones entre el movimiento y la producción vocal.', '3.2. Reproduce elementos del entorno con diversos materiales.']),
('Primer Grado', 'Expresión Artística', '4. Relaciona, entre sí, los lenguajes artísticos.', ARRAY['4.1. Utiliza diversos lenguajes artísticos para describir su entorno social y natural.', '4.2. Realiza actividades que integran diferentes expresiones artísticas y que fortalecen su identidad.']),

-- Segundo Grado
('Segundo Grado', 'Expresión Artística', '1. Utiliza las disciplinas artísticas como un medio de comunicación con su entorno inmediato.', ARRAY['1.1. Escucha y reproduce esquemas musicales producidos con la voz.', '1.2. Escucha y reproduce esquemas musicales producidos con instrumentos.', '1.3. Reproduce esquemas musicales con su cuerpo.', '1.4. Demuestra dominio de las habilidades básicas en la elaboración de trabajos.', '1.5. Evidencia dominio de la estructura de la danza y del movimiento.']),
('Segundo Grado', 'Expresión Artística', '2. Manifiesta interés por las creaciones artísticas participando en actividades propias de cada rama del arte.', ARRAY['2.1. Participa en juegos cantados, domésticos y musicales (canciones, rondas, recitados) de su comunidad.', '2.2. Valora la expresión artística en sus diferentes manifestaciones.']),
('Segundo Grado', 'Expresión Artística', '3. Se expresa creativamente utilizando diversos lenguajes: musical, teatral, corporal, plástico y audiovisual.', ARRAY['3.1. Utiliza diversas modalidades artísticas en la expresión creativa de sus emociones.', '3.2. Mueve su cuerpo en forma rítmica y coordinada en su desempeño escénico.']),
('Segundo Grado', 'Expresión Artística', '4. Demuestra respeto por las manifestaciones culturales de los pueblos que conforman el país.', ARRAY['4.1. Participa en la organización de presentaciones artísticas tradicionales y populares en la escuela.']);

-- ===== cnb_primaria_19.sql =====
-- CNB Primaria - Expresión Artística - Tercero y Cuarto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Expresión_Artística_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Tercer Grado
('Tercer Grado', 'Expresión Artística', '1. Establece relaciones entre los fenómenos artísticos en su ámbito sonoro y visual.', ARRAY['1.1. Relaciona ritmos y sonidos en los ámbitos vocal e instrumental.', '1.2. Combina líneas, patrones, texturas y color al elaborar objetos con diversidad de materiales.', '1.3. Participa en actividades que integran ritmo y melodía al movimiento y al desplazamiento.', '1.4. Integra los distintos lenguajes artísticos al describir su entorno social y cultural.']),
('Tercer Grado', 'Expresión Artística', '2. Expresa sentimientos y emociones por medio de desempeños artísticos: musicales, plásticos, teatrales, entre otros.', ARRAY['2.1. Aplica conceptos precisos de índole rítmica, melódica o combinada con la interpretación instrumental y vocal.', '2.2. Utiliza las artes plásticas para expresar sentimientos y emociones.', '2.3. Incorpora elementos del movimiento corporal y escénico a la expresión libre de sus sentimientos.']),
('Tercer Grado', 'Expresión Artística', '3. Se involucra en actividades que fomentan creatividad utilizando recursos existentes en su comunidad.', ARRAY['3.1. Participa en actividades musicales aportando su propia creación.', '3.2. Utiliza diferentes recursos plásticos en la elaboración de sus trabajos.', '3.3. Participa en el montaje de proyectos escénicos.']),
('Tercer Grado', 'Expresión Artística', '4. Manifiesta aprecio por el arte y los artistas guatemaltecos valorando su desempeño en el tiempo y en el espacio.', ARRAY['4.1. Reconoce la obra de artistas guatemaltecos.', '4.2. Identifica a los artistas guatemaltecos, los asocia con su obra y los ubica en el tiempo.', '4.3. Participa activamente en la organización de actividades para divulgar el arte de artistas guatemaltecos.']),

-- Cuarto Grado
('Cuarto Grado', 'Expresión Artística', '1. Aplica los principios rectores de las disciplinas artísticas en sus tareas cotidianas.', ARRAY['1.1. Expresa, oralmente, por medio de gestos y de movimientos, su nivel de percepción.', '1.2. Establece los efectos de la luz y del color en la expresión artística visual.', '1.3. Aplica los principios del movimiento en las actividades de danza en las que participa.', '1.4. Utiliza los efectos escénicos para fundamentar sus juicios sobre obras escénicas a las que asiste como espectador.']),
('Cuarto Grado', 'Expresión Artística', '2. Utiliza los diversos lenguajes artísticos para expresar sus emociones, sentimientos y pensamientos.', ARRAY['2.1. Utiliza el canto y la ejecución instrumental para expresar sus sentimientos.', '2.2. Utiliza las artes plásticas como medio de expresión de sus sentimientos.', '2.3. Utiliza la danza y las artes escénicas como medio de expresión de sus sentimientos.']),
('Cuarto Grado', 'Expresión Artística', '3. Aplica con pertinencia los conocimientos y las técnicas de las artes y los saberes tradicionales de su comunidad.', ARRAY['3.1. Utiliza el conocimiento de la voz y de los instrumentos propios de su comunidad en la ejecución de melodías sencillas.', '3.2. Aplica técnicas bi y tridimensionales en la producción de trabajos de artes plásticas.', '3.3. Utiliza sus conocimientos de ritmo y movimiento al participar en eventos de danza y teatro en su comunidad, región y país.']),
('Cuarto Grado', 'Expresión Artística', '4. Promueve, creativamente, proyectos artísticos colectivos de acuerdo con su nivel de desempeño.', ARRAY['4.1. Organiza producciones sonoras de manera espontánea.', '4.2. Participa como autor y como observador en exhibiciones de trabajos artísticos en el aula y en la escuela.', '4.3. Participa activamente en la organización de actividades artísticas en el aula, escuela y comunidad.']);

-- ===== cnb_primaria_20.sql =====
-- CNB Primaria - Expresión Artística - Quinto y Sexto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Expresión_Artística_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Quinto Grado
('Quinto Grado', 'Expresión Artística', '1. Utiliza los lenguajes artísticos en planteamientos creativos para la resolución de problemas.', ARRAY['1.1. Manifiesta comprensión del significado de los símbolos utilizados en la lecto-escritura musical.', '1.2. Establece la diferencia entre los colores existentes en la naturaleza y los producidos por el ser humano.', '1.3. Relaciona la percepción visual y auditiva de signos y efectos escénicos con elementos de la cotidianeidad.']),
('Quinto Grado', 'Expresión Artística', '2. Utiliza los lenguajes artísticos para establecer relación entre la expresión de emociones e ideas y la realidad circundante.', ARRAY['2.1. Asocia ritmos y sonidos con elementos del entorno circundante.', '2.2. Interpreta la intencionalidad del autor al analizar el uso de la forma, el color y la textura.']),
('Quinto Grado', 'Expresión Artística', '3. Utiliza técnicas de las diferentes artes y los saberes tradicionales de su comunidad en la elaboración de proyectos específicos.', ARRAY['3.1. Participa en actividades colectivas de canto y ejecución instrumental.', '3.2. Aplica técnicas que evidencian conocimiento del efecto de la luz sobre el color y del manejo de diversos materiales de su comunidad en la elaboración de proyectos escolares.', '3.3. Asocia el movimiento, el ritmo y el espacio en el montaje de coreografías.']),
('Quinto Grado', 'Expresión Artística', '4. Identifica diferentes opciones para impulsar técnicas utilizadas en la creación y producción artísticas.', ARRAY['4.1. Utiliza diferentes medios en la divulgación de eventos relacionados con la tradición musical de su comunidad.', '4.2. Utiliza diferentes medios en la divulgación de las técnicas de producción de la plástica y los textiles propios de su comunidad.', '4.3. Utiliza diferentes medios para la divulgación de eventos propios de la tradición oral de su comunidad.']),

-- Sexto Grado
('Sexto Grado', 'Expresión Artística', '1. Relaciona los códigos de las disciplinas artísticas con los saberes tradicionales.', ARRAY['1.1. Utiliza la lecto-escritura musical en la interpretación de música tradicional o moderna.', '1.2. Utiliza el registro audiovisual (grabación) como recurso para analizar y valorar el trabajo artístico.']),
('Sexto Grado', 'Expresión Artística', '2. Utiliza los lenguajes artísticos para fortalecer la comunicación de emociones e ideas con otros y otras.', ARRAY['2.1. Describe los procesos de experimentación sonora en función de la música y de la comunicación.', '2.2. Utiliza un lenguaje iconográfico en el diseño de afiches, carteles y letreros.']),
('Sexto Grado', 'Expresión Artística', '3. Participa en la producción de proyectos artísticos, individuales y colectivos, como una forma de promover mejoras en su entorno inmediato.', ARRAY['3.1. Participa en conjuntos musicales y de danza que utilizan repertorios que reflejan la identidad nacional.', '3.2. Participa en proyectos artísticos que resaltan la importancia de las diferentes texturas para los débiles visuales.', '3.3. Participa en actividades de conservación del patrimonio cultural.']),
('Sexto Grado', 'Expresión Artística', '4. Relaciona conocimientos y técnicas de las distintas artes con los saberes tradicionales de su entorno en la creación y producción artística.', ARRAY['4.1. Participa en dramatizaciones de obras de su propia creación y de autores nacionales e internacionales.', '4.2. Participa en la producción de materiales audiovisuales con contenidos culturales de su comunidad y región.', '4.3. Participa en foros cuyo contenido enfoca los elementos de la tradición cultural de su comunidad.']);

-- ===== cnb_primaria_21.sql =====
-- CNB Primaria - Educación Física - Primero y Segundo Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Educación_Física_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Primer Grado
('Primer Grado', 'Educación Física', '1. Identifica su esquema corporal y la forma de utilizarlo para realizar diversas actividades.', ARRAY['1.1. Utiliza su esquema corporal en las diversas actividades que realiza.', '1.2. Demuestra control de las diferentes partes de su cuerpo al realizar actividades que requieren equilibrio.', '1.3. Identifica la ubicación de su cuerpo, con respecto a un espacio y tiempo determinado.', '1.4. Identifica su habilidad rítmica-motriz en las actividades que realiza.']),
('Primer Grado', 'Educación Física', '2. Demuestra sus habilidades perceptivas, visuales, auditivas y táctiles por medio de actividades motrices.', ARRAY['2.1. Participa en juegos y rondas tradicionales y escolares que requieren el conocimiento del esquema corporal.']),
('Primer Grado', 'Educación Física', '3. Identifica los beneficios que obtiene con la práctica de hábitos de higiene, seguridad alimentaria y nutricional y actividades físicas.', ARRAY['3.1. Practica hábitos de higiene.', '3.2. Practica la seguridad alimentaria y nutricional.', '3.3. Identifica medidas de seguridad en sus actividades físicas, familiares y escolares.']),
('Primer Grado', 'Educación Física', '4. Fomenta actitudes que permiten la integración social y la pertenencia de grupo.', ARRAY['4.1. Manifiesta respeto por las actitudes, opiniones y diferencias de los y las demás.', '4.2. Participa en actividades grupales mostrando seguridad y tolerancia.']),

-- Segundo Grado
('Segundo Grado', 'Educación Física', '1. Utiliza el conocimiento de la función de su esquema corporal en las diversas actividades que realiza.', ARRAY['1.1. Practica movimientos corporales empleando diferentes partes de su cuerpo.', '1.2. Demuestra dominio de sus movimientos en forma combinada.', '1.3. Demuestra seguridad en actividades que requieren equilibrio.', '1.4. Mejora su habilidad rítmica-motriz en las actividades que realiza.']),
('Segundo Grado', 'Educación Física', '2. Demuestra dominio de sus movimientos en forma coordinada.', ARRAY['2.1. Participa, con seguridad, en juegos y rondas tradicionales.']),
('Segundo Grado', 'Educación Física', '3. Practica hábitos de higiene, seguridad alimentaria y nutricional y actividades físicas en beneficio de su salud.', ARRAY['3.1. Práctica hábitos de higiene para conservar la salud.', '3.2. Práctica la seguridad alimentaria y nutricional para mantenerse sano.', '3.3. Utiliza medidas de seguridad en sus actividades físicas, familiares y escolares.']),
('Segundo Grado', 'Educación Física', '4. Practica actitudes que permiten la integración social y la pertenencia de grupo.', ARRAY['4.1. Demuestra respeto por las actitudes, opiniones y diferencias de los y las demás.', '4.2. Participa en actividades grupales mostrando seguridad y colaboración.']);

-- ===== cnb_primaria_22.sql =====
-- CNB Primaria - Educación Física - Tercer Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Educación_Física_-_Tercer_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercer Grado', 'Educación Física', '1. Demuestra habilidades y destrezas de coordinación motriz general.', ARRAY['1.1. Aplica sus habilidades y destrezas motrices en forma coordinada.', '1.2. Demuestra seguridad en actividades que requieren equilibrio.', '1.3. Demuestra su habilidad rítmica-motriz en las actividades que realiza.']),
('Tercer Grado', 'Educación Física', '2. Establece la relación de su esquema corporal con su capacidad motriz en los diferentes movimientos que realiza.', ARRAY['2.1. Evidencia la relación de su esquema corporal, con su capacidad motriz en la realización de actividades deportivas y recreativas.']),
('Tercer Grado', 'Educación Física', '3. Demuestra los beneficios que obtiene con la práctica de hábitos de higiene, seguridad alimentaria y nutricional y actividades físicas.', ARRAY['3.1. Practica hábitos de higiene para conservar la salud.', '3.2. Demuestra la importancia de practicar la seguridad alimentaria y nutricional para mantenerse sano.', '3.3. Utiliza medidas de seguridad en sus actividades físicas, familiares y escolares.']),
('Tercer Grado', 'Educación Física', '4. Promueve actitudes que permiten la integración social y la pertenencia de grupo.', ARRAY['4.1. Manifiesta respeto por las actitudes, opiniones y diferencias de los y las demás como norma de conducta.', '4.2. Participa en actividades grupales mostrando seguridad, colaboración y tolerancia.']);

-- ===== cnb_primaria_23.sql =====
-- CNB Primaria - Educación Física - Cuarto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Educación_Física_-_Cuarto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Cuarto Grado', 'Educación Física', '1. Practica actividades físico deportivas que exigen cierto nivel de esfuerzo, habilidad o destreza de acuerdo con sus posibilidades y limitaciones.', ARRAY['1.1. Demuestra sus habilidades y destrezas según sus posibilidades y limitaciones.', '1.2. Demuestra seguridad en actividades que requieren equilibrio.', '1.3. Ejecuta carrera, salto de longitud y altura estilo tijereta que incluye carrera de impulso, despegue, vuelo y caída.', '1.4. Utiliza, en forma creativa y autónoma, los recursos expresivos del cuerpo y del movimiento.']),
('Cuarto Grado', 'Educación Física', '2. Practica actividades de iniciación deportiva, recreativa y juegos fortaleciendo el desarrollo de valores interculturales.', ARRAY['2.2. Participa en juegos y rondas tradicionales y escolares que requieren el conocimiento del esquema corporal.']),
('Cuarto Grado', 'Educación Física', '3. Identifica los beneficios que obtiene con la práctica de hábitos de higiene, seguridad alimentaria y nutricional.', ARRAY['3.1. Practica hábitos de higiene.', '3.2. Practica la seguridad alimentaria y nutricional.', '3.3. Utiliza medidas de seguridad en sus actividades físicas, familiares y escolares.']),
('Cuarto Grado', 'Educación Física', '4. Demuestra actitudes que permiten la integración social y la pertenencia de grupo.', ARRAY['4.1. Manifiesta respeto por las actitudes, opiniones y diferencias de los y las demás.', '4.2. Participa en actividades grupales mostrando seguridad y tolerancia.']);

-- ===== cnb_primaria_24.sql =====
-- CNB Primaria - Educación Física - Quinto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Educación_Física_-_Quinto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Quinto Grado', 'Educación Física', '1. Realiza actividades motrices que exigen cierto nivel de esfuerzo, habilidad o destreza de acuerdo con sus posibilidades y limitaciones.', ARRAY['1.1. Participa en actividades motrices teniendo en cuenta sus posibilidades y limitaciones.', '1.2. Participa en actividades que requieren equilibrio corporal.', '1.3. Participa en diferentes tipos de carreras y saltos en las actividades físicas.', '1.4. Utiliza el movimiento de su cuerpo como medio de expresión.']),
('Quinto Grado', 'Educación Física', '2. Participa en actividades de iniciación deportiva, recreativa y de juego, manifestando actitudes de respeto a las reglas, normas y protección del medio ambiente.', ARRAY['2.1. Practica ejercicios de bote, lanzamiento, pase y recepción del implemento con ambas manos y alternándolas.', '2.2. Promueve juegos y rondas tradicionales y escolares que requieren el conocimiento del esquema corporal.']),
('Quinto Grado', 'Educación Física', '3. Practica hábitos de higiene, seguridad alimentaria y nutricional.', ARRAY['3.1. Practica hábitos de higiene y medidas de seguridad en las diferentes actividades en las que participa.', '3.2. Aplica la seguridad alimentaria y nutricional en su vida diaria.']),
('Quinto Grado', 'Educación Física', '4. Participa en actividades físico deportivas y recreativas en el medio natural, como una forma de mantener la salud, respetando las diferencias de los y las demás.', ARRAY['4.1. Respeta las opiniones y diferencias de las y los demás en los juegos y actividades físico deportivas en las que participa.', '4.2. Acepta las diferencias y respeta a las y los demás y las normas de juego, en las actividades físico deportivas en las que participa.']);

-- ===== cnb_primaria_25.sql =====
-- CNB Primaria - Educación Física - Sexto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Educación_Física_-_Sexto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Sexto Grado', 'Educación Física', '1. Practica juegos de iniciación deportiva teniendo en cuenta sus niveles de destreza en los juegos en los que participa.', ARRAY['1.1. Utiliza sus habilidades motrices en los diferentes tipos de juegos o actividades predeportivas en las que participa.', '1.2. Manifiesta equilibrio y dominio del implemento deportivo.', '1.3. Demuestra coordinación en sus movimientos en las carreras y saltos en los que participa.', '1.4. Participa en actividades que requieren expresividad y creatividad en las que utiliza el eje corporal.']),
('Sexto Grado', 'Educación Física', '2. Practica juegos de iniciación adaptando las reglas y normas al espacio, al tiempo, a los recursos disponibles y a la protección del medio ambiente.', ARRAY['2.1. Demuestra dominio en ejercicios de conducción, control, bote, lanzamiento y recepción del implemento deportivo.', '2.2. Participa en actividades físicas de bajo impacto ambiental adaptando reglas y normas al espacio, tiempo y recursos disponibles.']),
('Sexto Grado', 'Educación Física', '3. Fomenta hábitos de higiene, seguridad alimentaria y nutricional.', ARRAY['3.1. Practica hábitos de higiene y medidas de seguridad en su entorno inmediato.', '3.2. Describe la importancia de la seguridad alimentaria y nutricional en su familia, escuela y comunidad.']),
('Sexto Grado', 'Educación Física', '4. Demuestra iniciativa personal y el hábito del trabajo en equipo, aceptando las normas y reglas previamente establecidas.', ARRAY['4.1. Respeta normas de juego y acepta las diferencias de las y los demás.', '4.2. Demuestra actitudes de cooperación, solidaridad, tolerancia y tratamiento equitativo con los y las demás, en los roles que desempeña en la actividad física.']);

-- ===== cnb_primaria_26.sql =====
-- CNB Primaria - Formación Ciudadana - Primer Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Formación_Ciudadana_-_Primer_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primer Grado', 'Formación Ciudadana', '1. Valora su identidad personal, familiar, de grupo social, étnica y cultural, así como su participación, la de sus padres y compañeras (os) en el desarrollo de actividades en la familia y en el aula.', ARRAY['1.1. Se respeta a sí mismo o a sí misma, a su familia y a su grupo social.', '1.2. Participa con responsabilidad en las actividades del hogar y del aula.', '1.3. Es solidario, cooperativo y equitativo en las actividades que realiza, en la familia y en el aula.', '1.4. Manifiesta su autoestima y aprecio por los y las demás.', '1.5. Se identifica con orgullo con respecto a su familia, grupo social, étnico y cultural.']),
('Primer Grado', 'Formación Ciudadana', '2. Evidencia equidad y buen trato en sus relaciones interpersonales como niña o niño en la vida familiar y escolar.', ARRAY['2.1. Participa con autonomía en actividades en la escuela.', '2.2. Trata con equidad a niñas, niños, maestras y maestros.', '2.3. Defiende el derecho a dar y recibir un trato social y legal basado en la equidad y la justicia social.']),
('Primer Grado', 'Formación Ciudadana', '3. Comparte responsabilidades, deberes y obligaciones en el aula.', ARRAY['3.1. Participa en la organización de actividades de aula.', '3.2. Propone soluciones a los problemas en el aula.', '3.3. Comparte opiniones en la toma de decisiones en el aula.']),
('Primer Grado', 'Formación Ciudadana', '4. Participa en la discusión y búsqueda de solución a los problemas y conflictos en el aula.', ARRAY['4.1. Aplica los aportes, las opiniones y los consejos que recibe, a la solución de problemas.', '4.2. Aplica técnicas comunicativas para afrontar conflictos y resolver problemas en el aula y en la escuela.']),
('Primer Grado', 'Formación Ciudadana', '5. Interpreta el presente de su comunidad con base en los hechos históricos, testimonios y actores destacados.', ARRAY['5.1. Identifica hechos históricos importantes de la comunidad.', '5.2. Identifica a los actores destacados de los hechos históricos de su comunidad.', '5.3. Identifica los lugares de importancia histórica de la comunidad.']);

-- ===== cnb_primaria_27.sql =====
-- CNB Primaria - Formación Ciudadana - Segundo Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Formación_Ciudadana_-_Segundo_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Grado', 'Formación Ciudadana', '1. Manifiesta autonomía, solidaridad y respeto en sus relaciones en el aula y en el hogar.', ARRAY['1.1. Emite juicios críticos de sus acciones y de las de los demás.', '1.2. Manifiesta su autoestima en las relaciones sociales.', '1.3. Manifiesta principios de autocontrol y autorregulación en sus relaciones con los y las demás.', '1.4. Demuestra principios de autonomía en sus relaciones.', '1.5. Fija las metas que pretende alcanzar.']),
('Segundo Grado', 'Formación Ciudadana', '2. Evidencia equidad y buen trato en sus relaciones interpersonales, étnicas e interétnicas en la familia, en la escuela y en su comunidad.', ARRAY['2.1. Demuestra buen trato en sus relaciones sociales.', '2.2. Participa en la promoción de los Derechos Humanos y de los derechos colectivos.', '2.3. Propone acciones personales y grupales para la vivencia del respeto y la solidaridad.']),
('Segundo Grado', 'Formación Ciudadana', '3. Participa responsablemente en la organización del aula y del hogar para propiciar la convivencia y el beneficio de todos.', ARRAY['3.1. Asume responsablemente sus compromisos y obligaciones en la familia y en la escuela.', '3.2. Reconoce los deberes y derechos de los miembros de la comunidad educativa.', '3.3. Propone alternativas de organización en el aula.', '3.4. Respeta el rol de las instituciones y autoridades locales.']),
('Segundo Grado', 'Formación Ciudadana', '4. Utiliza el diálogo y el consenso en situaciones donde se afrontan problemas y conflictos de la vida familiar y escolar.', ARRAY['4.1. Identifica las causas y efectos de problemas sociales.', '4.2. Utiliza el diálogo y el consenso para afrontar conflictos y en la solución de problemas.', '4.3. Utiliza los saberes y las experiencias de los adultos en la solución de conflictos.', '4.4. Valora las formas pacíficas y equitativas para afrontar problemas.', '4.5. Participa en la solución de problemas donde todos ganen.']),
('Segundo Grado', 'Formación Ciudadana', '5. Asocia hechos históricos de su comunidad con los del municipio, reconociendo a sus actores destacados y sus efectos en la vida actual y futura.', ARRAY['5.1. Describe costumbres, tradiciones y los centros culturales del municipio.', '5.2. Ubica los grupos étnicos coexistentes en el municipio.', '5.3. Relaciona los acontecimientos culturales e históricos del municipio con los de la comunidad.', '5.4. Reconoce su papel protagónico en el mejoramiento de la calidad de vida personal y familiar.', '5.5. Identifica los diferentes símbolos y signos presentes en su entorno.']);

-- ===== cnb_primaria_28.sql =====
-- CNB Primaria - Formación Ciudadana - Tercer Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Formación_Ciudadana_-_Tercer_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercer Grado', 'Formación Ciudadana', '1. Manifiesta autonomía, solidaridad, respeto y liderazgo en sus relaciones con su familia y en la escuela.', ARRAY['1.1. Manifiesta autocontrol en sus acciones para sostener buenas relaciones con los demás.', '1.2. Utiliza sus habilidades de liderazgo en el trabajo de grupo.']),
('Tercer Grado', 'Formación Ciudadana', '2. Convive de manera solidaria, respetuosa y tolerante en espacios donde comparten la diversidad de género, de etnias y de clases sociales.', ARRAY['2.1. Identifica los derechos de todo grupo étnico.', '2.2. Participa en actividades de mejoramiento comunitario.', '2.3. Se identifica con orgullo con su cultura y grupo étnico.']),
('Tercer Grado', 'Formación Ciudadana', '3. Participa, democráticamente, en la organización de actividades de estudio, recreativas y culturales impulsadas en el aula por el gobierno escolar para una cultura de paz.', ARRAY['3.1. Identifica las tareas y roles de los miembros de la familia, de la escuela y otras instituciones para el desarrollo de la comunidad.', '3.2. Cumple con las normas y compromisos de convivencia establecidos.']),
('Tercer Grado', 'Formación Ciudadana', '4. Propone soluciones para afrontar problemas y conflictos en la vida familiar y escolar a partir de principios interculturales y democráticos.', ARRAY['4.1. Identifica las causas y efectos de problemas inmediatos.', '4.2. Utiliza el diálogo y el consenso en la solución de problemas.', '4.3. Utiliza los saberes y las experiencias de los adultos con la solución de conflictos.', '4.4. Identifica las instancias institucionales y su papel en la solución de conflictos.']),
('Tercer Grado', 'Formación Ciudadana', '5. Relaciona los diferentes hechos históricos de su departamento, reconociendo a sus actores destacados y sus efectos en la vida actual y futura.', ARRAY['5.1. Identifica costumbres, tradiciones y centros culturales del departamento.', '5.2. Participa en forma protagónica en el mejoramiento de la calidad de vida personal, familiar y comunitaria.', '5.3. Identifica los símbolos por sus características y representatividad.']);

-- ===== cnb_primaria_29.sql =====
-- CNB Primaria - Formación Ciudadana - Cuarto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Formación_Ciudadana_-_Cuarto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Cuarto Grado', 'Formación Ciudadana', '1. Demuestra actitudes basadas en principios de convivencia solidaria y respetuosa, en los diferentes ámbitos en los que se desenvuelve.', ARRAY['1.1. Comparte experiencias en el marco de la cultura de paz en diferentes espacios.', '1.2. Rechaza las expresiones, actitudes y comportamientos de la cultura de violencia.', '1.3. Promueve acciones y actitudes a favor de vivir los Derechos Humanos colectivos.', '1.4. Identifica la importancia de vivir los Derechos Humanos de poblaciones específicas.', '1.5. Formula perfiles del ciudadano(a) que fortalecen la convivencia democrática y la cultura de paz.']),
('Cuarto Grado', 'Formación Ciudadana', '2. Participa en la construcción de relaciones justas enmarcadas en la equidad y la solidaridad para mejorar la calidad de vida de todos y todas.', ARRAY['2.1. Participa solidariamente en el trabajo con grupos heterogéneos.', '2.2. Evalúa situaciones para construir soluciones justas y solidarias.', '2.3. Propicia una relación armoniosa en contextos plurales.', '2.4. Practica normas de conducta y de convivencia social en el marco de la cultura de paz, sustentada en el respeto, la equidad y la justicia social.', '2.5. Practica procesos que favorecen las relaciones simétricas.', '2.6. Redacta ensayos sobre las consecuencias negativas de la exclusión y la discriminación en diversos espacios sociales.']),
('Cuarto Grado', 'Formación Ciudadana', '3. Describe las funciones que realizan personas y organizaciones a favor de la democracia y la ciudadanía.', ARRAY['3.2. Debate sobre las diferentes formas de organización y liderazgo.', '3.3. Revisa el desempeño de dirigentes democráticos y autoritarios en la historia del país y sus consecuencias.', '3.4. Valora la equidad y solidaridad presentes en la familia, en la escuela y la comunidad local.', '3.5. Examina el estilo del poder local como elemento que puede favorecer la democracia o el autoritarismo.']),
('Cuarto Grado', 'Formación Ciudadana', '4. Propone formas solidarias de solución a las desigualdades e intereses presentes en los problemas y conflictos que analiza.', ARRAY['4.1. Propone soluciones a problemas y conflictos cotidianos.', '4.2. Argumenta el papel de las relaciones desiguales en los conflictos.', '4.3. Propone soluciones cooperativas para afrontar conflictos.', '4.4. Comenta las actitudes y comportamientos que agudizan los conflictos.', '4.5. Comparte las lecciones aprendidas en la guerra y el proceso de paz.', '4.6. Comenta los principales hechos de la guerra e identifica a los sectores más afectados por la misma.', '4.7. Compara la sociedad actual con la sociedad que se plantea en los Acuerdos de Paz.']),
('Cuarto Grado', 'Formación Ciudadana', '5. Critica los hechos y procesos históricos que han aportado a la construcción de la democracia.', ARRAY['5.1. Comenta los efectos de hechos históricos en la construcción social de la localidad y de la nación.', '5.2. Describe el papel de organizaciones y movimientos sociales en la construcción de una sociedad democrática y pacífica.', '5.3. Comenta las influencias culturales presentes en Guatemala.', '5.4. Explica las consecuencias culturales del colonialismo.', '5.5. Practica la interculturalidad como forma de vida en sus relaciones cotidianas.']);

-- ===== cnb_primaria_30.sql =====
-- CNB Primaria - Formación Ciudadana - Quinto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Formación_Ciudadana_-_Quinto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Quinto Grado', 'Formación Ciudadana', '1. Participa en acciones orientadas al ejercicio de los Derechos Humanos y a la construcción de una cultura de paz en la familia, en la comunidad y en el país.', ARRAY['1.1. Argumenta la necesidad de practicar actitudes y comportamientos de la cultura de paz en las interacciones que se dan en diversos espacios.', '1.2. Redacta ensayos sobre las consecuencias políticas que provoca en personas, los grupos sociales y pueblos, el no gozar de sus derechos.', '1.3. Identifica condiciones, obstáculos y riesgos que limitan la participación social.', '1.4. Identifica situaciones de riesgo que limitan la vivencia de los derechos humanos de niños y niñas en la familia, la comunidad y el país.', '1.5. Relaciona la vulnerabilidad personal y grupal con los contextos de riesgo en los espacios ocupacionales urbanos y rurales.', '1.6. Argumenta propuestas de solución a casos de niños, niñas y jóvenes de Guatemala que sufren hambre y desnutrición.']),
('Quinto Grado', 'Formación Ciudadana', '2. Propone formas de superar las relaciones de desigualdad, de explotación y marginación presentes en la cotidianidad.', ARRAY['2.1. Manifiesta comportamientos que favorecen la equidad.', '2.2. Expresa capacidad de reaccionar éticamente ante los estereotipos y prejuicios.', '2.3. Identifica la discriminación sexista, de género, etnocéntrica y el racismo.', '2.4. Comenta sobre la situación y vigencia de los derechos humanos y la equidad en población en riesgo: migrantes, mujeres, niñas.', '2.5. Participa en observación de situaciones en las que las asimetrías se traducen en desigualdad social.', '2.6. Emite juicios sobre las causas sociales y culturales de la desigualdad y sus manifestaciones.', '2.7. Identifica las recomendaciones de los acuerdos de paz en relación con el racismo y la discriminación étnica y de género.']),
('Quinto Grado', 'Formación Ciudadana', '3. Fomenta prácticas democráticas en el ejercicio del liderazgo y en la organización de una ciudadanía participativa.', ARRAY['3.1. Manifiesta actitudes y prácticas de liderazgo democrático.', '3.2. Identifica los estilos de gestión de los líderes religiosos, cívicos, políticos y de las instituciones en el país.', '3.3. Discute sobre los principios fundamentales de la Constitución Política de la República en relación con los derechos y obligaciones ciudadanas del guatemalteco.', '3.4. Identifica organizaciones, instituciones y líderes que trabajan a favor de los Derechos Humanos, la Cultura de Paz y la Ciudadanía.', '3.5. Identifica el papel que han desempeñado en la historia del país hombres y mujeres notables.']),
('Quinto Grado', 'Formación Ciudadana', '4. Participa en la negociación y el diálogo orientados hacia la prevención y transformación de los conflictos.', ARRAY['4.1. Identifica el papel del mediador(a) en las dramatizaciones de hechos de conflictividad.', '4.2. Comenta sobre indagaciones realizadas acerca de las problemáticas de la niñez y la juventud en relación con el uso y manejo de drogas, en la escuela y la comunidad.', '4.3. Describe los procesos centroamericanos de negociación y los acuerdos de paz en el marco de la necesidad de prevenir y transformar los conflictos.', '4.4. Expone las razones de los conflictos identificados y las consecuencias de las diversas formas de afrontarlos.', '4.5. Comenta sobre las diversas formas en que fueron afectadas las poblaciones por el conflicto armado interno.']),
('Quinto Grado', 'Formación Ciudadana', '5. Demuestra una actitud crítica ante hechos históricos y sus consecuencias en el presente que inciden en el futuro.', ARRAY['5.1. Explica con sentido crítico diversos hechos históricos significativos y los relaciona con las modalidades de desarrollo político y social.', '5.2. Participa con entusiasmo y responsabilidad, en conmemoraciones que se organizan en la escuela.', '5.3. Explica con sentido crítico las consecuencias de los intercambios económicos y culturales en América Latina.', '5.4. Describe el rumbo de los actuales procesos de transculturación en un contexto globalizado de múltiples migraciones e influenciado por los medios de comunicación.', '5.5. Opina críticamente sobre el papel que cumplen los medios en la formación de opinión pública.']);

-- ===== cnb_primaria_31.sql =====
-- CNB Primaria - Formación Ciudadana - Sexto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Formación_Ciudadana_-_Sexto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Sexto Grado', 'Formación Ciudadana', '1. Participa en relaciones sociales que inciden en los derechos y responsabilidades necesarias para una cultura de paz en el contexto nacional e internacional.', ARRAY['1.1. Expresa solidaridad en el espacio escolar, en la familia y la comunidad.', '1.2. Defiende los Derechos Humanos relacionados con el bienestar de las personas y en favor del desarrollo social.', '1.3. Identifica las relaciones sociales de calidad en contextos de diversidad.']),
('Sexto Grado', 'Formación Ciudadana', '2. Fomenta actitudes y acciones orientadas a erradicar la discriminación y exclusión para fortalecer la solidaridad y las culturas de los pueblos.', ARRAY['2.1. Identifica en los acuerdos de paz, las recomendaciones orientadas a erradicar la exclusión y discriminación de la mujer y de los pueblos indígenas.', '2.2. Describe las causas socioeconómicas, culturales y políticas de las asimetrías y la desigualdad.', '2.3. Describe los beneficios de la equidad, tolerancia y cooperación en una sociedad democrática.', '2.4. Identifica los artículos constitucionales que garantizan sus derechos y obligaciones, así como el funcionamiento de las entidades del Estado.', '2.5. Emite juicios acerca de falacias y estereotipos orientados a desarrollar sentimientos de intolerancia, de culpa e inferioridad.']),
('Sexto Grado', 'Formación Ciudadana', '3. Formula proyectos y realizaciones orientadas a favor del ejercicio de la ciudadanía y la democracia en la familia, la comunidad y el país.', ARRAY['3.1. Describe las características del liderazgo y la gestión democrática y autoritaria.', '3.2. Participa democrática y propositivamente en el gobierno estudiantil y la organización del aula.', '3.3. Describe la diversidad de acciones con las que se ejerce ciudadanía.', '3.4. Describe el papel y nivel de desempeño de las instituciones del sistema democrático.', '3.5. Explica el funcionamiento de las instituciones democráticas: del Estado y de la sociedad civil.', '3.6. Describe los derechos y las responsabilidades sociales que tienen los ciudadanos con su persona, su familia, con las instituciones sociales y el país.']),
('Sexto Grado', 'Formación Ciudadana', '4. Promueve acciones para fortalecer la existencia de actitudes y prácticas de cultura de paz en diferentes espacios y situaciones de la vida grupal.', ARRAY['4.1. Valora la ciudadanía cimentada en una cultura de paz.', '4.2. Describe la presencia de la cultura de violencia en su espacio inmediato.', '4.3. Formula propuestas orientadas a transformar y controlar de manera constructiva los conflictos.', '4.4. Identifica los factores sociales y culturales que favorecen la conflictividad y la violencia.', '4.5. Examina el contenido y comenta los propósitos de cada una de las recomendaciones de los informes REMHI y de la CEH.']),
('Sexto Grado', 'Formación Ciudadana', '5. Planifica el futuro personal y comunitario a partir del análisis crítico del pasado y del presente.', ARRAY['5.1. Comenta acerca de los daños ocasionados por las guerras y elabora propuestas para reducir su incidencia.', '5.2. Construye un mapa de los pueblos y departamentos que fueron más afectados por la violencia.']);

-- ===== cnb_primaria_32.sql =====
-- CNB Primaria - Productividad y Desarrollo - Cuarto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Productividad_y_Desarrollo_-_Cuarto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Cuarto Grado', 'Productividad y Desarrollo', '1. Utiliza información, de diferentes fuentes, que le facilita encontrar respuestas a su curiosidad natural y a la comprensión de su entorno.', ARRAY['1.1. Ejecuta diferentes formas de recopilar información, a partir de las fuentes que tiene a su alcance.', '1.2. Registra aspectos, en forma oral y escrita, derivados de la observación y de la información.', '1.3. Elabora informes escritos o representaciones de la información recopilada.', '1.4. Participa activa y respetuosamente, en el equipo de trabajo.']),
('Cuarto Grado', 'Productividad y Desarrollo', '2. Utiliza la comunicación como elemento facilitador del logro de calidad en sus producciones personales.', ARRAY['2.1. Explica la importancia de respetar normas y aplicarlas, así como de tener presente parámetros para el logro de resultados con calidad.', '2.2. Participa en actividades de retroalimentación en función de mejorar procesos y resultados.', '2.3. Explica cuando menos tres formas de mejorar la relación cliente-proveedor.', '2.4. Valora la comunicación como un elemento clave para obtener calidad en distintas creaciones personales y colectivas.']),
('Cuarto Grado', 'Productividad y Desarrollo', '3. Identifica la presencia de tecnología como alternativa innovadora para la solución de problemas de su entorno inmediato.', ARRAY['3.1. Utiliza los recursos a su alcance para la satisfacción de necesidades que se le presentan en su vida cotidiana.', '3.2. Utiliza los elementos tecnológicos materiales e intelectuales propios de la familia y comunidad en acciones de la vida cotidiana.', '3.3. Promueve la divulgación de información de peligros en el uso de herramientas y máquinas.', '3.4. Propone opciones que permiten el uso de tecnología en la solución de problemas.']),
('Cuarto Grado', 'Productividad y Desarrollo', '4. Relaciona las actividades productivas y de servicio con el desarrollo de su comunidad.', ARRAY['4.1. Utiliza los recursos a su alcance para satisfacer sus necesidades y superar las dificultades que se le presentan en su vida cotidiana.', '4.2. Diferencia entre demanda y oferta; entre competencia y red de apoyo.', '4.3. Describe cómo las actividades económicas se relacionan con la vida de las personas de la comunidad.', '4.4. Diferencia los productos y servicios que se generan en su comunidad de los que provienen de otras.']),
('Cuarto Grado', 'Productividad y Desarrollo', '5. Participa en actividades orientadas a la búsqueda de soluciones a problemas de su entorno inmediato.', ARRAY['5.1. Propone diversas opciones de solución a los problemas de contaminación en el centro educativo y en su entorno.', '5.2. Explica la importancia del medio ambiente, su protección, rescate y conservación.', '5.3. Participa en actividades de protección, conservación y rescate de los recursos naturales y culturales de su entorno.']);

-- ===== cnb_primaria_33.sql =====
-- CNB Primaria - Productividad y Desarrollo - Quinto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Productividad_y_Desarrollo_-_Quinto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Quinto Grado', 'Productividad y Desarrollo', '1. Relaciona hechos históricos con la situación actual de la vida de la comunidad atendiendo los aspectos socioculturales, económicos y naturales.', ARRAY['1.1. Narra, en su idioma materno los hechos históricos de la comunidad y el origen de las familias.', '1.2. Compara las características emprendedoras con su forma de actuar ante las situaciones de su vida cotidiana.', '1.3. Emite juicios valorativos ante los aportes de los distintos trabajos, oficios y profesiones que se desempeñan en la comunidad.']),
('Quinto Grado', 'Productividad y Desarrollo', '2. Utiliza, sistemáticamente, controles en el proceso permanente de mejora de la calidad en los resultados de sus actividades productivas.', ARRAY['2.1. Explica qué es la evaluación y cómo se puede aplicar en la búsqueda de la calidad.', '2.2. Aplica controles de calidad durante un proceso productivo o la prestación de un servicio.', '2.3. Presenta sugerencias de cómo mejorar un servicio escolar (tienda) o la organización de alguna actividad de carácter extraescolar.']),
('Quinto Grado', 'Productividad y Desarrollo', '3. Aplica los principios de la ciencia y la tecnología relacionados con los saberes de su cultura, en la realización de actividades productivas.', ARRAY['3.1. Maneja en forma adecuada las herramientas, utensilios y máquinas sencillas.', '3.2. Describe las relaciones entre los principios científicos y los tipos de tecnología existentes en el entorno.', '3.3. Propone eventuales innovaciones en el uso de la tecnología existente en la comunidad.', '3.4. Construye máquinas y herramientas sencillas de acuerdo con los principios discutidos en clase.']),
('Quinto Grado', 'Productividad y Desarrollo', '4. Desarrolla actividades que mejoran su preparación técnica o académica y que impulsan el desarrollo de su comunidad.', ARRAY['4.1. Describe las fuentes de ocupación laboral existentes en su comunidad.', '4.2. Describe las diferencias, ventajas y desventajas del trabajo como auto empleado (empresario) y del trabajo como dependiente.', '4.3. Clasifica posibles actividades económicas que podrían desarrollarse en la comunidad.', '4.4. Describe las características de personas emprendedoras.', '4.5. Construye, en forma sencilla, un proyecto de vida.', '4.6. Identifica actividades económicas en las que puede desempeñarse laboralmente.']),
('Quinto Grado', 'Productividad y Desarrollo', '5. Impulsa el desarrollo sustentable de su cultura y de la comunidad.', ARRAY['5.1. Participa en la reforestación y limpieza de fuentes de agua cercanas a su comunidad.', '5.2. Promueve entre los vecinos de la comunidad, estrategias para evitar el deterioro ambiental.', '5.3. Comparte principios básicos de su cultura para apoyar el desarrollo de la comunidad.', '5.4. Participa en campañas que promueven la detección de fuentes de financiamiento y acompañamiento en proyectos de desarrollo.', '5.5. Emite opiniones con respecto a la utilización de los ingresos en beneficio de la comunidad.']);

-- ===== cnb_primaria_34.sql =====
-- CNB Primaria - Productividad y Desarrollo - Sexto Grado
-- Fuente: .../Dosificación_de_los_aprendizajes_-_Área_de_Productividad_y_Desarrollo_-_Sexto_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Sexto Grado', 'Productividad y Desarrollo', '1. Plantea opciones de solución a problemas que inciden en las situaciones críticas de la comunidad, a partir de la información disponible.', ARRAY['1.1. Argumenta sobre interrelaciones ambientales, históricas y económicas que la comunidad debe dominar.', '1.2. Plantea ampliaciones e innovaciones que pueden empezar a registrarse para mejorar la información que recopilan en su centro educativo.', '1.3. Utiliza la información que está aportando su grupo al centro de documentación de la escuela como parte de la historia de su vida y del centro educativo.', '1.4. Realiza comparaciones de la economía familiar con relación a los recursos naturales.']),
('Sexto Grado', 'Productividad y Desarrollo', '2. Establece la relación entre la aplicación de medios de investigación social y los métodos de resolución de problemas para la mejora permanente de su entorno inmediato.', ARRAY['2.1. Explica problemas sociales que afectan a su comunidad y ofrece posibles alternativas de solución.', '2.2. Describe técnicas para realizar investigaciones de carácter social en su comunidad.', '2.3. Participa en círculos de calidad para buscar alternativas de solución a problemas identificados en el aula, la escuela y la comunidad.', '2.4. Diseña su proyecto de vida.', '2.5. Participa en actividades en pro de la mejora de la calidad de vida de los habitantes de su comunidad.']),
('Sexto Grado', 'Productividad y Desarrollo', '3. Describe los beneficios generados por el uso de la tecnología para el desarrollo de los Pueblos de Guatemala y el cuidado del medio ambiente.', ARRAY['3.1. Describe cómo la investigación científica aporta a la tecnología.', '3.2. Investiga la importancia de la tecnología que emplean las diferentes culturas.', '3.3. Deduce los beneficios de la aplicación de las tecnologías locales y familiares.', '3.4. Explica los principales riesgos para el medio ambiente derivados de las actividades humanas.']),
('Sexto Grado', 'Productividad y Desarrollo', '4. Ejecuta actividades orientadas a innovar procesos productivos y de servicio en la comunidad.', ARRAY['4.1. Propone un proyecto a ser ejecutado en la escuela y uno a ser ejecutado en la comunidad.', '4.2. Se manifiesta con técnicas de análisis de procesos (FODA).', '4.3. Diseña un proyecto productivo o de servicios, de manera individual o en grupo.']),
('Sexto Grado', 'Productividad y Desarrollo', '5. Participa en equipos comunitarios que promueven el rescate y la protección de los bienes naturales de su entorno.', ARRAY['5.1. Comparte información sobre lugares, fechas y resultados de las cumbres sobre medio ambiente.', '5.2. Identifica los ecosistemas que sostienen la vida en su comunidad.', '5.3. Contrasta la teoría con las pláticas realizadas sobre aspectos relacionados con el tema medio ambiental.', '5.4. Realiza propuestas de planificación del desarrollo económico en forma compatible con los recursos naturales.']);

-- ===== cnb_basico_1.sql =====
-- CNB Ciclo Básico - Comunicación y Lenguaje Idioma Español - Primer Básico
INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Comunicación y Lenguaje L1', 'Competencia 1: Se comunica en forma oral, atendiendo a las intenciones, la situación comunicativa, sus recursos expresivos, entre otros.', ARRAY['1.1 Infiere el significado del mensaje tomando en cuenta el contexto, las intenciones del emisor y sus propios propósitos de escucha.', '1.2. Controla la eficacia de la propia comunicación y la modifica al saber repetir, ampliar, parafrasear el mensaje o utilizar otro tipo de registro lingüístico.', '1.3. Muestra empatía hacia su interlocutor y su mensaje, con relación al sentido, finalidades del discurso, punto de vista.']),
('Primero Básico', 'Comunicación y Lenguaje L1', 'Competencia 2: Desarrolla habilidades de entendimiento, comprensión e interpretación de lo que lee.', ARRAY['2.1. Regula su fluidez lectora, según el tipo de texto.', '2.2. Desarrolla habilidades de comprensión.', '2.3. Lee con placer obras literarias, especialmente de autores guatemaltecos.']),
('Primero Básico', 'Comunicación y Lenguaje L1', 'Competencia 3: Redacta textos en forma autónoma, según las distintas intenciones y situaciones comunicativas.', ARRAY['3.1. Escribe textos claros y precisos, teniendo en cuenta las fases de la redacción.', '3.2. Redacta textos apegados a la gramática del idioma.', '3.3 Valora la precisión y corrección en lo que escribe y publica.']);

-- ===== cnb_basico_2.sql =====
-- CNB Ciclo Básico - Comunicación y Lenguaje Idioma Español - Segundo y Tercero Básico
INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Comunicación y Lenguaje L1', 'Competencia 1: Participa en diversas situaciones comunicativas, formales y no formales, con claridad, precisión, concisión y con efectividad.', ARRAY['1.1. Establece estrategias para inferir el significado de mensajes complejos, de distintos contextos orales - cotidianos, educativos y otros.', '1.2. Establece los pasos necesarios para que su mensaje sea coherente, cohesionado y adecuado.', '1.3. Interactúa en forma reflexiva y asertiva.']),
('Segundo Básico', 'Comunicación y Lenguaje L1', 'Competencia 2: Mejora sus habilidades de entendimiento, comprensión e interpretación de lo que lee.', ARRAY['2.1. Mejora su fluidez lectora, según el tipo de texto.', '2.2. Aplica un plan estratégico para corregir y aumentar su comprensión inferencial.', '2.3. Lee con autonomía y placer principalmente obras literarias de autores hispanoamericanos.']),
('Segundo Básico', 'Comunicación y Lenguaje L1', 'Competencia 3: Redacta textos en forma clara, concisa, sencilla, organizada y adecuada al contexto y a la intencionalidad.', ARRAY['3.1. Escribe textos adecuados, claros, concisos, sencillos y organizados, teniendo en cuenta las fases de la redacción.', '3.2. Resuelve problemas gramaticales, para que su texto sea correcto y lingüísticamente comprensible.', '3.3 Corrige y mejora constantemente la precisión y corrección en lo que redacta y publica.']),
('Tercero Básico', 'Comunicación y Lenguaje L1', 'Competencia 1: En forma autónoma, participa en forma fluida y eficiente en diversas situaciones comunicativas, con un objetivo preciso, en forma clara, concisa, secuencial y coherente.', ARRAY['1.1. Infiere el significado de la información y argumentos válidos o útiles, en distintos contextos orales en los que participa: informales y formales, coloquiales, publicitarios y científicos.', '1.2. Controla la objetividad del mensaje que expone, controlando la adecuación, coherencia y cohesión, así como su propia opinión.', '1.3. Aplica estrategias para tomar decisiones asertivas acerca de lo que escucha o dice.']),
('Tercero Básico', 'Comunicación y Lenguaje L1', 'Competencia 2: Practica con autonomía sus habilidades de entendimiento, comprensión e interpretación de lo que lee.', ARRAY['2.1. Lee textos digitales con fluidez.', '2.2. Utiliza sus habilidades de comprensión lectora en distintos textos, incluidos los digitales.', '2.3. Lee con autonomía y placer especialmente obras literarias de autores de la literatura universal.']),
('Tercero Básico', 'Comunicación y Lenguaje L1', 'Competencia 3: Redacta textos con autonomía, con claridad, concisión, sencillez, organización, cohesión, coherencia y adecuación, según el contexto y la intencionalidad.', ARRAY['3.1. Escribe textos en forma autónoma, coherentes, cohesionados y adecuados, teniendo en cuenta las fases de la redacción.', '3.2. Redacta textos gramaticalmente correctos.', '3.3. Realiza en forma autónoma, las correcciones ortográficas para dar precisión y claridad a lo que redacta y publica.']);

-- ===== cnb_basico_3.sql =====
-- CNB Ciclo Básico - Comunicación y Lenguaje Idioma Extranjero (Inglés / L3) - 1ro, 2do, 3ro Básico
INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 1: Responds to basic oral instructions given in English at school.', ARRAY['1.1. Distinguishes the meaning of words and phrases related to daily school life.', '1.2. Understands specific phrases related to everyday activities at school.', '1.3. Follows responsibly common directions given orally by the teacher.']),
('Primero Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 2: Answers orally to simple directions, questions and gives basic information by using specific topics framed at school and family.', ARRAY['2.1. Begins to use appropriately polite social language and basic vocabulary with classmates.', '2.2. Asks and answers respectfully basic questions about needed information.', '2.3. Provides information orally about very specific phrases.']),
('Primero Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 3: Reads aloud and silently: syllables, common words and phrases in English.', ARRAY['3.1. Pronounces common words and phrases when reading.', '3.2. Recognizes the meaning of common words and phrases in his readings.', '3.3. Analyzes the meaning of common words and phrases when reading.']),
('Primero Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 4: Writes words and simple phrases and sentences in the new language with the right spelling and grammar structure to be applied in daily life situations.', ARRAY['4.1. Writes words with accurate spelling.', '4.2. Writes phrases with the right grammar structure.', '4.3. Creates simple phrases valuing his own culture and context.']),
('Segundo Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 1: Understands simple phrases and specific range of vocabulary concerning to known topics in short dialogues and oral sentences.', ARRAY['1.1. Distinguishes the meaning of basic vocabulary concerning to familiar topics.', '1.2. Responds to greetings, farewells and apologies appropriately.', '1.3. Understands sentences about known topics.']),
('Segundo Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 2: Communicates ideas using familiar phrases, everyday expressions and structured ideas by means of speeches.', ARRAY['2.1. Gives information about familiar topics and personal experiences using basic connectors, phrases and simple sentences.', '2.2. Asks and answers basic questions about familiar topics using simple tenses.', '2.3. Builds short speeches about his context or basic topics.']),
('Segundo Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 3: Reads simple sentences in a given text about his daily life matters.', ARRAY['3.1. Pronounces properly simple sentences in readings related to daily life matters.', '3.2. Makes inferences about the meaning of simple sentences.', '3.3. Explains by different ways the meaning of very simple sentences.']),
('Segundo Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 4: Writes simple sentences and descriptions of his environment by using basic terms.', ARRAY['4.1. Writes sentences according to the right grammar structure.', '4.2. Interprets the several meanings of a text.', '4.3. Creates different kind of descriptions using basic terms.']),
('Tercero Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 1: Understands basic sentences in simple and compound tenses.', ARRAY['1.1. Responds to sequence main ideas or events given in classroom.', '1.2. Deduces the meaning of basic conversations of known topics.', '1.3. Compares grammar structure of simple and compound tenses.']),
('Tercero Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 2: Expresses ideas and opinions orally, related to relevant topics through simple sentences.', ARRAY['2.1. Makes oral presentations about familiar topics and personal experiences.', '2.2. Asks and answers basic questions about different topics using compound tenses.', '2.3. Shares information about different topics in several contexts.']),
('Tercero Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 3: Reads very basic texts concerning the immediate environment and background.', ARRAY['3.1. Finds specific information in short and everyday readings.', '3.2. Makes inferences about the meaning of very basic texts.', '3.3. Analyzes the primarily intention of very basic texts.']),
('Tercero Básico', 'Comunicación y Lenguaje L3 (Idioma Extranjero)', 'Competence 4: Produces simple narrations in a written form with an appropriate grammatical structure and accurate spelling on a variety of topics.', ARRAY['4.1. Writes narrations about different topics of the context.', '4.2. Applies different grammar rules in writing.', '4.3. Creates own narrations taking into account accurate spelling.']);

-- ===== cnb_basico_4.sql =====
-- CNB Ciclo Básico - Matemática - Primer Grado
-- Fuente: .../CNB_Ciclo_Básico/Matemática/Malla_curricular_Primer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Matemática', '1. Identifica elementos comunes en patrones algebraicos y geométricos.', ARRAY['1.1 Representa información cuantitativa generalizada a partir de variables.', '1.2 Reconoce figuras, relaciones, propiedades y medidas en diseños propuestos.', '1.3 Calcula áreas y perímetros de polígonos regulares.']),
('Primero Básico', 'Matemática', '2. Utiliza gráficas y símbolos en la representación de información y solución de problemas.', ARRAY['2.1 Construye proposiciones compuestas usando conectivos lógicos.', '2.2 Representa de forma simbólica y gráfica las relaciones entre variables.', '2.3 Distingue entre relaciones y funciones.', '2.4 Aplica ecuaciones de primer grado en la resolución de problemas.']),
('Primero Básico', 'Matemática', '3. Calcula operaciones combinadas de los diferentes conjuntos numéricos (naturales, enteros y racionales) con algoritmos escritos, mentales, exactos y aproximados.', ARRAY['3.1 Opera dentro de los conjuntos numéricos naturales y enteros, mediante procedimientos correspondientes.', '3.2 Identifica la representación y ubicación del conjunto de los racionales al realizar operaciones jerarquizadas y estimaciones.', '3.3 Aplica razones y proporciones al resolver problemas.']),
('Primero Básico', 'Matemática', '4. Interpreta información estadística representada en tablas, esquemas y gráficos.', ARRAY['4.1 Aplica procedimientos estadísticos y medidas de tendencia central para datos no agrupados.', '4.2 Tabula datos sin agrupar para representarlos y determinar su frecuencia.', '4.3 Grafica polígonos de frecuencias e histogramas que representan los datos.']),
('Primero Básico', 'Matemática', '5. Establece estrategias variadas al resolver problemas que surgen del contexto para matematizarlos.', ARRAY['5.1 Relaciona los sistemas de medidas para calcular sus equivalencias.', '5.2 Reconoce la función del universo, tiempo y espacio con enfoque cultural.', '5.3 Identifica patrones y características del sistema vigesimal.']);

-- ===== cnb_basico_5.sql =====
-- CNB Ciclo Básico - Matemática - Segundo Grado
-- Fuente: .../CNB_Ciclo_Básico/Matemática/Malla_curricular_Segundo_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Matemática', '1. Resuelve problemas utilizando las relaciones y propiedades entre patrones algebraicos, geométricos y trigonométricos.', ARRAY['1.1. Opera polinomios al realizar suma, resta, multiplicación y división.', '1.2. Aplica relaciones geométricas en la resolución de problemas.', '1.3. Resuelve problemas en los que se involucran propiedades y relaciones de los triángulos.']),
('Segundo Básico', 'Matemática', '2. Resuelve problemas utilizando modelos matemáticos en la representación y comunicación de resultados.', ARRAY['2.1. Representa información estructurada a partir de los elementos de la lógica matemática.', '2.2. Grafica relaciones y funciones lineales en el plano cartesiano.', '2.3. Aplica la función lineal en la solución de problemas.', '2.4. Utiliza ecuaciones y desigualdades de primer grado en la representación y solución de problemas.']),
('Segundo Básico', 'Matemática', '3. Resuelve problemas al aplicar las propiedades de los conjuntos numéricos.', ARRAY['3.1. Representa los conjuntos numéricos en diagramas según sus características.', '3.2. Realiza operaciones en los conjuntos numéricos aplicando la jerarquía.', '3.3. Aplica sucesiones aritméticas y geométricas en la solución de problemas.']),
('Segundo Básico', 'Matemática', '4. Utiliza métodos estadísticos en el análisis y representación de información.', ARRAY['4.1. Interpreta las medidas de tendencia central en datos agrupados.', '4.2. Interpreta las medidas de posición en datos agrupados.', '4.3. Calcula la probabilidad simple en la ocurrencia de eventos.']),
('Segundo Básico', 'Matemática', '5. Traduce información que obtiene de su entorno a lenguaje lógico simbólico.', ARRAY['5.1. Determina las características de los sistemas de numeración posicional.', '5.2. Relaciona la cosmovisión maya en el contexto del tiempo y la persona.', '5.3. Relaciona patrones del contexto con el pensamiento ancestral.']);

-- ===== cnb_basico_6.sql =====
-- CNB Ciclo Básico - Matemática - Tercer Grado
-- Fuente: .../CNB_Ciclo_Básico/Matemática/Malla_curricular_Tercer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Matemática', '1. Construye patrones aritméticos, algebraicos y geométricos, aplicando propiedades y relaciones en la solución de problemas.', ARRAY['1.1. Aplica la factorización de polinomios al simplificar fracciones y expresiones algebraicas.', '1.2. Resuelve problemas que involucran el cálculo de medidas y la aplicación de propiedades de figuras planas y cuerpos sólidos.', '1.3. Utiliza teoremas relacionados con triángulos obtusángulos en la solución de problemas.']),
('Tercero Básico', 'Matemática', '2. Construye modelos matemáticos para el análisis y representación de las relaciones.', ARRAY['2.1. Emite juicios argumentando procedimientos y resultados.', '2.2. Resuelve problemas aplicando la teoría de conjuntos.', '2.3. Utiliza funciones para representar y resolver problemas.', '2.4. Utiliza diferentes métodos en la resolución de ecuaciones, inecuaciones y sistemas de ecuaciones.']),
('Tercero Básico', 'Matemática', '3. Aplica las propiedades de las operaciones en los conjuntos numéricos reales y complejos.', ARRAY['3.1. Identifica las propiedades y sus relaciones en el conjunto de los números reales.', '3.2. Describe el conjunto de los números complejos y su relación con los números reales.', '3.3. Realiza operaciones entre el conjunto de los reales y los complejos.']),
('Tercero Básico', 'Matemática', '4. Resuelve problemas aplicando medidas de dispersión y probabilidad.', ARRAY['4.1. Identifica las medidas de dispersión en un conjunto de datos.', '4.2. Aplica la probabilidad de ocurrencia de eventos.', '4.3. Determina un espacio muestral a partir de combinaciones y permutaciones.']),
('Tercero Básico', 'Matemática', '5. Aplica métodos de razonamiento, el lenguaje y la simbología matemática en la interpretación de situaciones de su entorno.', ARRAY['5.1. Determina cantidades del sistema decimal y su relación con otros sistemas de diferentes bases.', '5.2. Interpreta las matemáticas de contexto a partir de su relación con el universo, el tiempo y el espacio.', '5.3. Usa los patrones relacionados con el pensamiento maya.']);

-- ===== cnb_basico_7.sql =====
-- CNB Ciclo Básico - Ciencias Naturales - Primer Grado
-- Fuente: .../CNB_Ciclo_Básico/Ciencias_Naturales/Malla_curricular_Primer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Ciencias Naturales', '1. Describe fenómenos naturales de su entorno y plantea conjeturas sobre posibles soluciones a problemas cotidianos, utilizando diferentes recursos tecnológicos.', ARRAY['1.1. Relaciona el conocimiento científico con los avances tecnológicos de las sociedades y las culturas.', '1.2. Comprueba hipótesis mediante la realización de experimentos guiados y presenta los resultados obtenidos.', '1.3. Expresa datos precisos a partir de la medición de magnitudes en su entorno.', '1.4. Utiliza diferentes tecnologías para satisfacer necesidades personales y colectivas.']),
('Primero Básico', 'Ciencias Naturales', '2. Describe la Tierra, la organización de la naturaleza y el uso sostenible de los bienes naturales, para el mantenimiento del equilibrio en los ecosistemas.', ARRAY['2.1. Identifica la estructura básica de la tierra y su interrelación con otros astros del Sistema Solar.', '2.2. Distingue diferentes fuentes de energía y otros bienes naturales del planeta, sus efectos y uso sostenible.', '2.3. Caracteriza los niveles de organización de la naturaleza, los flujos de materia y energía en el ecosistema, factores que alteran su equilibrio y las acciones para evitar su desequilibrio.', '2.4. Comunica acciones que favorecen el uso racional y la conservación de los bienes naturales y los servicios socio-ambientales.', '2.5. Identifica fenómenos naturales que son amenazas potenciales para la comunidad y el país y algunas medidas para su prevención.']),
('Primero Básico', 'Ciencias Naturales', '3. Describe el cuerpo humano y otros seres vivos, su organización, estructura y procesos básicos que le permitan valorar su complejidad y procurar su mantenimiento.', ARRAY['3.1. Describe la estructura y funciones de diferentes tipos de células.', '3.2. Distingue las funciones de las células de acuerdo con el tipo de tejido que conforman.', '3.3. Identifica las estructuras de los sistemas músculo-esquelético y sus funciones en el organismo.', '3.4. Establece la interrelación entre los aparatos digestivo y respiratorio con el sistema circulatorio.', '3.5. Describe la sexualidad, así como los derechos, responsabilidades y riesgos que esta conlleva.', '3.6. Describe las diversas formas en que el organismo excreta sus desechos.', '3.7. Explica cómo funcionan los sistemas de protección del cuerpo humano.', '3.8. Ejemplifica las medidas necesarias para cuidar de los aparatos y sistemas del cuerpo humano.']),
('Primero Básico', 'Ciencias Naturales', '4. Describe los procesos físicos, químicos y biológicos de la materia y la energía, para explicar los fenómenos que ocurren en su entorno.', ARRAY['4.1. Distingue las propiedades físicas y químicas de la materia en su entorno.', '4.2. Describe la composición subatómica de la materia.', '4.3. Describe la evolución del conocimiento de la mecánica en la historia y examina su relación con el desarrollo histórico y socioeconómico en el mundo.']);

-- ===== cnb_basico_8.sql =====
-- CNB Ciclo Básico - Ciencias Naturales - Segundo Grado
-- Fuente: .../CNB_Ciclo_Básico/Ciencias_Naturales/Malla_curricular_Segundo_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Ciencias Naturales', '1. Explica las causas de los fenómenos naturales de su entorno, recurriendo a los conceptos científicos y la tecnología, a fin de descartar o aceptar hipótesis.', ARRAY['1.1. Explica qué es la ciencia, su aplicación y cómo se relaciona con la tecnología, el arte, la religión, la cultura, la sociedad, y teorías del origen de la vida, desde las visiones de distintos pueblos en Guatemala y del mundo.', '1.2. Explica la importancia de la investigación científica y la divulgación de los proyectos de ciencia escolar.']),
('Segundo Básico', 'Ciencias Naturales', '2. Relaciona los recursos del planeta con sus procesos internos y la problemática ambiental, su potencial de amenaza y la gestión integral del riesgo para reducir la vulnerabilidad personal y local.', ARRAY['2.1. Discute acerca de las principales actividades humanas de impacto socioambiental y su influencia en los ecosistemas.', '2.2. Propone acciones concretas basadas en la legislación ambiental de Guatemala, para la preservación de los recursos naturales.', '2.3. Explica la influencia de la actividad humana en algunos fenómenos naturales, los efectos nocivos para el ambiente, las formas para contrarrestarlos y algunas medidas de adaptación y mitigación.', '2.4. Gestiona el riesgo a nivel local.']),
('Segundo Básico', 'Ciencias Naturales', '3. Explica la interrelación entre los sistemas del cuerpo humano y sus procesos biológicos para garantizar calidad de vida.', ARRAY['3.1. Explica cómo se relaciona el cuerpo humano con su entorno y su interior.', '3.2. Describe procesos y medidas vinculados con la reproducción y la sexualidad, a partir de la etapa del desarrollo que vive.', '3.3. Asume un estilo de vida saludable.', '3.4. Expone las posibilidades de obtener diferentes características en los descendientes y el posible origen de sus diferencias.', '3.5. Describe el proceso de evolución de las especies.', '3.6. Clasifica los organismos de acuerdo con las características establecidas en la taxonomía biológica, protegiendo la diversidad de seres vivos que lo rodean.']),
('Segundo Básico', 'Ciencias Naturales', '4. Aplica conceptos, principios y propiedades de la materia y la energía para explicar los fenómenos que ocurren en su medio.', ARRAY['4.1. Describe la organización y características representadas en la Tabla periódica de los elementos.', '4.2. Explica la mecánica de formación de compuestos binarios y los nombra utilizando el sistema clásico o funcional.', '4.3. Utiliza vectores para representar conceptos básicos de la cinemática traslacional, en una y dos dimensiones.', '4.4. Describe el movimiento de una partícula, en una y dos dimensiones.', '4.5. Relaciona las gráficas de posición y velocidad versus tiempo con las ecuaciones matemáticas para movimiento con velocidad constante.']);

-- ===== cnb_basico_9.sql =====
-- CNB Ciclo Básico - Ciencias Naturales - Tercer Grado
-- Fuente: .../CNB_Ciclo_Básico/Ciencias_Naturales/Malla_curricular_Tercer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Ciencias Naturales', '1. Discute los resultados obtenidos a partir de la aplicación de los métodos de investigación científica, que le permitan dar solución a problemas de la vida cotidiana, utilizando diferentes recursos tecnológicos.', ARRAY['1.1. Explica la importancia del enfoque interdisciplinario en la investigación científica, así como la necesidad de hacer ciencia ciudadana en el país.', '1.2. Describe formas para realizar investigación científica y tecnológica.', '1.3. Argumenta acerca de la importancia de la innovación científica y tecnológica en Guatemala.']),
('Tercero Básico', 'Ciencias Naturales', '2. Propone soluciones prácticas a la problemática socio-ambiental local, la reducción de riesgo y la vulnerabilidad personal y local.', ARRAY['2.1. Relaciona el concepto de riesgo con la amenaza y la vulnerabilidad local.', '2.2. Discute acerca de los problemas socio-ambientales locales y sus posibles soluciones.', '2.3. Aplica el protocolo establecido en el plan de respuesta escolar para proteger su vida y la de los demás en caso de un desastre natural.']),
('Tercero Básico', 'Ciencias Naturales', '3. Argumenta acerca del cuidado personal, familiar y comunitario que procuran la salud integral.', ARRAY['3.1. Discute acerca del daño personal y social que produce el consumo de drogas, con base en información y datos estadísticos confiables.', '3.2. Explica la sexualidad humana y los posibles riesgos que implica asumirla en forma irresponsable.', '3.3. Discute acerca de la importancia de una alimentación equilibrada y los daños corporales que se producen debido a desórdenes alimenticios.']),
('Tercero Básico', 'Ciencias Naturales', '4. Resuelve problemas vinculados con los fenómenos físicos, químicos y biológicos que ocurren en su contexto.', ARRAY['4.1. Aplica los principios de la mecánica cuántica para establecer la ubicación de los electrones en un átomo.', '4.2. Establece diferencias entre átomos, moléculas y iones presentes en los compuestos.', '4.3. Utiliza números de oxidación para formar y nombrar compuestos con oxígeno, hidrógeno y sin oxígeno e hidrógeno.', '4.4. Analiza gráficas de posición, velocidad y aceleración versus tiempo y las relaciona con los modelos matemáticos relacionados con el movimiento y aceleración constante, en una dimensión.', '4.5. Resuelve problemas teóricos y experimentales de movimiento acelerado en una dimensión, de proyectiles y movimiento circular uniforme relacionados con la vida diaria.', '4.6. Aplica las leyes de Newton en la explicación de la ocurrencia de fenómenos y situaciones de la cotidianidad, del ámbito tecnológico y en la resolución de problemas de equilibrio estático en 1D.', '4.7. Explica la relación entre los conceptos de trabajo, potencia y energía mecánica en problemas de la vida cotidiana.', '4.8. Describe distintas formas de generar energía y su impacto en el medio ambiente local.']);

-- ===== cnb_basico_10.sql =====
-- CNB Ciclo Básico - Ciencias Sociales, Formación Ciudadana e Interculturalidad - Primer Grado
-- Fuente: .../CNB_Ciclo_Básico/Ciencias_Sociales,_Formación_Ciudadana_e_Interculturalidad/Malla_curricular_Primer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '1. Interpreta procedimientos de investigación que se desarrollan en las Ciencias Sociales.', ARRAY['1.1. Describe la importancia de las Ciencias Sociales para el desarrollo de las sociedades.', '1.2. Establece la función de un método y una técnica en el proceso de investigación.', '1.3. Muestra interés por el uso de centros de información.']),
('Primero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '2. Clasifica los factores que inciden en la problemática poblacional y ambiental del mundo.', ARRAY['2.1. Contrasta la geografía y recursos naturales de los diversos continentes.', '2.2. Identifica en distintos contextos del mundo los efectos del crecimiento de la población.', '2.3. Demuestra compromiso con la protección del ambiente.']),
('Primero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '3. Reconoce los procesos históricos que han incidido en la conformación de las sociedades del mundo y Guatemala.', ARRAY['3.1. Comprende el escenario histórico del mundo, previo a la civilización griega y romana.', '3.2. Explica los procesos históricos desde la prehistoria hasta el desarrollo de la civilización romana.', '3.3. Se interesa por conocer los aportes de las diferentes civilizaciones que incidieron en la conformación de las sociedades del mundo, América y Guatemala.']),
('Primero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '4. Respeta las normas para el ejercicio ciudadano intercultural, democrático y la convivencia.', ARRAY['4.1. Determina las leyes nacionales e internacionales que prescriben los derechos de los pueblos de Guatemala.', '4.2. Formula alternativas para la convivencia armónica e intercultural en distintos contextos.', '4.3. Identifica las características y problemáticas de la democracia en la estructura política de Guatemala.', '4.4. Demuestra interés por participar en organizaciones estudiantiles del centro educativo.']);

-- ===== cnb_basico_11.sql =====
-- CNB Ciclo Básico - Ciencias Sociales, Formación Ciudadana e Interculturalidad - Segundo Grado
-- Fuente: .../CNB_Ciclo_Básico/Ciencias_Sociales,_Formación_Ciudadana_e_Interculturalidad/Malla_curricular_Segundo_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '1. Aplica procedimientos específicos de investigación de determinadas Ciencias Sociales.', ARRAY['1.1. Distingue los métodos y técnicas de investigación propios de la Antropología.', '1.2. Compara los métodos y técnicas de investigación antropológica e histórica.', '1.3. Demuestra interés por investigar temáticas sociales.']),
('Segundo Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '2. Explica la situación demográfica y ambiental del continente americano y Guatemala.', ARRAY['2.1. Distingue las características físicas del continente americano.', '2.2. Argumenta las causas y consecuencias de la situación demográfica de América.', '2.3. Propone buenas prácticas para la protección del ambiente.']),
('Segundo Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '3. Interpreta el contexto histórico mundial del encuentro entre distintas sociedades de diferentes continentes.', ARRAY['3.1. Distingue el contexto histórico en que inicia la Edad Media.', '3.2. Explica los fenómenos sociales e históricos desde la invasión de los Pueblos Bárbaros al Imperio Romano hasta el nacimiento del Islam.', '3.3. Evidencia disposición por indagar sobre contextos históricos específicos de la Edad Media.']),
('Segundo Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '4. Asume actitud incluyente, propositiva y responsable frente a las necesidades de su comunidad.', ARRAY['4.1. Reconoce la importancia de la participación comunitaria en el marco del desarrollo social.', '4.2. Explica la importancia de la interculturalidad y convivencia armónica para el desarrollo comunitario.', '4.3. Comparte los beneficios comunitarios del ejercicio de derechos, la práctica de valores y el cumplimiento de normativas y obligaciones.']);

-- ===== cnb_basico_12.sql =====
-- CNB Ciclo Básico - Ciencias Sociales, Formación Ciudadana e Interculturalidad - Tercer Grado
-- Fuente: .../CNB_Ciclo_Básico/Ciencias_Sociales,_Formación_Ciudadana_e_Interculturalidad/Malla_curricular_Tercer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '1. Utiliza métodos y técnicas específicas para realizar procesos básicos de investigación en Ciencias Sociales, según su propósito.', ARRAY['1.1. Selecciona un problema de investigación de su contexto.', '1.2. Planifica procesos de investigación del problema seleccionado.', '1.3. Se esfuerza por presentar un informe de investigación que cumpla con características científicas.']),
('Tercero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '2. Propone medidas de mitigación para reducir el impacto demográfico y ambiental en su contexto.', ARRAY['2.1. Explica las características de la vulnerabilidad geográfica de Guatemala.', '2.2. Infiere la situación demográfica de Guatemala y su incidencia en el entorno.', '2.3. Opina sobre los efectos e impacto de la actividad económica en el ambiente guatemalteco.']),
('Tercero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '3. Analiza las distintas relaciones de poder que se establecen en el proceso de formación del Estado guatemalteco.', ARRAY['3.1. Determina el contexto histórico de Guatemala y Europa en el cual se concretó la invasión y conquista.', '3.2. Explica la continuidad de las relaciones de poder internas y externas, posteriores a la Independencia de Guatemala y Centroamérica.', '3.3. Investiga sobre la prolongación de las relaciones de poder internas y externas en el tiempo hasta mediados del Siglo XX.', '3.4. Se interesa por profundizar en los procesos de la historia reciente de Guatemala.']),
('Tercero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '4. Participa activamente en la transformación de conflictos, en el marco de la realidad social, cultural y política de su entorno.', ARRAY['4.1. Relaciona los Acuerdos de Paz con el fortalecimiento de la democracia participativa en Guatemala.', '4.2. Deduce el impacto de la rendición de cuentas y la auditoría social en las instituciones del Estado.', '4.3. Argumenta la importancia de los valores para la construcción de la democracia, cultura de legalidad e interculturalidad.']);

-- ===== cnb_basico_13.sql =====
-- CNB Ciclo Básico - Culturas e Idiomas Maya, Garífuna o Xinca - Primer Grado
-- Fuente: .../CNB_Ciclo_Básico/Culturas_e_Idiomas_Maya,_Garífuna_o_Xinca/Malla_curricular_Primer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '1. Practica con profundidad determinados elementos de la cultura de los Pueblos de Guatemala.', ARRAY['1.1. Clasifica elementos de la cultura del pueblo Maya.', '1.2. Distingue elementos de la cultura del pueblo Xinka.', '1.3. Describe elementos de la cultura del pueblo Garífuna.', '1.4. Describe elementos de la cultura del pueblo Ladino o Mestizo.']),
('Primero Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '2. Articula asertivamente la escucha y el habla en el idioma de aprendizaje, al transmitir mensajes de diferente intención comunicativa y contexto.', ARRAY['2.1. Reconoce el origen de los idiomas de Guatemala.', '2.2. Discute respetuosamente sobre un tema de interés común siguiendo un esquema.', '2.3. Utiliza el idioma Maya, Garífuna o Xinka como medio para comunicarse en diferentes ambientes.']),
('Primero Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '3. Utiliza lecturas cortas y de menor complejidad como medio analítico para una mejor comprensión del idioma y la cultura de la comunidad lingüística.', ARRAY['3.1. Aplica estrategias para una mejor comprensión lectora.', '3.2. Identifica textos en el idioma de estudio.', '3.3. Aplica los diferentes tipos de lectura.']),
('Primero Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '4. Construye expresiones escritas básicas, utilizando la estructura gramatical del idioma Maya, Garífuna o Xinka, para comunicar su vivencia cultural.', ARRAY['4.1. Escribe textos cortos y con sentido en el idioma de estudio.', '4.2. Expresa de forma escrita al comunicar sus ideas.', '4.3. Escribe con claridad los textos que lee.']);

-- ===== cnb_basico_14.sql =====
-- CNB Ciclo Básico - Culturas e Idiomas Maya, Garífuna o Xinca - Segundo Grado
-- Fuente: .../CNB_Ciclo_Básico/Culturas_e_Idiomas_Maya,_Garífuna_o_Xinca/Malla_curricular_Segundo_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '1. Compara prácticas culturales existentes en función de su entorno para la construcción de identidades.', ARRAY['1.1. Identifica la concepción de cultura, cosmovisión, principios y valores del pueblo Maya.', '1.2. Identifica la concepción de cultura, cosmovisión, principios y valores del pueblo Xinka.', '1.3. Define la concepción de cultura, cosmovisión, principios y valores del pueblo Garífuna.']),
('Segundo Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '2. Expresa pensamientos y emociones oralmente y de forma diferenciada sobre las prácticas culturales de su contexto.', ARRAY['2.1. Se expresa de manera fluida en el idioma en un nivel básico.', '2.2. Comprende de forma clara los mensajes que recibe.', '2.3. Proporciona información básica relacionada con sus actividades diarias.']),
('Segundo Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '3. Analiza de manera crítica lo que lee en el idioma Maya, Garífuna o Xinka, para que tenga sentido y significado cultural en sus actividades diarias.', ARRAY['3.1. Identifica la idea principal de los textos.', '3.2. Selecciona diversos textos.', '3.3. Emplea la lectura para el enriquecimiento personal.']),
('Segundo Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '4. Utiliza la norma gramatical del idioma Maya, Garífuna o Xinka, en las producciones de textos sencillos sobre las prácticas culturales de su contexto.', ARRAY['4.1. Produce textos sencillos sobre temas familiares.', '4.2. Redacta textos sencillos y coherentes con diferentes intencionalidades.', '4.3. Emplea la estructura gramatical del idioma en sus redacciones.']);

-- ===== cnb_basico_15.sql =====
-- CNB Ciclo Básico - Culturas e Idiomas Maya, Garífuna o Xinca - Tercer Grado
-- Fuente: .../CNB_Ciclo_Básico/Culturas_e_Idiomas_Maya,_Garífuna_o_Xinca/Malla_curricular_Tercer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '1. Utiliza los elementos culturales de su pueblo y de algunos países latinoamericanos para fortalecer su identidad.', ARRAY['1.1. Identifica la riqueza cultural de países de Centroamérica.', '1.2. Compara elementos culturales de distintos países latinoamericanos.', '1.3. Explica la importancia de tener cultura e identidad.']),
('Tercero Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '2. Se expresa en el idioma Maya, Garífuna o Xinka con fluidez y precisión, sobre circunstancias de mayor complejidad de su contexto.', ARRAY['2.1. Utiliza vocabulario variado en sus expresiones en su respectivo idioma.', '2.2. Defiende su punto de vista con seguridad sobre diferentes temas.', '2.3. Se relaciona con hablantes nativos con un grado suficiente de fluidez y naturalidad.', '2.4. Utiliza la lectura en el idioma de manera efectiva para fines sociales, académicos y profesionales.', '2.5. Comprende las ideas principales de textos complejos que traten de temas concretos y abstractos.']),
('Tercero Básico', 'Culturas e Idiomas Maya, Garífuna o Xinca', '3. Produce diferentes tipos de textos escritos relacionados con el ámbito escolar, comunitario, social y nacional.', ARRAY['3.1. Reconstruye la información y los argumentos procedentes de diversas fuentes en lenguaje escrito.', '3.2. Produce textos coherentes sobre temas cortos y de interés común, tomando en cuenta la norma gramatical del idioma.', '3.3. Utiliza la gramática del idioma en la construcción de diferentes tipos de texto.']);

-- ===== cnb_basico_16.sql =====
-- CNB Ciclo Básico - Educación Artística - Primer Grado (Artes Plásticas, Danza, Música, Teatro)
-- Fuente: .../CNB_Ciclo_Básico/Educación_Artística/Malla_curricular_Primer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Artes Plásticas
('Primero Básico', 'Educación Artística (Artes Plásticas)', '1. Aplica elementos, técnicas y la psicología del color en las composiciones visuales que realiza de forma armónica y equilibrada.', ARRAY['1.1. Utiliza los elementos del arte en la composición visual.', '1.2. Elabora composiciones aplicando las técnicas del arte plástico.', '1.3. Elabora composiciones aplicando los colores cálidos y/o fríos.']),
('Primero Básico', 'Educación Artística (Artes Plásticas)', '2. Experimenta en la elaboración de obras artísticas tomando en cuenta lo humano, familiar, natural, histórico, social y cultural.', ARRAY['2.1. Retrata a sus amigos y familiares.', '2.2. Experimenta mezclas de colores utilizando diferentes técnicas naturales.', '2.3. Elabora obras artísticas a partir de diferentes cosmovisiones.']),
('Primero Básico', 'Educación Artística (Artes Plásticas)', '3. Expone en actividades culturales sus obras artísticas.', ARRAY['3.1. Muestra sus pinturas y dibujos de forma colectiva e individual.', '3.2. Ordena las obras plásticas para generar equilibrio dentro del espacio de exposición.', '3.3. Diseña invitaciones o afiches para promover su obra plástica.']),
-- Danza
('Primero Básico', 'Educación Artística (Danza)', '1. Utiliza gestos y sus posibilidades de movimiento como lenguaje corporal expresivo.', ARRAY['1.1. Realiza gestos y movimientos como parte de su lenguaje expresivo.', '1.2. Relaciona el movimiento con ideas, sentimientos y emociones propias y de su grupo.', '1.3. Crea movimientos en el espacio de manera individual y grupal.']),
('Primero Básico', 'Educación Artística (Danza)', '2. Experimenta movimientos con su cuerpo al realizar trabajos individuales o grupales de danza.', ARRAY['2.1. Utiliza ritmos y música apropiados para acompañar sus trabajos dancísticos.', '2.2. Identifica las partes de su cuerpo apropiadas para desarrollar su actividad dancística.', '2.3. Selecciona movimientos apropiados para realizar sus trabajos de danza.']),
('Primero Básico', 'Educación Artística (Danza)', '3. Realiza actividades de baile que fortalecen la diversidad cultural.', ARRAY['3.1. Analiza las posibilidades y recursos expresivos de su cuerpo en movimiento.', '3.2. Produce trabajos de expresión dancística creativa que respeten las opiniones del grupo.', '3.3. Emite criterios sobre los movimientos y gestos corporales pertenecientes a diversos estilos de géneros dancísticos de su entorno y de otras culturas.']),
-- Música
('Primero Básico', 'Educación Artística (Música)', '1. Experimenta con los sonidos por medio del canto, instrumentos musicales convencionales y no convencionales de forma individual y colectiva.', ARRAY['1.1. Produce discursos sonoros con instrumentos convencionales y no convencionales.', '1.2. Recrea paisajes sonoros y fenómenos acústicos con medios a su alcance.', '1.3. Utiliza las cualidades del sonido para la identificación de sonidos aislados y dentro de paisajes sonoros.', '1.4. Realiza procesos de grabación de paisajes sonoros diversos.', '1.5. Realiza ritmos por imitación o por lectura con su cuerpo, objetos, útiles sonoros e instrumentos musicales.', '1.6. Canta o ejecuta instrumentos musicales aplicando la armonía funcional.', '1.7. Organiza conciertos escolares en su centro educativo.']),
('Primero Básico', 'Educación Artística (Música)', '2. Experimenta distintas sensaciones provocadas por el contacto con la música.', ARRAY['2.1. Manifiesta su musicalidad relacionándola con su vida y contexto.', '2.2. Vincula expresiones verbales, escritas o artísticas con manifestaciones musicales que escucha.', '2.3. Utiliza la multifuncionalidad de la música para obtener beneficios físicos, emocionales y espirituales.']),
('Primero Básico', 'Educación Artística (Música)', '3. Reconoce su sonoridad individual, familiar y social dentro del contexto nacional.', ARRAY['3.1. Explora la sonoridad propia, familiar y de su entorno de manera respetuosa.', '3.2. Ejecuta grupalmente música maya, xinka, garífuna y ladina.', '3.3. Reflexiona acerca del repertorio guatemalteco.']),
-- Teatro
('Primero Básico', 'Educación Artística (Teatro)', '1. Utiliza los trece signos teatrales y los elementos básicos de actuación.', ARRAY['1.1. Representa por medio de escenificaciones los trece signos del teatro.', '1.2. Utiliza los elementos básicos para la creación de un personaje.', '1.3. Produce obras cortas de teatro.']),
('Primero Básico', 'Educación Artística (Teatro)', '2. Explora los recursos corporales (individual y en grupo) para recrear un hecho escénico por medio de la experimentación, exploración y descubrimiento.', ARRAY['2.1. Reconoce las diferentes posibilidades de movimientos corporales a nivel individual.', '2.2. Proyecta sus estados emocionales utilizando la observación y el reconocimiento que le ayudan a recrear personajes.', '2.3. Percibe las diferentes posibilidades del aparato fonador y el uso de la voz para aplicarlas en el hecho escénico.']),
('Primero Básico', 'Educación Artística (Teatro)', '3. Analiza discursos desde la dramaturgia de diversos autores guatemaltecos.', ARRAY['3.1. Investiga sobre la dramaturgia prehispánica, colonial y contemporánea.', '3.2. Justifica la importancia de analizar los discursos de los dramaturgos guatemaltecos para comprender el contexto nacional que vivían según su época.', '3.3. Teatraliza fragmentos de textos o escenas de dramaturgos guatemaltecos.']);

-- ===== cnb_basico_17.sql =====
-- CNB Ciclo Básico - Educación Artística - Segundo Grado (Artes Plásticas, Danza, Música, Teatro)
-- Fuente: .../CNB_Ciclo_Básico/Educación_Artística/Malla_curricular_Segundo_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Artes Plásticas
('Segundo Básico', 'Educación Artística (Artes Plásticas)', '1. Realiza composiciones con movimientos modernos utilizando las diferentes técnicas del arte plástico y las artes visuales.', ARRAY['1.1. Dibuja diferentes tipos de boceto con las técnicas básicas.', '1.2. Aplica la técnica acuarela para la realización de distintas figuras.', '1.3. Realiza obras visuales por medio de la fotografía y el video con diferentes aparatos tecnológicos.', '1.4. Experimenta con dibujos representando los diferentes movimientos de la época de la modernidad.']),
('Segundo Básico', 'Educación Artística (Artes Plásticas)', '2. Elabora obras artísticas de su contexto visual tomando en cuenta lo humano, familiar, natural, histórico, social y cultural.', ARRAY['2.1. Realiza pinturas, modelado o galería de fotografía como homenaje a diferentes artistas visuales.', '2.2. Elabora títeres que representan personajes de las artes visuales como homenaje a sus obras.', '2.3. Propone diseños de murales que representan el bien común.']),
('Segundo Básico', 'Educación Artística (Artes Plásticas)', '3. Organiza una exposición de sus trabajos con otras personas.', ARRAY['3.1. Realiza museografía con trabajos artísticos propios o de muestras colectivas.', '3.2. Ordena exposiciones artísticas con los elementos básicos de una exposición.', '3.3. Realiza una descripción escrita de las obras para exposición.']),
-- Danza
('Segundo Básico', 'Educación Artística (Danza)', '1. Interpreta danzas comunes de su contexto y otros contextos.', ARRAY['1.1. Baila piezas de danza de creación personal y grupal.', '1.2. Ejecuta movimientos en grupo promoviendo el trabajo en equipo.', '1.3. Representa trabajos dancísticos creativos en grupo.']),
('Segundo Básico', 'Educación Artística (Danza)', '2. Valora las imágenes del cuerpo en los trabajos de danza que realiza individual y grupalmente.', ARRAY['2.1. Aprecia las danzas realizadas por sus compañeros.', '2.2. Compara diferentes danzas de los pueblos bailadas individual o grupalmente.', '2.3. Identifica el ritmo, música y danza en las presentaciones de sus compañeros en el aula.']),
('Segundo Básico', 'Educación Artística (Danza)', '3. Relaciona aspectos danzarios de diferentes culturas y épocas mientras los experimenta con su cuerpo.', ARRAY['3.1. Analiza sus bailes y los de otros, con respeto a sus ideas e intereses.', '3.2. Aplica sus conocimientos de ritmo, música y danza en la creación de proyectos de aula.', '3.3. Emite criterios de los diseños coreográficos pertenecientes a diferentes estilos de géneros dancísticos de su entorno y de otras culturas.']),
-- Música
('Segundo Básico', 'Educación Artística (Música)', '1. Interpreta música utilizando diferentes elementos sonoros incluyendo el canto, instrumentos musicales convencionales y no convencionales de forma individual y colectiva.', ARRAY['1.1. Crea música utilizando elementos y materiales sonoros diversos.', '1.2. Realiza secuencias rítmicas utilizando ritmos existentes y ritmos originales.', '1.3. Ejecuta repertorios latinoamericanos por medio del canto e instrumentos musicales.', '1.4. Canta o interpreta en conciertos escolares e interescolares.']),
('Segundo Básico', 'Educación Artística (Música)', '2. Disfruta haciendo música de forma consciente y analítica.', ARRAY['2.1. Comparte sus habilidades musicales con sus compañeros.', '2.2. Asocia la música con otras disciplinas: artísticas, científicas, deportivas y otras.', '2.3. Utiliza la música para realizar juegos y repertorios musicales lúdicos.']),
('Segundo Básico', 'Educación Artística (Música)', '3. Compara la música latinoamericana de su época con la de otros tiempos al ejecutarla.', ARRAY['3.1. Identifica distintos géneros de música latinoamericana.', '3.2. Ejecuta música producida por los pueblos originarios de América Latina.', '3.3. Ejecuta la música de los pueblos mestizos y criollos de América Latina.']),
-- Teatro
('Segundo Básico', 'Educación Artística (Teatro)', '1. Elabora su propio discurso teatral por medio de diversos ejercicios de dramaturgia.', ARRAY['1.1. Proyecta sus estados emocionales utilizando la observación, reconocimiento, control y recreación.', '1.2. Realiza representaciones de personajes y escenas.', '1.3. Teatraliza a partir de situaciones de la vida diaria.']),
('Segundo Básico', 'Educación Artística (Teatro)', '2. Clasifica las características de las diversas manifestaciones del arte dramático.', ARRAY['2.1. Identifica las características de las diferentes divisiones y subdivisiones del género dramático y del hecho dramático.', '2.2. Define los diferentes roles que se desarrollan en el ambiente teatral.', '2.3. Utiliza el aparato fonador en la construcción de personajes según el género dramático: formas mayores y menores.']),
('Segundo Básico', 'Educación Artística (Teatro)', '3. Analiza el discurso desde la dramaturgia de diversos autores latinoamericanos.', ARRAY['3.1. Investiga sobre la dramaturgia prehispánica, colonial y contemporánea.', '3.2. Compara los discursos de los dramaturgos latinoamericanos para comprender el contexto nacional que vivían según su época.', '3.3. Teatraliza fragmentos de textos o escenas de dramaturgos latinoamericanos.']);

-- ===== cnb_basico_18.sql =====
-- CNB Ciclo Básico - Educación Artística - Tercer Grado (Artes Plásticas, Danza, Música, Teatro)
-- Fuente: .../CNB_Ciclo_Básico/Educación_Artística/Malla_curricular_Tercer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Artes Plásticas
('Tercero Básico', 'Educación Artística (Artes Plásticas)', '1. Crea composiciones aplicando distintas perspectivas y utilizando técnicas extraídas de la tradición maya.', ARRAY['1.1. Realiza obras artísticas utilizando uno, dos, tres puntos de fuga, perspectivas diédricas, caballeras y atmosféricas.', '1.2. Incursiona en la ilustración de textos literarios.', '1.3. Aplica técnicas extraídas de la tradición artística maya.']),
('Tercero Básico', 'Educación Artística (Artes Plásticas)', '2. Crea arte visual profundizando en temas sociales, históricos y naturales.', ARRAY['2.1. Realiza pinturas o galería de fotografía de las diferentes realidades sociales.', '2.2. Produce videos cortos con temáticas sociales.', '2.3. Construye instalaciones artísticas en su escuela o en su comunidad.']),
('Tercero Básico', 'Educación Artística (Artes Plásticas)', '3. Organiza exposiciones para presentar en su escuela o en su comunidad.', ARRAY['3.1. Produce materiales de apoyo para la difusión de su obra.', '3.2. Pinta murales en su escuela o en su comunidad.', '3.3. Realiza grafitis tomando como inspiración la realidad social, nacional e internacional.']),
-- Danza
('Tercero Básico', 'Educación Artística (Danza)', '1. Crea movimientos que representan expresiones, ideas, sentimientos e intereses de su cultura u otras culturas.', ARRAY['1.1. Combina movimientos originales para representar a su cultura y otras culturas.', '1.2. Improvisa movimientos no planificados que representan su cultura y la de otros.', '1.3. Ensaya sus proyectos dancísticos con fines de intercambio, coordinación y enriquecimiento artístico.']),
('Tercero Básico', 'Educación Artística (Danza)', '2. Evalúa los movimientos de su cuerpo con los movimientos de los demás, en trabajos individuales y colectivos promoviendo la crítica constructiva.', ARRAY['2.1. Reconoce actividades relacionadas con la danza en contextos culturales.', '2.2. Respeta los componentes culturales, etarios e históricos de los grupos sociales que la interpretan.', '2.3. Utiliza la crítica constructiva para retroalimentar a sus compañeros.']),
('Tercero Básico', 'Educación Artística (Danza)', '3. Critica con fundamento artístico los aspectos relevantes de las danzas de su cultura y otras culturas, que practica en clase.', ARRAY['3.1. Investiga sobre las danzas individuales o colectivas que baila en clase.', '3.2. Argumenta la danza que realiza según el momento histórico que eligió.', '3.3. Evalúa danzas que baila individual o grupalmente.']),
-- Música
('Tercero Básico', 'Educación Artística (Música)', '1. Improvisa música utilizando el canto, instrumentos musicales convencionales y no convencionales de forma individual y colectiva.', ARRAY['1.1. Crea música con la voz o instrumentos musicales.', '1.2. Edita música con técnicas básicas de grabación.', '1.3. Interpreta repertorios en montajes musicales dentro y fuera del ámbito escolar.']),
('Tercero Básico', 'Educación Artística (Música)', '2. Expresa argumentos sobre el valor simbólico de la música, como bien cultural de eutonía individual y de creación social colectiva.', ARRAY['2.1. Utiliza las prácticas musicales para su estabilidad emocional.', '2.2. Realiza actividades escolares para vincular la música con la sociedad.', '2.3. Realiza proyectos escolares con impacto a la sociedad.']),
('Tercero Básico', 'Educación Artística (Música)', '3. Analiza la música contemporánea, la industria musical y los fenómenos globalizadores que impactan artísticamente en la actualidad.', ARRAY['3.1. Opina críticamente sobre la industria musical actual y su importancia en la sociedad.', '3.2. Expone puntos de vista sobre problemáticas musicales y fenómenos globalizadores.', '3.3. Interpreta música de distintas latitudes del mundo.']),
-- Teatro
('Tercero Básico', 'Educación Artística (Teatro)', '1. Produce obras de teatro utilizando los elementos de la dramaturgia.', ARRAY['1.1. Escribe obras con los elementos centrales de la dramaturgia.', '1.2. Crea textos teatrales a partir de sus experiencias de vida.', '1.3. Elabora su propio discurso teatral por medio de diversos ejercicios de dramaturgia.']),
('Tercero Básico', 'Educación Artística (Teatro)', '2. Recrea la dirección escénica utilizando para ello textos teatrales propios o ajenos.', ARRAY['2.1. Dirige prácticas de dirección escénica.', '2.2. Coordina creaciones colectivas.', '2.3. Utiliza su voz correctamente en la experimentación e interpretación de textos.']),
('Tercero Básico', 'Educación Artística (Teatro)', '3. Argumenta discursos desde la dramaturgia de diversos autores latinoamericanos.', ARRAY['3.1. Reflexiona sobre las opciones dramáticas y hechos dramáticos que existen.', '3.2. Justifica la importancia de analizar los discursos de los dramaturgos universales para comprender el contexto nacional, según su época.', '3.3. Representa fragmentos de textos teatrales de dramaturgos universales.']);

-- ===== cnb_basico_19.sql =====
-- CNB Ciclo Básico - Educación Física - Primer Grado
-- Fuente: .../CNB_Ciclo_Básico/Educación_Física/Malla_curricular_Primer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Educación Física', '1. Fortalece el nivel de desarrollo de las capacidades físicas y es consciente sobre la seguridad de su práctica.', ARRAY['1.1. Completa recorridos máximos en diferentes espacios, distancias o tiempo determinado sin dificultad.', '1.2. Utiliza eficazmente la fuerza máxima sin resentimiento orgánico en la práctica de actividades físicas.', '1.3. Ejecuta con destreza y seguridad la rapidez de traslación de un lugar a otro en el menor tiempo posible.', '1.4. Amplía gradualmente el grado de flexibilidad corporal.']),
('Primero Básico', 'Educación Física', '2. Practica acciones físico deportivas favoreciendo relaciones interpersonales armoniosas en la diversidad.', ARRAY['2.1. Aplica la técnica de los fundamentos del atletismo para su desarrollo deportivo.', '2.2. Ejecuta coordinadamente los elementos técnicos del baloncesto mejorando su habilidad técnico deportiva.', '2.3. Ejecuta coordinadamente los elementos técnicos del fútbol, mejorando su habilidad técnico deportiva.', '2.4. Realiza con dominio los elementos técnicos del voleibol, mejorando su habilidad técnico deportiva.', '2.5. Aplica de forma correcta los elementos técnicos del balonmano, optimizando su habilidad técnico deportiva.', '2.6. Construye de forma coordinada composiciones gimnásticas aplicando movimientos y ritmos para la mejora de la habilidad motriz.', '2.7. Vincula los elementos del ajedrez, para mejorar la habilidad de los procesos mentales.', '2.8. Conoce y emplea los elementos técnicos del chaaj o juego de pelota maya, mejorando su habilidad técnico deportiva.']),
('Primero Básico', 'Educación Física', '3. Practica hábitos de salud, nutrición y ejercicio físico que contribuyan a su calidad de vida.', ARRAY['3.1. Localiza correctamente la toma del pulso cardiaco en diferentes partes del cuerpo.', '3.2. Describe la importancia de la seguridad alimentaria y nutricional en su familia, escuela y comunidad.', '3.3. Demuestra la importancia de la ingesta de líquidos durante la actividad física y valora los períodos de descanso adecuados.']);

-- ===== cnb_basico_20.sql =====
-- CNB Ciclo Básico - Educación Física - Segundo Grado
-- Fuente: .../CNB_Ciclo_Básico/Educación_Física/Malla_curricular_Segundo_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Educación Física', '1. Practica actividades físicas mejorando su condición física para una vida saludable y social.', ARRAY['1.1. Desarrolla gradualmente la resistencia de media duración por medio de recorridos, saltos de cuerda o subir el escalón sin dificultad.', '1.2. Supera progresivamente el cansancio o fatiga de brazos y piernas como resultado de la aplicación de la fuerza rápida.', '1.3. Desarrolla con facilidad carreras cortas y movimientos rápidos en tiempos determinados.', '1.4. Supera gradualmente el grado de flexibilidad del tren inferior en acciones motrices.']),
('Segundo Básico', 'Educación Física', '2. Ejecuta la práctica deportiva constante para la mejora de la destreza motriz y el fomento de valores en su contexto.', ARRAY['2.1. Incrementa gradualmente el rendimiento individual en la ejecución de las carreras de velocidad, relevos, saltos e impulsión de bala.', '2.2. Aplica progresivamente de forma correcta la técnica ofensiva y defensiva en el baloncesto utilizando su creatividad.', '2.3. Realiza transiciones de ejercicios de defensa a ataque en fracciones cortas de tiempo generando acciones de juego en el fútbol.', '2.4. Ejecuta con seguridad los elementos técnicos del voleibol de forma individual y colectiva.', '2.5. Incrementa gradualmente la aplicación de los elementos técnicos del balonmano generando situaciones de juego.', '2.6. Realiza de forma creativa diferentes secuencias de movimientos rítmicos en la presentación de coreografías.', '2.7. Resuelve continuos problemas planteados en los diferentes movimientos producidos en el ajedrez.', '2.8. Ejecuta con seguridad los elementos técnicos del Chaaj o Juego de Pelota Maya, de forma individual y colectiva.']),
('Segundo Básico', 'Educación Física', '3. Integra hábitos higiénicos y medidas preventivas de seguridad en actividades físico deportivas y de la vida diaria.', ARRAY['3.1. Aplica correctamente las técnicas de respiración y relajación de acuerdo al incremento del pulso cardíaco durante la actividad física.', '3.2. Adopta hábitos de nutrición saludables adecuados en diferentes actividades de la vida cotidiana, para la conservación de la salud.', '3.3. Reconoce la importancia de la actividad física y mantiene la práctica permanente para el mejoramiento de la salud y calidad de vida.']);

-- ===== cnb_basico_21.sql =====
-- CNB Ciclo Básico - Educación Física - Tercer Grado
-- Fuente: .../CNB_Ciclo_Básico/Educación_Física/Malla_curricular_Tercer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Educación Física', '1. Practica las capacidades condicionales pertinentes para un buen rendimiento físico.', ARRAY['1.1. Alcanza la resistencia de corta duración por medio de recorridos en tramos cortos, saltos de cuerda o subir el escalón sin dificultad.', '1.2. Aplica la fuerza resistencia en repetidas contracciones musculares y periodos de tiempo sin deformar la técnica del ejercicio.', '1.3. Mejora de forma eficaz su capacidad de rapidez de reacción como respuesta a diferentes estímulos en el menor tiempo posible.', '1.4. Desarrolla agilidad fácilmente cuando cambia en diferentes situaciones motrices.']),
('Tercero Básico', 'Educación Física', '2. Realiza prácticas deportivas promoviendo la responsabilidad y la comunicación en la comunidad.', ARRAY['2.1. Aplica la técnica correcta en las diferentes pruebas de pista y campo en atletismo.', '2.2. Resuelve correctamente situaciones técnicas defensivas y ofensivas del baloncesto.', '2.3. Combina correctamente situaciones técnicas y tácticas defensivas y ofensivas en el fútbol de forma individual.', '2.4. Resuelve correctamente situaciones técnicas defensivas y ofensivas del voleibol.', '2.5. Ejecuta correctamente acciones técnicas defensivas y ofensivas de forma individual y grupal en el balonmano.', '2.6. Realiza correctamente la construcción de composiciones gimnásticas, coordinando ritmos musicales y coreografía para la mejora de la expresión corporal.', '2.7. Ejecuta diferentes tipos de ataque y defensa en el ajedrez anotando de forma correcta los movimientos.', '2.8. Emplea coordinadamente habilidades motrices combinadas, para ejecutar acciones que favorezcan la aplicación de la técnica del chaaj o juego de pelota maya.']),
('Tercero Básico', 'Educación Física', '3. Organiza un plan de actividad física permanente para mejoramiento de la calidad de vida individual y familiar.', ARRAY['3.1. Propone alternativas de solución ante problemas que afectan la salud de las personas.', '3.2. Expone las etapas de un proyecto productivo, tomado en relación a la actividad física.', '3.3. Construye estrategias que le permitan alcanzar una vida saludable, valorando el trabajo cooperativo.']);

-- ===== cnb_basico_22.sql =====
-- CNB Ciclo Básico - Emprendimiento para la Productividad - Primer Grado
-- Fuente: .../CNB_Ciclo_Básico/Emprendimiento_para_la_Productividad/Malla_curricular_Primer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Emprendimiento para la Productividad', '1. Elabora su proyecto de vida considerando el emprendimiento como herramienta para mejorar la calidad de vida desde su entorno familiar, cultural y comunitario.', ARRAY['1.1. Reconoce los principios del emprendimiento.', '1.2. Describe los aspectos y características que influyen en su vida personal y familiar.', '1.3. Valora la cultura de su comunidad.']),
('Primero Básico', 'Emprendimiento para la Productividad', '2. Diferencia los principios tecnológicos con normas de calidad, seguridad, higiene y pertinencia en procesos de producción.', ARRAY['2.1. Reconoce procesos y técnicas de producción.', '2.2. Reconoce la importancia de la aplicación de las normas de calidad, seguridad e higiene en los procesos de producción.', '2.3. Identifica las prácticas que brinden solución a problemas y que a la vez contribuyan al cuidado del medioambiente.']),
('Primero Básico', 'Emprendimiento para la Productividad', '3. Valora la importancia de administrar los bienes y recursos financieros para el desarrollo familiar y comunitario.', ARRAY['3.1. Explica la importancia de administrar los bienes familiares.', '3.2. Cuantifica los bienes familiares y ejecuta presupuestos.', '3.3. Identifica la relación entre las ocupaciones y actividades económicas de una comunidad eminentemente productiva.']);

-- ===== cnb_basico_23.sql =====
-- CNB Ciclo Básico - Emprendimiento para la Productividad - Segundo Grado
-- Fuente: .../CNB_Ciclo_Básico/Emprendimiento_para_la_Productividad/Malla_curricular_Segundo_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Emprendimiento para la Productividad', '1. Diseña propuestas de proyectos emprendedores para solucionar problemas o necesidades familiares y locales.', ARRAY['1.1. Describe las características de los proyectos emprendedores sostenibles.', '1.2. Identifica las etapas y procesos para planificar y promocionar proyectos.', '1.3. Registra las diferentes industrias y servicios que se prestan en la comunidad.']),
('Segundo Básico', 'Emprendimiento para la Productividad', '2. Desarrolla procesos productivos con calidad, utilizando tecnologías innovadoras y alternativas en la comunidad.', ARRAY['2.1. Diferencia las técnicas artesanales de las industriales.', '2.2. Identifica la importancia de la utilización de los indicadores de calidad en los procesos productivos.', '2.3. Cuantifica el impacto ambiental de los proyectos productivos.']),
('Segundo Básico', 'Emprendimiento para la Productividad', '3. Planifica procesos administrativos para el desarrollo de proyectos productivos sostenibles y sustentables.', ARRAY['3.1. Identifica métodos para la sostenibilidad de proyectos productivos/emprendedores y sustentabilidad.', '3.2. Identifica los procesos y requisitos legales en la organización laboral.', '3.3. Estima el plan de costos para elaborar diferentes productos.']);

-- ===== cnb_basico_24.sql =====
-- CNB Ciclo Básico - Emprendimiento para la Productividad - Tercer Grado
-- Fuente: .../CNB_Ciclo_Básico/Emprendimiento_para_la_Productividad/Malla_curricular_Tercer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Emprendimiento para la Productividad', '1. Ejecuta proyectos emprendedores para contribuir al desarrollo local comunitario.', ARRAY['1.1. Utiliza herramientas para diseñar proyectos emprendedores.', '1.2. Aplica procesos de mercadotecnia y publicidad en proyectos de emprendimiento local.', '1.3. Organiza las funciones en la administración de proyectos de emprendimiento local.']),
('Tercero Básico', 'Emprendimiento para la Productividad', '2. Determina el uso de la tecnología adecuada en la ejecución de proyectos emprendedores.', ARRAY['2.1. Practica los procesos de la gestión de la calidad y mejora continua de los procesos productivos.', '2.2. Demuestra la incidencia ambiental de un proyecto con la innovación sostenible ecológica.', '2.3. Identifica las diferentes tecnologías de la información y comunicación para contribuir a la mejora continua del proyecto emprendedor.']),
('Tercero Básico', 'Emprendimiento para la Productividad', '3. Administra con sostenibilidad proyectos de emprendimiento personales y locales.', ARRAY['3.1. Identifica las etapas del proceso administrativo.', '3.2. Registra los procesos y requisitos legales en la organización laboral.', '3.3. Estima fuentes para la sostenibilidad de proyectos emprendedores locales.']);

-- ===== cnb_basico_25.sql =====
-- CNB Ciclo Básico - Tecnologías del Aprendizaje y la Comunicación - Primer Grado
-- Fuente: .../CNB_Ciclo_Básico/Tecnologías_del_Aprendizaje_y_la_Comunicación/Malla_curricular_Primer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '1. Emplea los conocimientos y habilidades tecnológicos necesarios para realizar documentos digitales.', ARRAY['1.1. Describe la importancia que tiene la tecnología, los cuidados del equipo y la relación con la salud.', '1.2. Digita al tacto en forma ergonómica, con exactitud y la técnica correcta.', '1.3. Demuestra destrezas, habilidades y técnicas básicas en la elaboración de documentos de uso cotidiano.', '1.4. Redacta documentos en procesadores de texto.']),
('Primero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '2. Utiliza recursos digitales para la realización de materiales académicos de manera responsable, empleando protocolos de seguridad informática.', ARRAY['2.1. Selecciona diferentes herramientas tecnológicas en internet, apropiadas para comunicar y recibir información.', '2.2. Desarrolla una cultura de respeto ante las diferentes opiniones al elaborar trabajos colaborativos.', '2.3. Establece diferencias entre la información con base bibliográfica y la información sin respaldo académico.', '2.4. Traslada electrónicamente documentos de texto a destinatarios.']),
('Primero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '3. Emplea tecnologías colaborativas e interactivas en trabajos escolares con compañeros, dentro y fuera del espacio de aprendizaje.', ARRAY['3.1. Identifica sitios confiables para su trabajo escolar y aprendizajes oportunos.', '3.2. Utiliza herramientas colaborativas para desarrollar diversas actividades.', '3.3. Presenta documentos de acuerdo con las normas generales de presentación.']);

-- ===== cnb_basico_26.sql =====
-- CNB Ciclo Básico - Tecnologías del Aprendizaje y la Comunicación - Segundo Grado
-- Fuente: .../CNB_Ciclo_Básico/Tecnologías_del_Aprendizaje_y_la_Comunicación/Malla_curricular_Segundo_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Tecnologías del Aprendizaje y la Comunicación', '1. Aplica herramientas tecnológicas apropiadas, al ejecutar tareas específicas.', ARRAY['1.1. Selecciona el hardware de acuerdo con su uso y función, para utilizarlo adecuadamente y facilitar el trabajo.', '1.2. Utiliza aplicaciones de software de texto para tareas específicas, con eficiencia y velocidad.', '1.3. Representa información obtenida de fuentes externas, utilizando software de imágenes o presentaciones.']),
('Segundo Básico', 'Tecnologías del Aprendizaje y la Comunicación', '2. Emplea información por medio de técnicas de investigación en la web de manera precisa, segura, legal y ética.', ARRAY['2.1. Selecciona técnicas de investigación de acuerdo con los requerimientos para elaborar diferentes documentos.', '2.2. Distingue sitios seguros y éticos para la obtención de información gráfica y textual.', '2.3. Demuestra valores éticos al hacer uso de la información y respeta los derechos de autor.']),
('Segundo Básico', 'Tecnologías del Aprendizaje y la Comunicación', '3. Utiliza recursos tecnológicos colaborativos e interactivos en proyectos de investigación.', ARRAY['3.1. Selecciona tecnologías (programas, presentaciones, textos e imágenes) para facilitar el intercambio de comunicación.', '3.2. Utiliza diferentes programas para realizar presentaciones audiovisuales, contemplando las normas de presentación, contenido, diseño y uso bibliográfico.', '3.3. Comparte proyectos innovadores con diferentes usuarios a través de presentadores multimedia, en espacios educativos.']);

-- ===== cnb_basico_27.sql =====
-- CNB Ciclo Básico - Tecnologías del Aprendizaje y la Comunicación - Tercer Grado
-- Fuente: .../CNB_Ciclo_Básico/Tecnologías_del_Aprendizaje_y_la_Comunicación/Malla_curricular_Tercer_grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '1. Comparte su experiencia, conocimientos, habilidades y conceptos tecnológicos con los demás.', ARRAY['1.1. Elige la herramienta y la plataforma apropiadas para transmitir sus ideas, trabajos o mensajes.', '1.2. Diseña materiales digitales como infografías, simulaciones, gráficos u otro material multimedia.', '1.3. Publica contenido en una estructura social compuesta de acuerdo con un criterio específico.']),
('Tercero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '2. Crea recursos innovadores para proponer soluciones a problemas de la vida cotidiana desde el campo tecnológico, interactuando con expertos y miembros de la comunidad.', ARRAY['2.1. Utiliza aplicaciones tecnológicas para el análisis de datos, planificador digital, etc. que faciliten la propuesta de soluciones a un problema de carácter educativo o comunitario.', '2.2. Recolecta datos o identifica patrones relevantes mediante el uso de herramientas para la toma de decisiones.', '2.3. Comparte soluciones creativas utilizando texto, imágenes y video, de diferentes fuentes.']),
('Tercero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '3. Interactúa socialmente en línea, respetando y aceptando las normas grupales.', ARRAY['3.1. Interactúa en la web de forma ética con personas de otras culturas, de forma que pueda ampliar su punto de vista y aprendizaje.', '3.2. Crea y comparte trabajos abordando problemas comunitarios en plataformas colaborativas.', '3.3. Explora problemas o necesidades de la comunidad y utiliza tecnología colaborativa para encontrar soluciones juntamente con sus compañeros y profesor.']);

-- ===== cnb_bachillerato_1.sql =====
-- CNB Bachillerato (Diversificado) - INSERTs de competencias
-- NOTA IMPORTANTE: la tabla `competencias` fue diseñada originalmente para Primaria
-- (columna `grado` con valores '1ro'..'6to'). Para Bachillerato no existe columna de
-- carrera/orientación, por lo que se usa una etiqueta compuesta en el campo `grado`:
--   '[Carrera/Orientación] - [Año]'
-- Ejemplos: 'Bachillerato en Ciencias y Letras - Cuarto Año'
--           'Bachillerato en Ciencias y Letras - Quinto Año'
--           'Bachillerato por Madurez - Cuarto Año'
-- Esto permite identificar la carrera y el año aunque el schema no tenga columna dedicada.
-- Fuente: cnbguatemala.org (Currículum Nacional Base de Guatemala), páginas
-- "Bachillerato en Ciencias y Letras/Competencias - Cuarto Grado" y "... Quinto Grado".
-- Estas páginas resumen 1 competencia principal por área/subárea y grado (sin indicadores
-- de logro desglosados a este nivel; el array `indicadores` se deja vacío ARRAY[]::TEXT[]
-- salvo que se indique lo contrario).

-- =========================================================
-- BACHILLERATO EN CIENCIAS Y LETRAS - CUARTO AÑO
-- =========================================================
INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Lengua y Literatura', 'Competencia 1: Utiliza el lenguaje como el medio que le permite establecer relaciones en los diferentes ámbitos en los que se desenvuelve.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Lengua y Literatura', 'Competencia 2: Aplica diferentes estrategias de lectura que le permiten generar significados de los textos que lee.', ARRAY[]::TEXT[]),
('Bachillerato en Ciencias y Letras - Cuarto Año', 'Lengua y Literatura', 'Competencia 3: Valora la literatura hispanoamericana como aporte cultural universal.', ARRAY[]::TEXT[]),
