-- ===== cnb_bachillerato_4.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Diseño Gráfico
-- Solo áreas técnicas distintivas. Cada subárea tiene su propia página "/Malla_Curricular" con competencias+indicadores.
-- Fuente: .../Bachillerato.../Área_de_Tecnología/Subárea_de_Fundamentación_del_Diseño_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Diseño Gráfico - Cuarto Año', 'Fundamentación del Diseño', '1. Desarrolla un potencial creativo por medio de los conceptos básicos de diseño.', ARRAY['1.1. Analiza la importancia del diseño gráfico a partir de los enfoques teóricos en las diferentes áreas de aplicación.', '1.2. Explica los diferentes fundamentos que rigen la importancia del diseño.', '1.3. Asume actitudes críticas y objetivas para analizar diseños.']),
('Bachillerato en Ciencias y Letras con Orientación en Diseño Gráfico - Cuarto Año', 'Fundamentación del Diseño', '2. Aplica técnicas y procedimientos en la realización de diseños.', ARRAY['2.1. Identifica los elementos esenciales en el manejo del diseño gráfico.', '2.2. Utiliza los diferentes modelos y estrategias de los estilos del diseño para llevar a cabo el proceso de elaboración.', '2.3. Aplica técnicas referentes al diseño.']),
('Bachillerato en Ciencias y Letras con Orientación en Diseño Gráfico - Cuarto Año', 'Cromatología del Color', '1. Reconoce el Diseño como producto manifiesto de la actividad humana, y de la evolución cultural y tecnológica de los Pueblos.', ARRAY['1.1. Describe distintas actividades que se dan en las diversas culturas a través del tiempo.', '1.2. Identifica el significado del color en todas sus manifestaciones.', '1.3. Aplica la psicología del color para realizar diseños gráficos.']),
('Bachillerato en Ciencias y Letras con Orientación en Diseño Gráfico - Cuarto Año', 'Cromatología del Color', '2. Clasifica los diferentes materiales y colores para crear diseños de uso en la industria.', ARRAY['2.1. Utiliza materiales diversos en la realización de diseños gráficos en concordancia con el color.', '2.2. Relaciona conocimientos y técnicas de las distintas artes del color.', '2.3. Reconoce el valor del color y lo proyecta en los diseños gráficos.']),
('Bachillerato en Ciencias y Letras con Orientación en Diseño Gráfico - Cuarto Año', 'Cromatología del Color', '3. Aplica las propiedades del color en las creaciones que realiza.', ARRAY['3.1. Utiliza apropiadamente los colores de acuerdo al mensaje que transmitirá.', '3.2. Utiliza los colores en la transmisión de sensaciones experimentadas en las escenas o motivos originales de sus creaciones.']),
('Bachillerato en Ciencias y Letras con Orientación en Diseño Gráfico - Cuarto Año', 'Cromatología del Color', '4. Describe la contribución del color en los diferentes procesos y productos del diseño gráfico.', ARRAY['4.1. Aplica la escala cromática, con base a sus características y al impacto que produce en el diseño gráfico.', '4.2. Interpreta el proceso de armonización y contraste de los colores en los productos de diseño gráfico.']),
('Bachillerato en Ciencias y Letras con Orientación en Diseño Gráfico - Cuarto Año', 'Diseño Gráfico Computarizado I', '1. Utiliza conocimientos de diseño gráfico por computadora en la creación de nuevos bocetos.', ARRAY['1.1. Reconoce los diferentes diseños gráficos y su clasificación.', '1.2. Valora los diseños gráficos guatemaltecos y los que representan identidad de los cuatro Pueblos.', '1.3. Utiliza adecuadamente los programas de cómputo para la realización de los diseños gráficos.']),
('Bachillerato en Ciencias y Letras con Orientación en Diseño Gráfico - Cuarto Año', 'Diseño Gráfico Computarizado I', '2. Utiliza programas de cómputo en la solución de problemas relacionados con el área o campo de trabajo.', ARRAY['2.1. Crea diseños personalizados para su uso en la elaboración de diferentes producciones.', '2.2. Incorpora nuevas tecnologías aplicando los programas de manera productiva y eficiente.', '2.3. Manifiesta la expresión de una forma propia mediante la ilustración.']);

-- ===== cnb_bachillerato_5.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Educación
-- Solo área técnica distintiva: Fundamentos de Pedagogía
-- Fuente: .../Bachillerato.../Área_de_Pedagogía/Subárea_de_Fundamentos_de_Pedagogía_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Educación - Cuarto Año', 'Fundamentos de Pedagogía', '1. Reflexiona sobre los elementos históricos de la Pedagogía y su incidencia en la educación actual.', ARRAY['1.1. Analiza los antecedentes de la Pedagogía como movimiento histórico.', '1.2. Utiliza en el ámbito que le corresponde los conceptos de Pedagogía y educación desde su cosmovisión.', '1.3. Identifica los principios y fines de la educación.']),
('Bachillerato en Ciencias y Letras con Orientación en Educación - Cuarto Año', 'Fundamentos de Pedagogía', '2. Argumenta sobre los diferentes aportes de otras ciencias a la Pedagogía y su aplicación en el proceso de aprendizaje.', ARRAY['2.1. Identifica la relación y los aportes de la Pedagogía con otras ciencias.', '2.2. Interpreta la trascendencia del papel que desempeña la Pedagogía en el campo educativo.']),
('Bachillerato en Ciencias y Letras con Orientación en Educación - Cuarto Año', 'Fundamentos de Pedagogía', '3. Analiza los principales modelos y enfoques pedagógicos que orientan el proceso de aprendizaje.', ARRAY['3.1. Compara los principales modelos y enfoques educativos en el proceso de aprendizaje.', '3.2. Contrasta los modelos y enfoques que se aplican en el Sistema Educativo guatemalteco con los sistemas educativos de Latinoamérica.', '3.3. Expone sus puntos de vista en cuanto a la educación tradicional y el nuevo paradigma educativo.']),
('Bachillerato en Ciencias y Letras con Orientación en Educación - Cuarto Año', 'Fundamentos de Pedagogía', '4. Enfoca los fundamentos de la educación desde una concepción holística y cosmocéntrica que caracteriza a cada uno de los Pueblos.', ARRAY['4.1. Identifica los fundamentos de la educación de los Pueblos de Guatemala.', '4.2. Reconoce la influencia de los fundamentos de la educación en la convivencia diaria y recíproca de los Pueblos y su contexto.', '4.3. Utiliza los fundamentos de la Pedagogía comparada, en la visión educativa de los cuatro Pueblos.']);

-- ===== cnb_bachillerato_6.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Educación Física
-- Solo área técnica distintiva: Epistemología de la Educación Física
-- Fuente: .../Bachillerato.../Área_de_Educación_Física/Subárea_de_Epistemología_de_la_Educación_Física_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Educación Física - Cuarto Año', 'Epistemología de la Educación Física', '1. Describe las bases del surgimiento y devenir histórico de la Educación Física, asociándolos a la problemática nacional.', ARRAY['1.1. Interpreta la historia internacional y nacional de la Educación Física.', '1.2. Propone soluciones a la problemática actual de la Educación Física a nivel nacional.', '1.3. Plantea soluciones a la problemática actual de la Educación Física a nivel departamental.']),
('Bachillerato en Ciencias y Letras con Orientación en Educación Física - Cuarto Año', 'Epistemología de la Educación Física', '2. Describe el marco doctrinal de la Educación Física de acuerdo a su entorno socio-educativo.', ARRAY['2.1. Expone las bases doctrinales de la Educación Física.', '2.2. Explica los conceptos y definiciones de la Educación Física.', '2.3. Relaciona la Educación Física con distintas formas de actividad física.']),
('Bachillerato en Ciencias y Letras con Orientación en Educación Física - Cuarto Año', 'Epistemología de la Educación Física', '3. Explica la forma estructural y organizativa de Educación Física a nivel departamental y nacional para su formación académica.', ARRAY['3.1. Discute de forma objetiva la realidad de la Educación Física nacional.', '3.2. Presenta los diferentes procesos de desarrollo del ámbito curricular de la Educación Física nacional.', '3.3. Expone la estructura organizacional de la Educación Física nacional.']);

-- ===== cnb_bachillerato_7.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Educación Musical
-- Solo área técnica distintiva: Lenguaje Musical
-- Fuente: .../Bachillerato.../Área_de_Comunicación_y_Lenguaje/Subárea_de_Lenguaje_Musical_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Educación Musical - Cuarto Año', 'Lenguaje Musical', '1. Aplica habilidades auditivas al escuchar música con evidente conciencia rítmica, melódica y armónica.', ARRAY['1.1. Identifica auditivamente duraciones, motivos, secuencias y frases rítmicas.', '1.2. Compara alturas sonoras, intervalos, secuencias y frases melódicas.', '1.3. Reproduce sonidos en simultaneidad y los ubica nombrándolos por su respectivo acorde.']),
('Bachillerato en Ciencias y Letras con Orientación en Educación Musical - Cuarto Año', 'Lenguaje Musical', '2. Utiliza signos y símbolos musicales en la lectura y escritura de partituras musicales.', ARRAY['2.1. Reproduce por lectura, secuencias rítmicas percutiendo en distintos cuerpos sonoros.', '2.2. Identifica los símbolos de la lecto-escritura musical los que luego reproduce.', '2.3. Aplica signos y símbolos musicales para escribir y expresar sus ideas y emociones.']),
('Bachillerato en Ciencias y Letras con Orientación en Educación Musical - Cuarto Año', 'Lenguaje Musical', '3. Utiliza signos y símbolos de lecto-escritura musical en la creación y expresión de música como un recurso de comunicación.', ARRAY['3.1. Produce secuencias rítmicas y melódicas sencillas.', '3.2. Comunica ideas propias aplicando signos y símbolos musicales.', '3.3. Presenta creaciones propias a su comunidad.']);

-- ===== cnb_bachillerato_8.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Electricidad
-- Solo área técnica distintiva: Electricidad Básica y Electromagnetismo
-- Fuente: .../Bachillerato.../Área_de_Tecnología/Subárea_de_Electricidad_Básica_y_Electromagnetismo_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Electricidad - Cuarto Año', 'Electricidad Básica y Electromagnetismo', '1. Expone, de forma conceptual, operatoria y experimental, los conceptos fundamentales de fuerza eléctrica, campo eléctrico y potencial eléctrico.', ARRAY['1.1. Interpreta los conceptos fundamentales de electrostática.', '1.2. Describe las ecuaciones utilizadas en electrostática y sus respectivos procedimientos para resolverlas.', '1.3. Aplica las ecuaciones y los conceptos fundamentales de electrostática para resolver problemas contextualizados.', '1.4. Comprueba los conceptos teóricos con experimentos demostrativos y experimentos de laboratorio.']),
('Bachillerato en Ciencias y Letras con Orientación en Electricidad - Cuarto Año', 'Electricidad Básica y Electromagnetismo', '2. Utiliza los conceptos físicos y métodos algebraicos en la resolución de problemas relacionados con el concepto de capacitancia y sus aplicaciones eléctricas del entorno.', ARRAY['2.1. Explica la definición de capacitancia y su relación con el voltaje aplicado y la carga total.', '2.2. Aplica ecuaciones para resolver problemas relacionados con capacitancia y condensadores.', '2.3. Realiza experimentos demostrativos y de laboratorio para comprobar los conceptos teóricos.']);

-- ===== cnb_bachillerato_9.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Finanzas y Administración
-- Solo área técnica distintiva: Contabilidad General y de Sociedades Mercantiles
-- Fuente: .../Bachillerato.../Área_de_Contabilidad_y_Auditoría/Subárea_Contabilidad_General_y_de_Sociedades_Mercantiles_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Finanzas y Administración - Cuarto Año', 'Contabilidad General y de Sociedades Mercantiles', '1. Aplica los fundamentos de contabilidad y la lógica contable, en el proceso de construcción de la contabilidad en las empresas.', ARRAY['1.1. Identificación de las especialidades de la contabilidad, productos y usuarios de la información contable.', '1.2. Utiliza los conceptos y la lógica en la jornalización de operaciones comerciales.', '1.3. Utiliza los documentos comerciales y de crédito en actividades comerciales.']),
('Bachillerato en Ciencias y Letras con Orientación en Finanzas y Administración - Cuarto Año', 'Contabilidad General y de Sociedades Mercantiles', '2. Aplica las Normas Internacionales de Contabilidad e Información Financiera -NIC- y -NIIF-, en procesos contables de las empresas mercantiles.', ARRAY['2.1. Interpreta las NIIF y NIC, leyes tributarias y la lógica contable en los procesos empresariales.', '2.2. Relaciona los principios de contabilidad y las leyes tributarias, aplicados en los libros contables en las empresas mercantiles.', '2.3. Efectúa registros contables y formula Estados Financieros, con base a la aplicación de la NIC 1 que contiene los aspectos relacionados a los mismos.']);

-- ===== cnb_bachillerato_10.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Gestión de Oficinas
-- Solo área técnica distintiva: Gestión Administrativa
-- Fuente: .../Bachillerato.../Área_de_Administración/Subárea_de_Gestión_Administrativa_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Gestión de Oficinas - Cuarto Año', 'Gestión Administrativa', '1. Manifiesta la importancia de la integración del proceso administrativo en las organizaciones según su naturaleza.', ARRAY['1.1. Describe los elementos del proceso administrativo en las organizaciones actuales.', '1.2. Compara las características y funciones de un administrador y de un gerente.', '1.3. Especifica la utilidad de la planeación en los diferentes tipos de organización según su naturaleza.', '1.4. Expresa la utilidad de diferentes tipos de estructuras organizacionales.', '1.5. Ejerce liderazgo en situaciones de gestión administrativa.', '1.6. Practica formas de control en diferentes situaciones organizacionales.']),
('Bachillerato en Ciencias y Letras con Orientación en Gestión de Oficinas - Cuarto Año', 'Gestión Administrativa', '2. Promueve el trabajo en equipo, en la resolución de problemas organizacionales y de su vida cotidiana.', ARRAY['2.1. Argumenta las ventajas del trabajo en equipo, en situaciones de la vida cotidiana.', '2.2. Ejecuta acciones para desarrollar las capacidades de los equipos de trabajo en una organización.', '2.3. Relaciona el trabajo en equipo de una organización con la resolución de problemas.']);

-- ===== cnb_bachillerato_11.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Mecánica Automotriz
-- Solo área técnica distintiva: Mantenimiento Básico de Automóvil
-- Fuente: .../Bachillerato.../Área_de_Tecnología/Subárea_de_Mantenimiento_Básico_de_Automóvil_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Mecánica Automotriz - Cuarto Año', 'Mantenimiento Básico de Automóvil', '1. Utiliza las técnicas de verificación de los distintos tipos de niveles necesarios para el perfecto funcionamiento de los mecanismos del automóvil, y el estudio de las generalidades de los principales sistemas de los automóviles, uso y manejo de herramienta y seguridad e higiene en el taller.', ARRAY['1.1. Identifica los diferentes sistemas de acuerdo con la función que desempeñan en el automóvil.', '1.2. Aplica la higiene y la seguridad en el uso de las herramientas en el mantenimiento del automóvil.']),
('Bachillerato en Ciencias y Letras con Orientación en Mecánica Automotriz - Cuarto Año', 'Mantenimiento Básico de Automóvil', '2. Clasifica los tipos de lubricantes y las técnicas para lubricar los mecanismos del automóvil.', ARRAY['2.1. Selecciona lubricantes para su aplicación en los diferentes sistemas del automóvil, de acuerdo con las características y especificaciones del fabricante.', '2.2. Utiliza las técnicas para cambios de cojinetes de fricción y lubricación de rodamientos.']),
('Bachillerato en Ciencias y Letras con Orientación en Mecánica Automotriz - Cuarto Año', 'Mantenimiento Básico de Automóvil', '3. Aplica las técnicas para reacondicionar y balancear aros y neumáticos y limpieza general de los automóviles.', ARRAY['3.1. Diagnostica fallas de aros y neumáticos de acuerdo a procedimientos técnicos y parámetros de calidad establecidos.', '3.2. Balancea aros y neumáticos de acuerdo con parámetros, procedimientos técnicos y medidas de seguridad establecidos.', '3.3. Lustra la carrocería del automóvil de acuerdo con los procedimientos técnicos y las prácticas recomendadas, para la protección del automóvil.']);

-- ===== cnb_bachillerato_12.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Textiles
-- Solo área técnica distintiva: Textiles I
-- Fuente: .../Bachillerato.../Área_de_Tecnología/Subárea_de_Textiles_I_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Textiles - Cuarto Año', 'Textiles I', '1. Selecciona los tipos de materiales que se utilizan en la industria textil: fibras, tejidos, telas, maquinaria, entre otros, así como los procesos de mayor relevancia en la generación de otros productos.', ARRAY['1.1. Explica los principales recursos y procesos para la elaboración de productos en la industria textil.', '1.2. Clasifica materiales utilizados en la industria textil: fibras, tejidos, telas, maquinaria, entre otros.', '1.3. Describe tipos, formas y usos de las telas y de los tejidos en la industria textil.', '1.4. Interpreta los principales factores de diseño, calidad y productividad de géneros textiles.']),
('Bachillerato en Ciencias y Letras con Orientación en Textiles - Cuarto Año', 'Textiles I', '2. Caracteriza las diferentes técnicas en la producción de tejidos para la confección de prendas de vestir en la industria textil.', ARRAY['2.1. Describe los principales procesos relacionados con la producción de tejidos y la confección de prendas de vestir.', '2.2. Detalla los procesos para la producción de telas tejidas a partir de hilos.']),
('Bachillerato en Ciencias y Letras con Orientación en Textiles - Cuarto Año', 'Textiles I', '3. Explica los principales factores relacionados con la producción en la industria textil, desde su propio contexto, en función de los aportes a la economía nacional y a nivel mundial y su incidencia a nivel personal y laboral.', ARRAY['3.1. Argumenta la contribución de la industria textil en la economía familiar y a nivel de país.', '3.2. Identifica medidas preventivas, correctivas y de emergencia en el entorno de trabajo para evitar accidentes.']);

