-- Fuente: .../Bachillerato.../Área_de_Administración/Subárea_de_Administración_Turística_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Turismo - Cuarto Año', 'Administración Turística', '1. Utiliza la información de la administración del recurso humano en sus diferentes intervenciones, considerándola como un factor determinante para el buen funcionamiento de la empresa.', ARRAY['1.1. Emite juicios basados en los resultados de sus investigaciones sobre la administración del recurso humano.', '1.2. Aplica el conocimiento sobre la selección y contratación de personal en sus diferentes intervenciones.', '1.3. Valora la importancia de la capacitación y evaluación constante al personal ya que esto incide en el servicio de altura que se le brinda al cliente.']),
('Bachillerato en Ciencias y Letras con Orientación en Turismo - Cuarto Año', 'Administración Turística', '2. Reconoce el proceso administrativo estructurado y la aplicación de herramientas y técnicas efectivas en el servicio al cliente, que trae beneficios al turismo nacional e internacional, buscando superar las expectativas del turista.', ARRAY['2.1. Utiliza técnicas y herramientas de servicio al cliente.', '2.2. Utiliza programas de Excel como herramientas que le permiten organizar y llevar mejor control de las cuentas.']);

-- ===== cnb_bachillerato_14.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Ciencias Biológicas
-- Solo área técnica distintiva: Biología I
-- Fuente: .../Bachillerato.../Área_de_Ciencias_Naturales/Subárea_de_Biología_I_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Ciencias Biológicas - Cuarto Año', 'Biología I', '1. Aplica el conocimiento científico en la investigación y resolución de problemas del entorno.', ARRAY['1.1. Identifica el campo de acción de la Biología y la Biotecnología, sus avances, los aportes de otras ciencias, así como las aplicaciones que en este campo tiene el método científico y otros métodos heurísticos.', '1.2. Utiliza la tecnología y las Matemáticas en la resolución de problemas, en la comunicación y desarrollo de investigaciones en el estudio de la Biología.']),
('Bachillerato en Ciencias y Letras con Orientación en Ciencias Biológicas - Cuarto Año', 'Biología I', '2. Representa información relacionada con la organización de la vida y sus principales procesos fisiológicos.', ARRAY['2.1. Representa los niveles de organización, estructuras, clasificación y la fisiología de los seres vivos.', '2.2. Distingue sustancias químicas que forman parte de los seres vivos.', '2.3. Diferencia los procesos de división celular, reproducción sexual y asexual y el rol de la mitosis y la meiosis en éstos.', '2.4. Explica las interacciones entre los organismos y el entorno físico donde viven.']);

-- ===== cnb_bachillerato_15.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Educación de Productividad y Desarrollo
-- Solo área técnica distintiva: Alimentación Sostenible y Sustentable
-- Fuente: .../Bachillerato.../Área_de_Productividad_y_Desarrollo/Subárea_de_Alimentación_Sostenible_y_Sustentable_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Educación de Productividad y Desarrollo - Cuarto Año', 'Alimentación Sostenible y Sustentable', '1. Utiliza principios, procesos y técnicas de agricultura moderna en la ejecución de proyectos productivos agropecuarios, que contribuyen al desarrollo humano y de la comunidad en el marco del desarrollo sostenible y sustentable.', ARRAY['1.1. Determina los avances de la agricultura y su incidencia en el desarrollo socioeconómico familiar y comunitario.', '1.2. Argumenta en relación con las acciones que deben considerarse antes, durante y después de la siembra de la semilla.', '1.3. Emplea diferentes procesos en el cultivo de hortalizas, atendiendo a las características climáticas de la región.', '1.4. Interpreta los principios, fundamentos y objetivos de la ecoagricultura.', '1.5. Emplea técnicas para la prevención de accidentes y sanitarias en el uso adecuado de herramientas y equipo.', '1.6. Discute acerca de los factores necesarios a considerar en la producción, manipulación y conservación de los alimentos en el aseguramiento de la calidad.']);

-- ===== cnb_bachillerato_16.sql =====
-- CNB Bachillerato en Ciencias y Letras con Orientación en Productividad y Emprendimiento (Modalidad Flexible)
-- Solo área técnica distintiva: Productividad en la Laboriosidad
-- Fuente: .../Bachillerato.../Área_de_Productividad_y_Emprendimiento/Subárea_de_Productividad_en_la_Laboriosidad_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Bachillerato en Ciencias y Letras con Orientación en Productividad y Emprendimiento (Modalidad Flexible) - Cuarto Año', 'Productividad en la Laboriosidad', '1. Contrasta la información mediante la investigación para la realización de proyectos en el ámbito familiar y comunitario.', ARRAY['1.1. Recopila la información necesaria mediante técnicas pertinentes.', '1.2. Clasifica la información obtenida en función del proceso a ejecutar.', '1.3. Valora la información obtenida para la oportuna toma de decisiones.']),
('Bachillerato en Ciencias y Letras con Orientación en Productividad y Emprendimiento (Modalidad Flexible) - Cuarto Año', 'Productividad en la Laboriosidad', '2. Plantea proyectos con control de calidad en su trabajo profesional.', ARRAY['2.1. Conoce las oportunidades y amenazas para la realización del proyecto.', '2.2. Verifica los procesos de control de calidad.', '2.3. Aplica métodos y normas en el manejo de los bienes y servicios.']),
('Bachillerato en Ciencias y Letras con Orientación en Productividad y Emprendimiento (Modalidad Flexible) - Cuarto Año', 'Productividad en la Laboriosidad', '3. Promueve procesos en gestión de proyectos en instituciones que faciliten el desarrollo económico personal, familiar y comunitario.', ARRAY['3.1. Determina acciones que propician la gestión para la implementación del proyecto.', '3.2. Evalúa la pertinencia y conveniencia de las posibles alianzas.', '3.3. Ejecuta acciones que propician la realización ordenada y sistemática del proyecto.']);

