-- ===== cnb_perito_1.sql =====
-- CNB Perito en Electricidad Industrial
-- Solo área técnica distintiva: Tecnología Eléctrica - Cuarto Grado
-- grado usa la etiqueta compuesta '[Carrera] - [Año]'
-- Fuente: .../Perito_en_Electricidad_Industrial/Área_de_Tecnología/Subárea_Tecnología_eléctrica_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Perito en Electricidad Industrial - Cuarto Año', 'Tecnología Eléctrica', '1. Maneja de forma correcta las herramientas y el equipo de un taller de electricidad.', ARRAY['1.1. Establece medidas de precaución necesarias al usar las herramientas y el equipo.', '1.2. Utiliza las herramientas y el equipo del electricista, tomando medidas de precaución.', '1.3. Realiza las mediciones correctas y exactas con las herramientas.']),
('Perito en Electricidad Industrial - Cuarto Año', 'Tecnología Eléctrica', '2. Realiza las diferentes acciones de la electricidad industrial que se llevan a cabo en la mecánica de banco.', ARRAY['2.1. Organiza los espacios del taller de acuerdo con la mecánica de banco.', '2.2. Utiliza los tornillos de banco según el trabajo a realizar.', '2.3. Aplica los tipos de mandíbula en el banco.']),
('Perito en Electricidad Industrial - Cuarto Año', 'Tecnología Eléctrica', '3. Identifica los fenómenos eléctricos y los circuitos eléctricos que se suscitan en el campo laboral.', ARRAY['3.1. Interpreta la medición de resistencias con precisión mediante el óhmetro y el código de colores.', '3.2. Aplica el óhmetro en la realización de circuitos eléctricos.', '3.3. Resuelve circuitos aplicando la ley de Ohm.']);

-- ===== cnb_perito_2.sql =====
-- CNB Perito en Electrónica y Dispositivos Digitales
-- Solo área técnica distintiva: Electrónica Analógica - Cuarto Grado
-- Fuente: .../Perito_en_Electrónica_y_Dispositivos_Digitales/Área_de_Tecnología/Subárea_de_Electrónica_Analógica_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Perito en Electrónica y Dispositivos Digitales - Cuarto Año', 'Electrónica Analógica', '1. Utiliza herramienta adecuada para medir fenómenos eléctricos y comprobar el funcionamiento básico de los dispositivos electrónicos pasivos y activos en un circuito eléctrico.', ARRAY['1.1. Clasifica las distintas herramientas que usa en el taller.', '1.2. Compara las características básicas de los dispositivos electrónicos pasivos y activos.', '1.3. Manipula equipo electrónico adecuado para medir, analizar y comprobar fenómenos eléctricos en un circuito.']),
('Perito en Electrónica y Dispositivos Digitales - Cuarto Año', 'Electrónica Analógica', '2. Construye circuitos eléctricos, utilizando la herramienta y el equipo adecuado que se encuentren disponibles en su vida profesional.', ARRAY['2.1. Agrupa dispositivos electrónicos de acuerdo con sus aplicaciones en circuitos eléctricos.', '2.2. Manipula programas simuladores en la construcción de circuitos eléctricos.', '2.3. Utiliza tarjetas de trabajo en la construcción de circuitos eléctricos reales.']),
('Perito en Electrónica y Dispositivos Digitales - Cuarto Año', 'Electrónica Analógica', '3. Interpreta los fenómenos eléctricos que se producen en un circuito eléctrico.', ARRAY['3.1. Identifica los distintos fenómenos que se dan en un circuito eléctrico.', '3.2. Manipula de forma adecuada dispositivos electrónicos de control en la construcción de sensores y alarmas.', '3.3. Compara las características básicas de las familias TTL y CMOS con el fin de utilizar los más adecuados en la creación de proyectos electrónicos.']),
('Perito en Electrónica y Dispositivos Digitales - Cuarto Año', 'Electrónica Analógica', '4. Utiliza equipo y herramienta adecuada que le permite localizar y reparar los componentes defectuosos en un equipo de sonido.', ARRAY['4.1. Interpreta el funcionamiento de los componentes electrónicos en un equipo de audio.', '4.2. Emplea técnicas adecuadas en la búsqueda y análisis de las distintas fallas de un equipo de audio.', '4.3. Repara los componentes defectuosos de un equipo de sonido.']);

-- ===== cnb_perito_3.sql =====
-- CNB Perito en Industria de Alimentos
-- Solo área técnica distintiva: Fundamentos Tecnológicos para la Industria Alimentaria - Cuarto Grado
-- Fuente: .../Perito_en_Industria_de_Alimentos/Área_Técnica/Subárea_Fundamentos_Tecnológicos_Para_la_Industria_Alimentaria_-_Cuarto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Perito en Industria de Alimentos - Cuarto Año', 'Fundamentos Tecnológicos para la Industria Alimentaria', '1. Utiliza los conocimientos adquiridos para la planeación de los diversos procesos que se realizan en la elaboración de alimentos.', ARRAY['1.1. Practica procedimientos acordes con las diferentes etapas que se realizan en los procesos de manufactura de alimentos.', '1.2. Elabora diagramas de flujo eficaces para la planeación e identificación de las etapas en que se incurre para el desarrollo de productos alimenticios.', '1.3. Replica las etapas de los procesos y procedimientos de la industria alimentaria.']),
('Perito en Industria de Alimentos - Cuarto Año', 'Fundamentos Tecnológicos para la Industria Alimentaria', '2. Aplica los principios relacionados con la inocuidad de los alimentos para obtener productos alimenticios que garanticen la salud de los consumidores.', ARRAY['2.1. Elabora planes para implementar sistemas que permitan la elaboración de alimentos inocuos.', '2.2. Explica los tipos de contaminantes que pueden existir en los alimentos.', '2.3. Expone sobre los métodos que se utilizan para evitar la contaminación en los alimentos.']);

-- ===== cnb_perito_4.sql =====
-- CNB Perito en Desarrollo Comunitario
-- Solo área técnica distintiva: Desarrollo Comunitario - Sexto Grado
-- Fuente: .../Perito_en_Desarrollo_Comunitario/Área_de_Productividad_y_Desarrollo/Subárea_de_Desarrollo_Comunitario_-_Sexto_Grado/Malla_Curricular

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Perito en Desarrollo Comunitario - Sexto Año', 'Desarrollo Comunitario', '1. Promueve la organización comunitaria, enfocada hacia la toma de decisiones y solución de problemas, con el propósito de lograr el desarrollo de su comunidad.', ARRAY['1.1. Emplea términos relacionados con el desarrollo comunitario.', '1.2. Identifica las necesidades e intereses de la comunidad por medio del diagnóstico comunitario.', '1.3. Propone soluciones a problemas a partir de estrategias establecidas.']),
('Perito en Desarrollo Comunitario - Sexto Año', 'Desarrollo Comunitario', '2. Propicia la participación comunitaria en el proceso de mejoramiento sostenido y equitativo de la calidad de vida de los habitantes, basado en medidas de conservación y protección del medio ambiente.', ARRAY['2.1. Aplica técnicas innovadoras que se orientan hacia el desarrollo de la comunidad.', '2.2. Participa en el proceso de mejoramiento comunitario.', '2.3. Realiza acciones de sostenibilidad y sustentabilidad comunitaria, sin perder de vista la protección ambiental.']);

